      {/* Mobile Bottom Navigation */}
      <div className="fixed bottom-6 left-0 right-0 px-6 sm:hidden z-50">
        <div className="bg-rose-900/95 backdrop-blur-md shadow-2xl rounded-[2rem] p-4 flex justify-around items-center border border-white/10">
             <button onClick={() => setActiveTab('dashboard')} className={`p-3 rounded-2xl transition-all ${activeTab === 'dashboard' ? 'bg-white text-rose-900' : 'text-rose-300'}`}>
                <Sparkles className="w-6 h-6" />
