import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import { generateDailyMission } from './services/geminiService';
import { Heart, Sparkles, BookOpen, User, Calendar, CheckCircle2, Trophy, ArrowRight, ShieldCheck, Clock } from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };
  const initialSubscription: SubscriptionInfo = {
    status: 'trial',
    plan: 'none',
    trialStartedAt: new Date().toISOString(),
    expiresAt: null
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v3');
    return saved ? JSON.parse(saved) : { 
      name: '', 
      language: LoveLanguage.NONE, 
      tankLevel: 5, 
      challenge: emptyChallenge,
      hasFinishedTutorial: false,
      subscription: initialSubscription
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v3');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', 
      language: LoveLanguage.NONE, 
      tankLevel: 5, 
      challenge: emptyChallenge,
      hasFinishedTutorial: true,
      subscription: initialSubscription
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'guide' | 'challenge' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);

  useEffect(() => {
    localStorage.setItem('love_user_v3', JSON.stringify(user));
  }, [user]);

  useEffect(() => {
    localStorage.setItem('love_partner_v3', JSON.stringify(partner));
  }, [partner]);

  // Lógica de Trial/Paywall
  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;

    const start = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDays = 7 * 24 * 60 * 60 * 1000;

    if (now - start > sevenDays) {
      return false;
    }
    return true;
  };

  const getTrialDaysRemaining = () => {
    const start = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDays = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDays - (now - start);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const startChallenge = async (days: 30 | 60) => {
    if (!checkAccess()) {
      setActiveTab('paywall');
      return;
    }
    if (partner.language === LoveLanguage.NONE) {
      alert("Defina primeiro a linguagem do seu parceiro no Painel.");
      return;
    }
    setLoadingMission(true);
    const firstMissionData = await generateDailyMission(partner.language, 1);
    const firstMission: Mission = {
      id: Math.random().toString(36).substr(2, 9),
      day: 1,
      title: firstMissionData.title || "Início da Jornada",
      description: firstMissionData.description || "Prepare-se para transformar seu amor.",
      rationale: firstMissionData.rationale || "O primeiro passo é o mais importante.",
      completed: false
    };

    setPartner(prev => ({
      ...prev,
      challenge: {
        type: days,
        startDate: new Date().toISOString(),
        missions: [firstMission]
      }
    }));
    setActiveTab('challenge');
    setLoadingMission(false);
  };

  const handleSubscribe = (planId: any) => {
    setUser(prev => ({
      ...prev,
      subscription: {
        ...prev.subscription,
        status: 'active',
        plan: planId
      }
    }));
    setActiveTab('dashboard');
  };

  const renderChallengeView = () => {
    if (!checkAccess()) return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;

    const challenge = partner.challenge;
    if (!challenge.type) {
      return (
        <div className="max-w-4xl mx-auto py-12 px-4 text-center">
          <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
            <div className="w-20 h-20 bg-rose-600 rounded-3xl flex items-center justify-center mx-auto mb-8 rotate-3 shadow-lg">
              <ShieldCheck className="w-10 h-10 text-white" />
            </div>
            <h2 className="text-4xl font-bold text-rose-900 mb-6">Compromisso de Amor</h2>
            <p className="text-gray-600 text-lg mb-10 max-w-2xl mx-auto leading-relaxed">
              Transformar um relacionamento exige decisão. Escolha um desafio para se dedicar intencionalmente à felicidade de <strong>{partner.name}</strong>.
            </p>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-lg mx-auto">
              <button 
                onClick={() => startChallenge(30)}
                disabled={loadingMission}
                className="group relative bg-white border-2 border-rose-200 p-8 rounded-3xl hover:border-rose-500 hover:bg-rose-50 transition-all text-left"
              >
                <span className="block text-rose-600 font-bold text-2xl mb-2">30 Dias</span>
                <span className="text-gray-500 text-sm italic">Foco e Reconexão Diária.</span>
                <ArrowRight className="absolute bottom-6 right-6 w-5 h-5 text-rose-300 group-hover:text-rose-500 transform group-hover:translate-x-1 transition-all" />
              </button>
              <button 
                onClick={() => startChallenge(60)}
                disabled={loadingMission}
                className="group relative bg-rose-600 p-8 rounded-3xl hover:bg-rose-700 transition-all text-left shadow-lg shadow-rose-200"
              >
                <span className="block text-white font-bold text-2xl mb-2">60 Dias</span>
                <span className="text-rose-100 text-sm italic">Transformação Profunda.</span>
                <ArrowRight className="absolute bottom-6 right-6 w-5 h-5 text-rose-300 transform group-hover:translate-x-1 transition-all" />
              </button>
            </div>
          </div>
        </div>
      );
    }

    const currentMission = challenge.missions.find(m => !m.completed);
    const completedCount = challenge.missions.filter(m => m.completed).length;
    const progressPercent = (completedCount / challenge.type) * 100;

    return (
      <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-rose-100 flex flex-col md:flex-row items-center gap-8">
          <div className="relative w-32 h-32 flex items-center justify-center">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="64" cy="64" r="58" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-rose-50" />
              <circle cx="64" cy="64" r="58" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={364.4} strokeDashoffset={364.4 - (364.4 * progressPercent) / 100} className="text-rose-600 transition-all duration-1000" />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-2xl font-black text-rose-900">{completedCount}</span>
              <span className="text-[10px] text-rose-400 font-bold uppercase tracking-tighter">Dias de Amor</span>
            </div>
          </div>
          <div className="flex-1 text-center md:text-left">
            <h3 className="text-2xl font-bold text-gray-800">Jornada de {challenge.type} Dias</h3>
            <p className="text-gray-500">Você está transformando o mundo de {partner.name}.</p>
          </div>
        </div>

        {currentMission ? (
          <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
            <Sparkles className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
            <div className="relative z-10">
              <div className="flex items-center gap-3 mb-6">
                <div className="px-4 py-1 bg-rose-800 rounded-full text-xs font-bold uppercase tracking-widest text-rose-200">Missão Dia {currentMission.day}</div>
              </div>
              <h4 className="text-4xl font-bold mb-6 text-rose-50">{currentMission.title}</h4>
              <p className="text-xl text-rose-100/90 leading-relaxed mb-8">"{currentMission.description}"</p>

              <div className="bg-rose-800/40 p-6 rounded-2xl border border-rose-700/50 mb-10 text-sm text-rose-200">
                <strong>Fundamento:</strong> {currentMission.rationale}
              </div>

              <button 
                onClick={() => {
                   const updatedMissions = partner.challenge.missions.map(m => 
                      m.id === currentMission.id ? { ...m, completed: true, completedAt: new Date().toISOString() } : m
                    );
                    setPartner(prev => ({
                      ...prev,
                      tankLevel: Math.min(10, prev.tankLevel + 1),
                      challenge: { ...prev.challenge, missions: updatedMissions }
                    }));
                }}
                className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:bg-rose-50 transition-all flex items-center justify-center gap-3 shadow-xl"
              >
                Concluir com Amor
              </button>
            </div>
          </div>
        ) : (
          <div className="bg-green-50 p-12 rounded-[3rem] border-2 border-green-100 text-center">
             <Trophy className="w-16 h-16 text-green-500 mx-auto mb-4" />
             <h3 className="text-3xl font-bold text-green-900">Parabéns!</h3>
             <p className="text-green-700">Você concluiu a etapa de hoje.</p>
          </div>
        )}
      </div>
    );
  };

  const renderContent = () => {
    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!checkAccess()} />;

    switch (activeTab) {
      case 'challenge':
        return renderChallengeView();
      case 'quiz':
        return (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-3xl font-bold text-center mb-8 text-rose-900">Sua Linguagem</h2>
            <Quiz onComplete={(res) => {
              setUser(prev => ({ ...prev, language: res }));
              setActiveTab('dashboard');
            }} />
          </div>
        );
      case 'guide':
        return (
          <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-500">
             <h2 className="text-3xl font-bold text-rose-900 mb-8">As 5 Linguagens</h2>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {Object.entries(LANGUAGE_METADATA).map(([lang, meta]) => (
                  lang !== LoveLanguage.NONE && (
                    <div key={lang} className={`p-6 rounded-2xl border shadow-sm ${meta.color}`}>
                      <div className="flex items-center gap-3 mb-3">
                        {meta.icon}
                        <h3 className="font-bold text-xl">{lang}</h3>
                      </div>
                      <p className="text-sm opacity-90 leading-relaxed">{meta.description}</p>
                    </div>
                  )
                ))}
             </div>
          </div>
        );
      default:
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Header Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-white p-8 rounded-3xl shadow-sm border border-rose-100 flex flex-col items-center text-center">
                <div className="w-16 h-16 bg-rose-50 rounded-2xl flex items-center justify-center mb-4">
                  <User className="w-8 h-8 text-rose-500" />
                </div>
                <input 
                    className="text-xl font-bold text-gray-800 bg-transparent border-b border-transparent focus:border-rose-200 outline-none text-center w-full"
                    placeholder="Seu Nome"
                    value={user.name}
                    onChange={(e) => setUser(prev => ({ ...prev, name: e.target.value }))}
                />
                <p className="text-rose-500 font-medium text-sm mt-1">{user.language}</p>
                {user.language === LoveLanguage.NONE && (
                  <button onClick={() => setActiveTab('quiz')} className="mt-4 px-6 py-2 bg-rose-600 text-white rounded-full text-xs font-bold shadow-lg shadow-rose-100">Descobrir Linguagem</button>
                )}
              </div>

              <div className="bg-white p-8 rounded-3xl shadow-sm border border-rose-100 flex flex-col items-center text-center">
                <div className="w-16 h-16 bg-rose-50 rounded-2xl flex items-center justify-center mb-4">
                  <Heart className="w-8 h-8 text-rose-500 fill-rose-500" />
                </div>
                <input 
                  className="text-xl font-bold text-gray-800 bg-transparent border-b border-transparent focus:border-rose-200 outline-none text-center w-40"
                  placeholder="Parceiro(a)"
                  value={partner.name}
                  onChange={(e) => setPartner(prev => ({ ...prev, name: e.target.value }))}
                />
                <select 
                  className="mt-1 text-rose-600 font-bold text-sm bg-rose-50 px-3 py-1 rounded-full outline-none"
                  value={partner.language}
                  onChange={(e) => setPartner(prev => ({ ...prev, language: e.target.value as LoveLanguage }))}
                >
                  <option value={LoveLanguage.NONE}>Selecionar Linguagem</option>
                  {Object.values(LoveLanguage).filter(l => l !== LoveLanguage.NONE).map(lang => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Tank Section */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge label={`Seu Tanque`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
              <TankGauge label={`Tanque de ${partner.name}`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
            </div>

            {/* Trial Banner */}
            {user.subscription.status === 'trial' && (
              <div className="bg-gradient-to-r from-rose-900 to-rose-700 p-8 rounded-[2rem] text-white flex flex-col md:flex-row justify-between items-center gap-6 shadow-xl">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-white/10 rounded-xl flex items-center justify-center">
                    <Clock className="w-6 h-6 text-rose-200" />
                  </div>
                  <div>
                    <h4 className="text-xl font-bold">Teste Gratuito Ativo</h4>
                    <p className="text-rose-200 text-sm">Você tem {getTrialDaysRemaining()} dias para explorar todas as ferramentas.</p>
                  </div>
                </div>
                <button onClick={() => setActiveTab('paywall')} className="px-6 py-3 bg-white text-rose-900 rounded-xl font-bold text-sm">Ver Planos Premium</button>
              </div>
            )}
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen pb-32">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      <header className="sticky top-0 z-50 bg-rose-50/80 backdrop-blur-lg border-b border-rose-100 mb-8">
        <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-2xl flex items-center justify-center shadow-xl shadow-rose-200">
              <Heart className="w-7 h-7 text-white fill-white" />
            </div>
            <div>
              <h1 className="text-xl font-black text-rose-900 leading-none">Linguagens</h1>
              <span className="text-[10px] font-bold text-rose-400 uppercase tracking-widest">do Amor</span>
            </div>
          </div>
          <nav className="hidden md:flex items-center gap-2">
            <button onClick={() => setActiveTab('dashboard')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'dashboard' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Painel</button>
            <button onClick={() => setActiveTab('challenge')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'challenge' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Jornada</button>
            <button onClick={() => setActiveTab('quiz')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'quiz' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Teste</button>
            <button onClick={() => setActiveTab('guide')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'guide' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Guia</button>
          </nav>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">
        {renderContent()}
