            <p className="text-center text-gray-500 mb-8 max-w-md mx-auto">Responda honestamente para descobrir como você se sente mais amado(a).</p>
            <Quiz onComplete={(res) => {
              setUser(prev => ({ ...prev, language: res }));
              setActiveTab('dashboard');
            }} />
