            )}
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen pb-32">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      <header className="sticky top-0 z-50 bg-rose-50/80 backdrop-blur-lg border-b border-rose-100 mb-8">
        <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-2xl flex items-center justify-center shadow-xl shadow-rose-200">
              <Heart className="w-7 h-7 text-white fill-white" />
            </div>
            <div>
              <h1 className="text-xl font-black text-rose-900 leading-none">Linguagens</h1>
              <span className="text-[10px] font-bold text-rose-400 uppercase tracking-widest">do Amor</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-2">
            <button onClick={() => setActiveTab('dashboard')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'dashboard' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Painel</button>
            <button onClick={() => setActiveTab('challenge')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'challenge' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Missão</button>
            <button onClick={() => setActiveTab('myChallenges')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'myChallenges' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Meus Desafios</button>
            <button onClick={() => setActiveTab('quiz')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'quiz' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Meu Teste</button>
            <button onClick={() => setActiveTab('guide')} className={`px-5 py-2.5 rounded-xl text-sm font-bold ${activeTab === 'guide' ? 'bg-rose-600 text-white shadow-lg' : 'text-rose-900'}`}>Guia</button>
          </nav>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">
        {renderContent()}
      </main>

      <div className="fixed bottom-6 left-0 right-0 px-6 sm:hidden z-50">
        <div className="bg-rose-900/95 backdrop-blur-md shadow-2xl rounded-[2rem] p-4 flex justify-around items-center border border-white/10">
             <button onClick={() => setActiveTab('dashboard')} className={`p-3 rounded-2xl ${activeTab === 'dashboard' ? 'bg-white text-rose-900' : 'text-rose-300'}`} title="Painel"><Sparkles className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('challenge')} className={`p-3 rounded-2xl ${activeTab === 'challenge' ? 'bg-white text-rose-900' : 'text-rose-300'}`} title="Missão"><Calendar className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('myChallenges')} className={`p-3 rounded-2xl ${activeTab === 'myChallenges' ? 'bg-white text-rose-900' : 'text-rose-300'}`} title="Meus Desafios"><ListChecks className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('partnerQuiz')} className={`p-3 rounded-2xl ${activeTab === 'partnerQuiz' ? 'bg-white text-rose-900' : 'text-rose-300'}`} title="Teste Parceiro"><UserPlus className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('guide')} className={`p-3 rounded-2xl ${activeTab === 'guide' ? 'bg-white text-rose-900' : 'text-rose-300'}`} title="Guia"><BookOpen className="w-6 h-6" /></button>
        </div>
      </div>
    </div>
  );
};

