import { GoogleGenAI, Type } from "@google/genai";
import { LoveLanguage, Mission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateDailyMission = async (targetLanguage: LoveLanguage, dayNumber: number): Promise<Partial<Mission>> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Gere uma missão prática para o dia ${dayNumber} de um desafio para alguém cuja linguagem do amor é "${targetLanguage}".`,
    config: {
      systemInstruction: `Você é um mentor de relacionamentos especialista no método de Gary Chapman. 
      Crie missões que sejam realizáveis em 24h e profundamente conectadas à linguagem especificada.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          rationale: { type: Type.STRING }
        },
        required: ["title", "description", "rationale"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getMissionCompletionFeedback = async (mission: Mission, partnerName: string): Promise<{ feedback: string, impact: number }> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `O usuário concluiu a missão: "${mission.title}". Descrição: "${mission.description}". Analise o impacto disso para o parceiro(a) ${partnerName}.`,
    config: {
      systemInstruction: `Analise o impacto emocional desta missão concluída. 
      Retorne um feedback curto e encorajador para o usuário e um valor numérico de impacto de 0.5 a 2.0.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          feedback: { type: Type.STRING, description: "Mensagem motivacional de 2 linhas" },
          impact: { type: Type.NUMBER, description: "Valor do preenchimento do tanque" }
        },
        required: ["feedback", "impact"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getCoachAdvice = async (history: {role: string, parts: {text: string}[]}[], userMessage: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [...history, { role: 'user', parts: [{ text: userMessage }] }],
    config: {
      systemInstruction: `Você é o "Personal Coach" de felicidade conjugal.
      PERSONA:
      - Expertise profunda em Psicologia Comportamental e Relacional (Teoria do Apego, Gottman).
      - Sólidos conhecimentos em Teologia e Princípios Bíblicos de família e amor.
      - Especialista em Gestão de Crise (conflitos, infidelidade, luto, finanças).
      OBJETIVO:
      - Ajudar casais a alcançarem "Felicidade Múltipla" (espiritual, emocional, física e financeira).
      - Ser compassivo, mas firme em princípios que constroem lares sólidos.
      - Sempre fornecer um conselho prático ao final da resposta.`,
      temperature: 0.8,
      topP: 0.95,
    }
  });
  return response.text;
};

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { Heart, Sparkles, BookOpen, User, Calendar, CheckCircle2, Trophy, ArrowRight, ShieldCheck, Clock, Bell, BellOff, Quote, UserPlus, AlertTriangle, ListChecks, MessageCircleCode, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };
  const initialSubscription: SubscriptionInfo = {
    status: 'trial',
    plan: 'none',
    trialStartedAt: new Date().toISOString(),
    expiresAt: null
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSubscription, notificationsEnabled: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: initialSubscription, notificationsEnabled: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const start = new Date(user.subscription.trialStartedAt).getTime();
    const sevenDays = 7 * 24 * 60 * 60 * 1000;
    return (new Date().getTime() - start) <= sevenDays;
  };

  const getTrialDaysRemaining = () => {
    const start = new Date(user.subscription.trialStartedAt).getTime();
    const remaining = (7 * 24 * 60 * 60 * 1000) - (new Date().getTime() - start);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const completeMission = async (mission: Mission) => {
    setLoadingMission(true);
    try {
      // IA Guia o Tanque
      const { feedback, impact } = await getMissionCompletionFeedback(mission, partner.name);

      const updatedMissions = partner.challenge.missions.map(m => 
        m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
      );

      const nextDay = mission.day + 1;
      if (nextDay <= (partner.challenge.type || 0)) {
        const nextData = await generateDailyMission(partner.language, nextDay);
        updatedMissions.push({
          id: Math.random().toString(36).substr(2, 9),
          day: nextDay,
          title: nextData.title!,
          description: nextData.description!,
          rationale: nextData.rationale!,
          completed: false
        });
      }

      setAiInsight(feedback);
      setPartner(prev => ({
        ...prev,
        tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
        challenge: { ...prev.challenge, missions: updatedMissions }
      }));
    } finally {
      setLoadingMission(false);
    }
  };

  const renderContent = () => {
    const hasAccess = checkAccess();
    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach'].includes(activeTab)) {
      return <Paywall onSubscribe={(id) => { setUser(p=>({...p, subscription:{...p.subscription, status:'active', plan:id as any}})); setActiveTab('dashboard'); }} isExpired={true} />;
    }

    switch (activeTab) {
      case 'coach': return <PersonalCoach />;
      case 'challenge': return (
        <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
           {/* Seção da Missão Atual com Feedback de IA */}
           {partner.challenge.missions.find(m => !m.completed) ? (
             <div className="space-y-6">
                <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
                  <BrainCircuit className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
                  <div className="relative z-10">
                    <h4 className="text-4xl font-bold mb-6 text-rose-50">{partner.challenge.missions.find(m => !m.completed)?.title}</h4>
                    <p className="text-xl text-rose-100/90 leading-relaxed mb-10">"{partner.challenge.missions.find(m => !m.completed)?.description}"</p>
                    <button 
                      onClick={() => completeMission(partner.challenge.missions.find(m => !m.completed)!)}
                      disabled={loadingMission}
                      className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-3 shadow-xl"
                    >
                      {loadingMission ? "Aguardando Avaliação da IA..." : "Concluir e Encher Tanque"}
                    </button>
                  </div>
                </div>
                {aiInsight && (
                  <div className="bg-amber-50 border-2 border-amber-200 p-6 rounded-3xl animate-in zoom-in duration-300">
                    <div className="flex gap-4 items-start">
                      <Sparkles className="w-6 h-6 text-amber-500 shrink-0" />
                      <div>
                        <p className="font-bold text-amber-900 mb-1">Feedback da IA Mentora</p>
                        <p className="text-amber-800 italic leading-relaxed">{aiInsight}</p>
                      </div>
                    </div>
                  </div>
                )}
             </div>
           ) : (
             <div className="text-center py-20 bg-white rounded-[3rem] border border-rose-100">
               <Trophy className="w-16 h-16 text-yellow-500 mx-auto mb-4" />
               <h3 className="text-3xl font-bold text-rose-900">Etapa Concluída!</h3>
               <p className="text-gray-500">Aguarde o próximo dia para novas orientações da IA.</p>
             </div>
           )}
        </div>
      );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge label={`Seu Tanque`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
              <TankGauge label={`Tanque de ${partner.name} (IA Guided)`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
            </div>

            {/* Atalho para o Coach */}
            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 overflow-hidden relative group">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full group-hover:scale-150 transition-all duration-700" />
              <div className="flex items-center gap-6">
                 <div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shrink-0 shadow-inner">
                    <MessageCircleCode className="w-8 h-8 text-indigo-100" />
                 </div>
                 <div>
                    <h3 className="text-2xl font-black mb-1">Personal Coach de Felicidade</h3>
                    <p className="text-indigo-200 text-sm">Conselhos bíblicos, psicológicos e gestão de crise 24h.</p>
                 </div>
              </div>
              <button onClick={() => setActiveTab('coach')} className="px-8 py-4 bg-white text-indigo-900 rounded-2xl font-black text-sm hover:bg-indigo-50 transition-all z-10">Pedir Conselho</button>
            </div>

            {user.subscription.status === 'trial' && (
              <div className={`p-8 rounded-[2.5rem] text-white flex justify-between items-center ${trialDays <= 2 ? 'bg-orange-600 animate-pulse' : 'bg-rose-900'}`}>
                <div><h4 className="font-bold">Teste Gratuito: {trialDays} dias</h4><p className="text-xs opacity-70">Aproveite a IA Mentora e o Coach.</p></div>
                <button onClick={() => setActiveTab('paywall')} className="px-6 py-2 bg-white text-rose-900 rounded-xl font-bold text-sm">Assinar</button>
              </div>
            )}
          </div>
        );
      default: return <div className="p-10 text-center">Aba em desenvolvimento</div>;
    }
  };

  return (
    <div className="min-h-screen pb-32">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}
      <header className="sticky top-0 z-50 bg-rose-50/80 backdrop-blur-lg border-b border-rose-100 mb-8">
        <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-10 h-10 bg-rose-600 rounded-xl flex items-center justify-center shadow-lg"><Heart className="w-6 h-6 text-white fill-white" /></div>
            <h1 className="text-lg font-black text-rose-900">LoveBridge AI</h1>
          </div>
          <nav className="hidden lg:flex items-center gap-2">
            {['dashboard', 'challenge', 'coach', 'guide'].map((tab) => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`px-5 py-2 rounded-xl text-sm font-bold capitalize ${activeTab === tab ? 'bg-rose-600 text-white' : 'text-rose-900 hover:bg-rose-100'}`}>
                {tab === 'challenge' ? 'Missão' : tab === 'coach' ? 'Personal Coach' : tab}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">{renderContent()}</main>

      <div className="fixed bottom-6 left-0 right-0 px-6 sm:hidden z-50">
        <div className="bg-rose-900/95 backdrop-blur-md shadow-2xl rounded-[2rem] p-4 flex justify-around items-center border border-white/10">
             <button onClick={() => setActiveTab('dashboard')} className={`p-3 rounded-2xl ${activeTab === 'dashboard' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><Sparkles className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('challenge')} className={`p-3 rounded-2xl ${activeTab === 'challenge' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><Calendar className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('coach')} className={`p-3 rounded-2xl ${activeTab === 'coach' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><MessageCircleCode className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('guide')} className={`p-3 rounded-2xl ${activeTab === 'guide' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><BookOpen className="w-6 h-6" /></button>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { getCoachAdvice } from '../services/geminiService';
import { Message } from '../types';
import { Send, User, Bot, Sparkles, Book, ShieldAlert, Heart, Trash2 } from 'lucide-react';

const PersonalCoach: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem('coach_history');
    return saved ? JSON.parse(saved) : [{
      role: 'model',
      text: 'Olá. Sou seu Personal Coach. Estou aqui para oferecer sabedoria bíblica, suporte psicológico e estratégias de crise para que seu casamento floresça. Como posso ajudar hoje?',
      timestamp: new Date().toISOString()
    }];
  });
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem('coach_history', JSON.stringify(messages));
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async (text: string = input) => {
    if (!text.trim() || isTyping) return;

    const userMsg: Message = { role: 'user', text, timestamp: new Date().toISOString() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));
      const response = await getCoachAdvice(history, text);
      const botMsg: Message = { role: 'model', text: response, timestamp: new Date().toISOString() };
      setMessages(prev => [...prev, botMsg]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsTyping(false);
    }
  };

  const clearChat = () => {
    if (confirm("Deseja apagar o histórico do aconselhamento?")) {
      setMessages([{
        role: 'model',
        text: 'Histórico limpo. Como posso ajudar agora?',
        timestamp: new Date().toISOString()
      }]);
    }
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[75vh] bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-indigo-100 animate-in fade-in slide-in-from-bottom-4">
      {/* Header */}
      <div className="bg-indigo-900 p-6 text-white flex justify-between items-center">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg">
              <Bot className="w-7 h-7 text-white" />
           </div>
           <div>
              <h2 className="text-xl font-black leading-none mb-1">Coach de Felicidade</h2>
              <p className="text-[10px] text-indigo-300 uppercase tracking-widest font-bold">Expert em Casamento & Sabedoria</p>
           </div>
        </div>
        <button onClick={clearChat} className="p-3 hover:bg-white/10 rounded-xl transition-all text-indigo-300 hover:text-white">
          <Trash2 className="w-5 h-5" />
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-5 rounded-[2rem] shadow-sm ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-800 rounded-tl-none border border-indigo-50'
            }`}>
              <div className="flex items-center gap-2 mb-2 opacity-60 text-[10px] font-bold uppercase tracking-wider">
                {m.role === 'user' ? <User className="w-3 h-3" /> : <Sparkles className="w-3 h-3" />}
                {m.role === 'user' ? 'Você' : 'Personal Coach'}
              </div>
              <div className="text-sm leading-relaxed whitespace-pre-wrap">{m.text}</div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-white p-4 rounded-2xl border border-indigo-100 text-indigo-400 text-xs font-bold">
              O Coach está refletindo...
            </div>
          </div>
        )}
        <div ref={scrollRef} />
      </div>

      {/* Shortcuts */}
      <div className="px-6 py-4 flex gap-2 overflow-x-auto no-scrollbar">
         <button onClick={() => handleSend("Pode me dar um conselho bíblico para fortalecer meu casamento hoje?")} className="flex-none px-4 py-2 bg-indigo-50 text-indigo-700 rounded-full text-xs font-bold flex items-center gap-2 border border-indigo-100 hover:bg-indigo-100"><Book className="w-3 h-3" /> Conselheiro Bíblico</button>
         <button onClick={() => handleSend("Como lidar psicologicamente com a falta de comunicação?")} className="flex-none px-4 py-2 bg-rose-50 text-rose-700 rounded-full text-xs font-bold flex items-center gap-2 border border-rose-100 hover:bg-rose-100"><Heart className="w-3 h-3" /> Dica Psicológica</button>
         <button onClick={() => handleSend("S.O.S: Estamos em um momento de crise intensa. O que fazer agora?")} className="flex-none px-4 py-2 bg-red-600 text-white rounded-full text-xs font-bold flex items-center gap-2 border border-red-700 shadow-lg"><ShieldAlert className="w-3 h-3" /> Gestão de Crise</button>
      </div>

      {/* Input */}
      <div className="p-6 bg-white border-t border-indigo-50">
        <form className="relative flex gap-4" onSubmit={(e) => { e.preventDefault(); handleSend(); }}>
          <input 
            className="flex-1 bg-slate-50 border border-slate-200 p-4 pr-14 rounded-2xl text-sm focus:outline-none focus:border-indigo-500 transition-all"
            placeholder="Pergunte qualquer coisa sobre sua felicidade conjugal..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button 
            type="submit"
            className="absolute right-2 top-2 p-3 bg-indigo-600 text-white rounded-xl shadow-lg hover:bg-indigo-700 transition-all"
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
      </div>
    </div>
  );
};

export default PersonalCoach;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { Heart, Sparkles, BookOpen, User, Calendar, CheckCircle2, Trophy, ArrowRight, ShieldCheck, Clock, Bell, BellOff, Quote, UserPlus, AlertTriangle, ListChecks, MessageCircleCode, BrainCircuit, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  // Inicialização do estado de assinatura com lógica de Trial
  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  // Lógica de Validação de Acesso
  const checkAccess = () => {
    // Se já é assinante ativo, acesso liberado
    if (user.subscription.status === 'active') return true;

    // Se está no trial, verifica se ainda está no prazo de 7 dias
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;

    return (now - trialStart) <= sevenDaysInMs;
  };

  const getTrialDaysRemaining = () => {
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDaysInMs - (now - trialStart);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: {
        ...prev.subscription,
        status: 'active',
        plan: planId as any
      }
    }));
    setActiveTab('dashboard');
  };

  const completeMission = async (mission: Mission) => {
    setLoadingMission(true);
    try {
      const { feedback, impact } = await getMissionCompletionFeedback(mission, partner.name);
      const updatedMissions = partner.challenge.missions.map(m => 
        m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
      );

      const nextDay = mission.day + 1;
      if (nextDay <= (partner.challenge.type || 0)) {
        const nextData = await generateDailyMission(partner.language, nextDay);
        updatedMissions.push({
          id: Math.random().toString(36).substr(2, 9),
          day: nextDay,
          title: nextData.title || "Próxima Missão",
          description: nextData.description || "Continue sua jornada.",
          rationale: nextData.rationale || "O amor é construído dia a dia.",
          completed: false
        });
      }

      setAiInsight(feedback);
      setPartner(prev => ({
        ...prev,
        tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
        challenge: { ...prev.challenge, missions: updatedMissions }
      }));
    } finally {
      setLoadingMission(false);
    }
  };

  const renderMyChallenges = () => {
    const challenge = partner.challenge;
    if (!challenge.type) {
      return (
        <div className="max-w-4xl mx-auto py-12 text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
            <Calendar className="w-16 h-16 text-rose-200 mx-auto mb-6" />
            <h2 className="text-3xl font-bold text-rose-900 mb-4">Nenhum Desafio Ativo</h2>
            <p className="text-gray-600 mb-8 max-w-md mx-auto">Você ainda não iniciou uma jornada de amor. Vá até a aba "Missão" para começar.</p>
            <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-bold shadow-lg hover:bg-rose-700 transition-all">Iniciar Novo Desafio</button>
          </div>
        </div>
      );
    }

    const completedMissions = challenge.missions.filter(m => m.completed).sort((a, b) => b.day - a.day);
    const pendingMissions = challenge.missions.filter(m => !m.completed).sort((a, b) => a.day - b.day);
    const progressPercent = Math.round((completedMissions.length / challenge.type) * 100);

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in duration-500 pb-12">
        <div className="text-center"><h2 className="text-4xl font-bold text-rose-900 mb-2">Seu Progresso</h2></div>
        <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-rose-100 grid grid-cols-1 md:grid-cols-3 gap-8 items-center">
          <div><p className="text-sm font-bold text-rose-400 uppercase tracking-widest mb-1">Desafio Atual</p><h3 className="text-2xl font-black text-rose-900">{challenge.type} Dias</h3></div>
          <div className="relative pt-1">
            <div className="flex mb-2 items-center justify-between"><span className="text-xs font-semibold text-rose-600 uppercase">Progresso</span><span className="text-xs font-semibold text-rose-600">{progressPercent}%</span></div>
            <div className="overflow-hidden h-2 mb-4 flex rounded bg-rose-100"><div style={{ width: `${progressPercent}%` }} className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-rose-600 transition-all duration-1000"></div></div>
          </div>
          <div className="text-center"><div className="inline-flex flex-col items-center px-6 py-3 bg-rose-50 rounded-2xl border border-rose-100"><span className="text-3xl font-black text-rose-600">{completedMissions.length}</span><span className="text-[10px] font-bold text-rose-400 uppercase">Concluídas</span></div></div>
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <h3 className="text-xl font-bold text-rose-900 flex items-center gap-2 px-2"><Clock className="w-5 h-5 text-rose-400" /> Próxima Etapa</h3>
            {pendingMissions.length > 0 ? pendingMissions.map(m => (
              <div key={m.id} className="bg-white p-6 rounded-[2rem] border-2 border-rose-100 shadow-sm hover:border-rose-400 transition-all group cursor-pointer" onClick={() => setActiveTab('challenge')}>
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 bg-rose-50 rounded-xl flex items-center justify-center shrink-0 text-rose-600 font-black">{m.day}</div>
                  <div className="flex-1"><h4 className="font-bold text-gray-800 mb-1 group-hover:text-rose-600">{m.title}</h4><p className="text-sm text-gray-500 line-clamp-2">{m.description}</p></div>
                  <ChevronRight className="w-5 h-5 text-gray-300 group-hover:translate-x-1" />
                </div>
              </div>
            )) : <div className="p-10 border-2 border-dashed border-rose-100 rounded-[2rem] text-center text-gray-400">Jornada finalizada!</div>}
          </div>
          <div className="space-y-6">
            <h3 className="text-xl font-bold text-rose-900 flex items-center gap-2 px-2"><CheckCircle2 className="w-5 h-5 text-green-500" /> Concluídas</h3>
            {completedMissions.length > 0 ? completedMissions.map(m => (
              <div key={m.id} className="bg-green-50/50 p-5 rounded-2xl border border-green-100 flex items-center gap-4 opacity-80">
                <div className="w-10 h-10 bg-green-500 rounded-full flex items-center justify-center shrink-0"><CheckCircle2 className="w-5 h-5 text-white" /></div>
                <div className="flex-1"><h4 className="font-bold text-green-900 text-sm">Dia {m.day}: {m.title}</h4></div>
              </div>
            )) : <div className="p-8 bg-gray-50 rounded-[2rem] text-center text-gray-400 text-sm">Nenhuma missão concluída ainda.</div>}
          </div>
        </div>
      </div>
    );
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    // Proteção de rotas Premium
    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'coach': return <PersonalCoach />;
      case 'myChallenges': return renderMyChallenges();
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
                <div className="w-20 h-20 bg-rose-600 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-lg"><ShieldCheck className="w-10 h-10 text-white" /></div>
                <h2 className="text-4xl font-bold text-rose-900 mb-6">Compromisso de Amor</h2>
                <p className="text-gray-600 text-lg mb-10 max-w-2xl mx-auto leading-relaxed">Inicie um desafio intencional para transformar seu mundo.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-lg mx-auto">
                  <button onClick={() => { setLoadingMission(true); generateDailyMission(partner.language, 1).then(d => { setPartner(p => ({ ...p, challenge: { type: 30, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }); }} className="bg-white border-2 border-rose-200 p-8 rounded-3xl hover:border-rose-500 hover:bg-rose-50 transition-all text-left">
                    <span className="block text-rose-600 font-bold text-2xl mb-2">30 Dias</span>
                    <span className="text-gray-500 text-sm">Foco Diário.</span>
                  </button>
                  <button onClick={() => { setLoadingMission(true); generateDailyMission(partner.language, 1).then(d => { setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }); }} className="bg-rose-600 p-8 rounded-3xl hover:bg-rose-700 transition-all text-left shadow-lg text-white">
                    <span className="block font-bold text-2xl mb-2">60 Dias</span>
                    <span className="text-rose-100 text-sm">Transformação Profunda.</span>
                  </button>
                </div>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
             {currentMission ? (
               <div className="space-y-6">
                  <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
                    <BrainCircuit className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-6"><div className="px-4 py-1 bg-rose-800 rounded-full text-xs font-bold uppercase tracking-widest text-rose-200">Missão Dia {currentMission.day}</div></div>
                      <h4 className="text-4xl font-bold mb-6 text-rose-50">{currentMission.title}</h4>
                      <p className="text-xl text-rose-100/90 leading-relaxed mb-10">"{currentMission.description}"</p>
                      <button onClick={() => completeMission(currentMission)} disabled={loadingMission} className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-3 shadow-xl">
                        {loadingMission ? "Processando..." : "Concluir com Amor"}
                      </button>
                    </div>
                  </div>
                  {aiInsight && <div className="bg-amber-50 border-2 border-amber-200 p-6 rounded-3xl animate-in zoom-in duration-300"><div className="flex gap-4 items-start"><Sparkles className="w-6 h-6 text-amber-500 shrink-0" /><div><p className="font-bold text-amber-900 mb-1">Feedback da IA</p><p className="text-amber-800 italic leading-relaxed">{aiInsight}</p></div></div></div>}
               </div>
             ) : <div className="text-center py-20 bg-white rounded-[3rem] border border-rose-100"><Trophy className="w-16 h-16 text-yellow-500 mx-auto mb-4" /><h3 className="text-3xl font-bold text-rose-900">Etapa Concluída!</h3></div>}
          </div>
        );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge label={`Seu Tanque`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
              <TankGauge label={`Tanque de ${partner.name}`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
            </div>
            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 relative group overflow-hidden">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full" />
              <div className="flex items-center gap-6"><div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shadow-inner"><MessageCircleCode className="w-8 h-8 text-indigo-100" /></div><div><h3 className="text-2xl font-black mb-1">Personal Coach de Felicidade</h3><p className="text-indigo-200 text-sm">Conselhos bíblicos e psicológicos 24h.</p></div></div>
              <button onClick={() => setActiveTab('coach')} className="px-8 py-4 bg-white text-indigo-900 rounded-2xl font-black text-sm hover:bg-indigo-50 transition-all z-10">Pedir Conselho</button>
            </div>
            {user.subscription.status === 'trial' && (
              <div className={`p-8 rounded-[2.5rem] text-white flex justify-between items-center transition-colors ${trialDays <= 2 ? 'bg-orange-600' : 'bg-rose-900'}`}>
                <div><h4 className="font-bold">Teste Gratuito: {trialDays} {trialDays === 1 ? 'dia' : 'dias'} restante{trialDays === 1 ? '' : 's'}</h4><p className="text-xs opacity-70">Aproveite a IA Mentora e o Coach antes da expiração.</p></div>
                <button onClick={() => setActiveTab('paywall')} className="px-6 py-2 bg-white text-rose-900 rounded-xl font-bold text-sm">Assinar Agora</button>
              </div>
            )}
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      default: return <div className="p-10 text-center">Aba em desenvolvimento</div>;
    }
  };

  return (
    <div className="min-h-screen pb-32">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}
      <header className="sticky top-0 z-50 bg-rose-50/80 backdrop-blur-lg border-b border-rose-100 mb-8">
        <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveTab('dashboard')}><div className="w-10 h-10 bg-rose-600 rounded-xl flex items-center justify-center shadow-lg"><Heart className="w-6 h-6 text-white fill-white" /></div><h1 className="text-lg font-black text-rose-900">LoveBridge AI</h1></div>
          <nav className="hidden lg:flex items-center gap-2">
            {['dashboard', 'challenge', 'myChallenges', 'coach', 'quiz', 'partnerQuiz'].map((tab) => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`px-5 py-2 rounded-xl text-sm font-bold capitalize ${activeTab === tab ? 'bg-rose-600 text-white' : 'text-rose-900 hover:bg-rose-100'}`}>
                {tab === 'dashboard' ? 'Painel' : tab === 'challenge' ? 'Missão' : tab === 'myChallenges' ? 'Meus Desafios' : tab === 'coach' ? 'Personal Coach' : tab === 'quiz' ? 'Meu Teste' : 'Teste Parceiro'}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">{renderContent()}</main>

      <div className="fixed bottom-6 left-0 right-0 px-6 sm:hidden z-50">
        <div className="bg-rose-900/95 backdrop-blur-md shadow-2xl rounded-[2rem] p-4 flex justify-around items-center border border-white/10">
             <button onClick={() => setActiveTab('dashboard')} className={`p-3 rounded-2xl ${activeTab === 'dashboard' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><Sparkles className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('challenge')} className={`p-3 rounded-2xl ${activeTab === 'challenge' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><Calendar className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('myChallenges')} className={`p-3 rounded-2xl ${activeTab === 'myChallenges' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><ListChecks className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('coach')} className={`p-3 rounded-2xl ${activeTab === 'coach' ? 'bg-white text-rose-900' : 'text-rose-300'}`}><MessageCircleCode className="w-6 h-6" /></button>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, BookOpen, User, Calendar, CheckCircle2, Trophy, 
  ArrowRight, ShieldCheck, Clock, Bell, BellOff, Quote, UserPlus, 
  AlertTriangle, ListChecks, MessageCircleCode, BrainCircuit, ChevronRight, 
  Book, Info
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const getTrialDaysRemaining = () => {
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDaysInMs - (now - trialStart);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const completeMission = async (mission: Mission) => {
    setLoadingMission(true);
    try {
      const { feedback, impact } = await getMissionCompletionFeedback(mission, partner.name);
      const updatedMissions = partner.challenge.missions.map(m => 
        m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
      );

      const nextDay = mission.day + 1;
      if (nextDay <= (partner.challenge.type || 0)) {
        const nextData = await generateDailyMission(partner.language, nextDay);
        updatedMissions.push({
          id: Math.random().toString(36).substr(2, 9),
          day: nextDay,
          title: nextData.title || "Próxima Missão",
          description: nextData.description || "Continue sua jornada.",
          rationale: nextData.rationale || "O amor é construído dia a dia.",
          completed: false
        });
      }

      setAiInsight(feedback);
      setPartner(prev => ({
        ...prev,
        tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
        challenge: { ...prev.challenge, missions: updatedMissions }
      }));
    } finally {
      setLoadingMission(false);
    }
  };

  const renderMyChallenges = () => {
    const challenge = partner.challenge;
    if (!challenge.type) {
      return (
        <div className="max-w-4xl mx-auto py-12 text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
            <Calendar className="w-16 h-16 text-rose-200 mx-auto mb-6" />
            <h2 className="text-3xl font-bold text-rose-900 mb-4">Nenhum Desafio Ativo</h2>
            <p className="text-gray-600 mb-8 max-w-md mx-auto">Inicie uma jornada de amor na aba "Missão" para acompanhar seu progresso aqui.</p>
            <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-bold shadow-lg hover:bg-rose-700 transition-all">Começar Agora</button>
          </div>
        </div>
      );
    }

    const completedMissions = challenge.missions.filter(m => m.completed).sort((a, b) => b.day - a.day);
    const pendingMissions = challenge.missions.filter(m => !m.completed).sort((a, b) => a.day - b.day);
    const progressPercent = Math.round((completedMissions.length / challenge.type) * 100);

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in duration-500 pb-12">
        <div className="text-center"><h2 className="text-4xl font-bold text-rose-900 mb-2">Seu Histórico</h2></div>
        <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-rose-100 grid grid-cols-1 md:grid-cols-3 gap-8 items-center">
          <div><p className="text-sm font-bold text-rose-400 uppercase tracking-widest mb-1">Jornada</p><h3 className="text-2xl font-black text-rose-900">{challenge.type} Dias</h3></div>
          <div className="relative pt-1">
            <div className="flex mb-2 items-center justify-between"><span className="text-xs font-semibold text-rose-600 uppercase">Progresso</span><span className="text-xs font-semibold text-rose-600">{progressPercent}%</span></div>
            <div className="overflow-hidden h-2 mb-4 flex rounded bg-rose-100"><div style={{ width: `${progressPercent}%` }} className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-rose-600 transition-all duration-1000"></div></div>
          </div>
          <div className="text-center"><div className="inline-flex flex-col items-center px-6 py-3 bg-rose-50 rounded-2xl border border-rose-100"><span className="text-3xl font-black text-rose-600">{completedMissions.length}</span><span className="text-[10px] font-bold text-rose-400 uppercase">Atos de Amor</span></div></div>
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <h3 className="text-xl font-bold text-rose-900 flex items-center gap-2 px-2"><Clock className="w-5 h-5 text-rose-400" /> Próxima Missão</h3>
            {pendingMissions.length > 0 ? pendingMissions.slice(0, 1).map(m => (
              <div key={m.id} className="bg-white p-6 rounded-[2rem] border-2 border-rose-100 shadow-sm hover:border-rose-400 transition-all group cursor-pointer" onClick={() => setActiveTab('challenge')}>
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 bg-rose-50 rounded-xl flex items-center justify-center shrink-0 text-rose-600 font-black">{m.day}</div>
                  <div className="flex-1"><h4 className="font-bold text-gray-800 mb-1 group-hover:text-rose-600">{m.title}</h4><p className="text-sm text-gray-500 line-clamp-2">{m.description}</p></div>
                  <ChevronRight className="w-5 h-5 text-gray-300 group-hover:translate-x-1" />
                </div>
              </div>
            )) : <div className="p-10 border-2 border-dashed border-rose-100 rounded-[2rem] text-center text-gray-400">Tudo em dia!</div>}
          </div>
          <div className="space-y-6">
            <h3 className="text-xl font-bold text-rose-900 flex items-center gap-2 px-2"><CheckCircle2 className="w-5 h-5 text-green-500" /> Concluídas</h3>
            <div className="space-y-4">
              {completedMissions.length > 0 ? completedMissions.map(m => (
                <div key={m.id} className="bg-green-50/50 p-5 rounded-2xl border border-green-100 flex items-center gap-4 opacity-80">
                  <div className="w-10 h-10 bg-green-500 rounded-full flex items-center justify-center shrink-0"><CheckCircle2 className="w-5 h-5 text-white" /></div>
                  <div className="flex-1"><h4 className="font-bold text-green-900 text-sm">Dia {m.day}: {m.title}</h4><p className="text-[10px] text-green-600 font-bold uppercase">{m.completedAt ? new Date(m.completedAt).toLocaleDateString() : 'Concluído'}</p></div>
                </div>
              )) : <div className="p-8 bg-gray-50 rounded-[2rem] text-center text-gray-400 text-sm">Sua jornada começa agora.</div>}
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderContent = () => {
    const hasAccess = checkAccess();
    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }
    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'coach': return <PersonalCoach />;
      case 'myChallenges': return renderMyChallenges();
      case 'guide':
        return (
          <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in duration-500 pb-12">
             <div className="text-center">
                <h2 className="text-4xl font-bold text-rose-900 mb-4">Guia das Linguagens</h2>
                <p className="text-gray-600 max-w-2xl mx-auto">Entenda como cada linguagem comunica amor e descubra a sua.</p>
             </div>
             <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-rose-100 relative overflow-hidden">
                <Quote className="absolute -top-6 -right-6 w-32 h-32 text-rose-50" />
                <div className="relative z-10 space-y-4 text-gray-700 leading-relaxed">
                   <h3 className="text-2xl font-bold text-rose-900 flex items-center gap-3 mb-4"><Info className="w-6 h-6" /> O Conceito</h3>
                   <p>Dr. Gary Chapman propõe que cada pessoa tem uma forma primária de expressar e receber amor. Quando você ama seu parceiro na "língua" dele, você preenche o seu <strong>Tanque Emocional</strong>.</p>
                   <div className="bg-rose-50 p-6 rounded-2xl italic border-l-4 border-rose-500 mt-6">"O amor é uma decisão que tomamos todos os dias."</div>
                </div>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {Object.entries(LANGUAGE_METADATA).map(([lang, meta]) => (
                  lang !== LoveLanguage.NONE && (
                    <div key={lang} className={`p-8 rounded-[2.5rem] border shadow-sm transition-all hover:shadow-md ${meta.color}`}>
                      <div className="flex items-center gap-4 mb-4"><div className="p-3 bg-white/50 rounded-2xl">{meta.icon}</div><h3 className="font-bold text-xl">{lang}</h3></div>
                      <p className="text-sm opacity-90 leading-relaxed">{meta.description}</p>
                    </div>
                  )
                ))}
             </div>
             <div className="bg-rose-900 p-10 rounded-[3rem] text-white text-center">
               <h3 className="text-2xl font-bold mb-4">Ainda não sabe a sua?</h3>
               <button onClick={() => setActiveTab('quiz')} className="px-8 py-3 bg-white text-rose-900 rounded-2xl font-black hover:bg-rose-50 transition-all">Fazer meu Teste agora</button>
             </div>
          </div>
        );
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
                <div className="w-20 h-20 bg-rose-600 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-lg"><ShieldCheck className="w-10 h-10 text-white" /></div>
                <h2 className="text-4xl font-bold text-rose-900 mb-6">Compromisso de Amor</h2>
                <p className="text-gray-600 text-lg mb-10 max-w-2xl mx-auto leading-relaxed">Escolha a intensidade da sua jornada de reconexão guiada por IA.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-lg mx-auto">
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, 1); setPartner(p => ({ ...p, challenge: { type: 30, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-white border-2 border-rose-200 p-8 rounded-3xl hover:border-rose-500 hover:bg-rose-50 transition-all text-left">
                    <span className="block text-rose-600 font-bold text-2xl mb-2">30 Dias</span>
                    <span className="text-gray-500 text-sm italic">Intensivo de Reconexão.</span>
                  </button>
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, 1); setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-rose-600 p-8 rounded-3xl hover:bg-rose-700 transition-all text-left shadow-lg text-white">
                    <span className="block font-bold text-2xl mb-2">60 Dias</span>
                    <span className="text-rose-100 text-sm italic">Nova Identidade Conjugal.</span>
                  </button>
                </div>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
             {currentMission ? (
               <div className="space-y-6">
                  <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
                    <BrainCircuit className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-6"><div className="px-4 py-1 bg-rose-800 rounded-full text-xs font-bold uppercase tracking-widest text-rose-200">Missão Dia {currentMission.day}</div></div>
                      <h4 className="text-4xl font-bold mb-6 text-rose-50">{currentMission.title}</h4>
                      <p className="text-xl text-rose-100/90 leading-relaxed mb-10">"{currentMission.description}"</p>
                      <button onClick={() => completeMission(currentMission)} disabled={loadingMission} className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-3 shadow-xl">
                        {loadingMission ? "Processando..." : "Concluir com Amor"}
                      </button>
                    </div>
                  </div>
                  {aiInsight && <div className="bg-amber-50 border-2 border-amber-200 p-6 rounded-3xl animate-in zoom-in duration-300"><div className="flex gap-4 items-start"><Sparkles className="w-6 h-6 text-amber-500 shrink-0" /><div><p className="font-bold text-amber-900 mb-1">Feedback da IA</p><p className="text-amber-800 italic leading-relaxed">{aiInsight}</p></div></div></div>}
               </div>
             ) : <div className="text-center py-20 bg-white rounded-[3rem] border border-rose-100"><Trophy className="w-16 h-16 text-yellow-500 mx-auto mb-4" /><h3 className="text-3xl font-bold text-rose-900">Etapa Concluída!</h3><p className="text-gray-500">Volte amanhã para sua próxima instrução guiada por IA.</p></div>}
          </div>
        );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in duration-500 pb-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <TankGauge label={`Seu Tanque`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
                <div className="bg-white p-6 rounded-2xl border border-rose-100 flex items-center justify-between">
                   <div><p className="text-xs font-bold text-gray-400 uppercase">Sua Linguagem</p><p className="font-black text-rose-600">{user.language}</p></div>
                   <button onClick={() => setActiveTab('quiz')} className="p-2 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-100 transition-all"><ChevronRight className="w-5 h-5" /></button>
                </div>
              </div>
              <div className="space-y-4">
                <TankGauge label={`Tanque de ${partner.name}`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
                <div className="bg-white p-6 rounded-2xl border border-rose-100 flex items-center justify-between">
                   <div><p className="text-xs font-bold text-gray-400 uppercase">Linguagem de {partner.name}</p><p className="font-black text-rose-600">{partner.language}</p></div>
                   <button onClick={() => setActiveTab('partnerQuiz')} className="p-2 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-100 transition-all"><UserPlus className="w-5 h-5" /></button>
                </div>
              </div>
            </div>

            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 relative group overflow-hidden">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full" />
              <div className="flex items-center gap-6"><div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shadow-inner"><MessageCircleCode className="w-8 h-8 text-indigo-100" /></div><div><h3 className="text-2xl font-black mb-1">Personal Coach</h3><p className="text-indigo-200 text-sm">Apoio psicológico, bíblico e gestão de crise 24h.</p></div></div>
              <button onClick={() => setActiveTab('coach')} className="px-8 py-4 bg-white text-indigo-900 rounded-2xl font-black text-sm hover:bg-indigo-50 transition-all z-10 shadow-lg">Conversar Agora</button>
            </div>

            {user.subscription.status === 'trial' && (
              <div className={`p-8 rounded-[2.5rem] text-white flex flex-col sm:flex-row justify-between items-center gap-4 transition-colors ${trialDays <= 2 ? 'bg-orange-600 animate-pulse' : 'bg-rose-900'}`}>
                <div><h4 className="font-bold text-lg">Período de Teste: {trialDays} {trialDays === 1 ? 'dia' : 'dias'} restante{trialDays === 1 ? '' : 's'}</h4><p className="text-xs opacity-70">Acesse todas as funções premium para blindar seu amor.</p></div>
                <button onClick={() => setActiveTab('paywall')} className="px-6 py-3 bg-white text-rose-900 rounded-xl font-black text-sm shadow-lg">Garantir Acesso Vitalício</button>
              </div>
            )}
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      default: return <div className="p-10 text-center">Aba em desenvolvimento</div>;
    }
  };

  return (
    <div className="min-h-screen pb-32 bg-rose-50/20">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-xl border-b border-rose-100">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-10 h-10 bg-rose-600 rounded-xl flex items-center justify-center shadow-lg group-hover:rotate-6 transition-transform"><Heart className="w-6 h-6 text-white fill-white" /></div>
            <div>
              <h1 className="text-lg font-black text-rose-900 leading-none">LoveBridge</h1>
              <span className="text-[10px] font-bold text-rose-400 uppercase tracking-widest">Inteligência Afetiva</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-1">
            {[
              { id: 'dashboard', label: 'Painel', icon: <Sparkles className="w-4 h-4" /> },
              { id: 'challenge', label: 'Missão', icon: <Calendar className="w-4 h-4" /> },
              { id: 'myChallenges', label: 'Meus Desafios', icon: <ListChecks className="w-4 h-4" /> },
              { id: 'coach', label: 'Coach', icon: <MessageCircleCode className="w-4 h-4" /> },
              { id: 'guide', label: 'Guia', icon: <BookOpen className="w-4 h-4" /> }
            ].map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-5 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 transition-all ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-lg shadow-rose-100' : 'text-rose-900 hover:bg-rose-50'
                }`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-8">
        {renderContent()}
      </main>

      {/* Mobile Nav - Completa */}
      <div className="fixed bottom-6 left-0 right-0 px-6 sm:hidden z-50">
        <div className="bg-rose-900/95 backdrop-blur-md shadow-2xl rounded-[2.5rem] p-3 flex justify-around items-center border border-white/10">
             <button onClick={() => setActiveTab('dashboard')} className={`p-4 rounded-2xl transition-all ${activeTab === 'dashboard' ? 'bg-white text-rose-900 shadow-lg' : 'text-rose-300 hover:bg-white/10'}`}><Sparkles className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('challenge')} className={`p-4 rounded-2xl transition-all ${activeTab === 'challenge' ? 'bg-white text-rose-900 shadow-lg' : 'text-rose-300 hover:bg-white/10'}`}><Calendar className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('myChallenges')} className={`p-4 rounded-2xl transition-all ${activeTab === 'myChallenges' ? 'bg-white text-rose-900 shadow-lg' : 'text-rose-300 hover:bg-white/10'}`}><ListChecks className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('coach')} className={`p-4 rounded-2xl transition-all ${activeTab === 'coach' ? 'bg-white text-rose-900 shadow-lg' : 'text-rose-300 hover:bg-white/10'}`}><MessageCircleCode className="w-6 h-6" /></button>
             <button onClick={() => setActiveTab('guide')} className={`p-4 rounded-2xl transition-all ${activeTab === 'guide' ? 'bg-white text-rose-900 shadow-lg' : 'text-rose-300 hover:bg-white/10'}`}><Book className="w-6 h-6" /></button>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, BookOpen, Calendar, CheckCircle2, Trophy, 
  Clock, ListChecks, MessageCircleCode, BrainCircuit, ChevronRight, 
  Book, Info, UserPlus, History
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const getTrialDaysRemaining = () => {
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDaysInMs - (now - trialStart);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const completeMission = async (mission: Mission) => {
    setLoadingMission(true);
    try {
      const { feedback, impact } = await getMissionCompletionFeedback(mission, partner.name);
      const updatedMissions = partner.challenge.missions.map(m => 
        m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
      );

      const nextDay = mission.day + 1;
      if (nextDay <= (partner.challenge.type || 0)) {
        const nextData = await generateDailyMission(partner.language, nextDay);
        updatedMissions.push({
          id: Math.random().toString(36).substr(2, 9),
          day: nextDay,
          title: nextData.title || "Próxima Missão",
          description: nextData.description || "Continue sua jornada.",
          rationale: nextData.rationale || "O amor é construído dia a dia.",
          completed: false
        });
      }

      setAiInsight(feedback);
      setPartner(prev => ({
        ...prev,
        tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
        challenge: { ...prev.challenge, missions: updatedMissions }
      }));
    } finally {
      setLoadingMission(false);
    }
  };

  const renderMyChallenges = () => {
    const challenge = partner.challenge;
    if (!challenge.type) {
      return (
        <div className="max-w-4xl mx-auto py-12 text-center animate-in fade-in slide-in-from-bottom-4">
          <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
            <History className="w-16 h-16 text-rose-200 mx-auto mb-6" />
            <h2 className="text-3xl font-bold text-rose-900 mb-4">Seu Histórico de Amor</h2>
            <p className="text-gray-600 mb-8 max-w-md mx-auto">Você ainda não tem desafios ativos. Inicie uma jornada de 30 ou 60 dias para ver seu progresso aqui.</p>
            <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-bold shadow-lg hover:bg-rose-700 transition-all">Começar Agora</button>
          </div>
        </div>
      );
    }

    const completedMissions = challenge.missions.filter(m => m.completed).sort((a, b) => b.day - a.day);
    const progressPercent = Math.round((completedMissions.length / challenge.type) * 100);

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-rose-100 flex flex-col md:flex-row justify-between items-center gap-6">
          <div>
            <p className="text-xs font-bold text-rose-400 uppercase tracking-widest mb-1">Jornada Ativa</p>
            <h3 className="text-2xl font-black text-rose-900">{challenge.type} Dias de Intencionalidade</h3>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-2xl font-black text-rose-600 leading-none">{progressPercent}%</p>
              <p className="text-[10px] font-bold text-gray-400 uppercase">Concluído</p>
            </div>
            <div className="w-16 h-16 rounded-full border-4 border-rose-100 flex items-center justify-center relative">
               <div className="absolute inset-0 rounded-full border-4 border-rose-600" style={{ clipPath: `inset(${100 - progressPercent}% 0 0 0)` }}></div>
               <Trophy className="w-6 h-6 text-rose-600" />
            </div>
          </div>
        </div>

        <div className="space-y-6">
           <h3 className="text-xl font-bold text-rose-900 px-2 flex items-center gap-2"><ListChecks className="w-5 h-5 text-rose-500" /> Linha do Tempo</h3>
           <div className="grid gap-4">
             {challenge.missions.map(m => (
               <div key={m.id} className={`p-6 rounded-[2rem] border transition-all ${m.completed ? 'bg-green-50 border-green-100' : 'bg-white border-rose-50'}`}>
                 <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black ${m.completed ? 'bg-green-500 text-white' : 'bg-rose-50 text-rose-400'}`}>{m.day}</div>
                    <div className="flex-1">
                       <h4 className={`font-bold ${m.completed ? 'text-green-900' : 'text-rose-900'}`}>{m.title}</h4>
                       <p className="text-sm text-gray-500 line-clamp-1">{m.description}</p>
                    </div>
                    {m.completed ? (
                      <CheckCircle2 className="w-6 h-6 text-green-500" />
                    ) : (
                      <button onClick={() => setActiveTab('challenge')} className="text-xs font-bold text-rose-600 hover:underline">Fazer Missão</button>
                    )}
                 </div>
               </div>
             ))}
           </div>
        </div>
      </div>
    );
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    // Se não tem acesso e tentou entrar em aba premium, mostra paywall preservando menus
    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'coach': return <PersonalCoach />;
      case 'myChallenges': return renderMyChallenges();
      case 'guide':
        return (
          <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
             <div className="text-center">
                <h2 className="text-4xl font-bold text-rose-900 mb-4">Guia das Linguagens</h2>
                <p className="text-gray-600">O segredo para um amor duradouro é falar a língua do outro.</p>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {Object.entries(LANGUAGE_METADATA).map(([lang, meta]) => (
                  lang !== LoveLanguage.NONE && (
                    <div key={lang} className={`p-8 rounded-[2.5rem] border shadow-sm transition-all hover:shadow-md ${meta.color}`}>
                      <div className="flex items-center gap-4 mb-4">
                        <div className="p-3 bg-white/50 rounded-2xl">{meta.icon}</div>
                        <h3 className="font-bold text-xl">{lang}</h3>
                      </div>
                      <p className="text-sm opacity-90 leading-relaxed mb-6">{meta.description}</p>
                    </div>
                  )
                ))}
             </div>
             <div className="bg-rose-900 p-10 rounded-[3rem] text-white text-center shadow-xl">
               <h3 className="text-2xl font-bold mb-4">Dúvidas sobre sua linguagem?</h3>
               <div className="flex flex-col sm:flex-row gap-4 justify-center">
                 <button onClick={() => setActiveTab('quiz')} className="px-8 py-3 bg-white text-rose-900 rounded-2xl font-black hover:bg-rose-50 transition-all">Refazer Meu Teste</button>
                 <button onClick={() => setActiveTab('partnerQuiz')} className="px-8 py-3 bg-rose-800 text-white rounded-2xl font-black hover:bg-rose-700 transition-all border border-rose-700">Teste do Parceiro</button>
               </div>
             </div>
          </div>
        );
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
                <Calendar className="w-16 h-16 text-rose-600 mx-auto mb-8" />
                <h2 className="text-4xl font-bold text-rose-900 mb-6">Iniciar Novo Desafio</h2>
                <p className="text-gray-600 text-lg mb-10 max-w-2xl mx-auto">Escolha por quanto tempo deseja se dedicar intensamente a preencher o tanque do seu parceiro.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-lg mx-auto">
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, 1); setPartner(p => ({ ...p, challenge: { type: 30, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-white border-2 border-rose-200 p-8 rounded-3xl hover:border-rose-500 hover:bg-rose-50 transition-all text-left">
                    <span className="block text-rose-600 font-bold text-2xl mb-2">30 Dias</span>
                    <span className="text-gray-500 text-sm italic">Ideal para reconexão imediata.</span>
                  </button>
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, 1); setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-rose-600 p-8 rounded-3xl hover:bg-rose-700 transition-all text-left shadow-lg text-white">
                    <span className="block font-bold text-2xl mb-2">60 Dias</span>
                    <span className="text-rose-100 text-sm italic">Foco em mudança de hábitos profundos.</span>
                  </button>
                </div>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12">
             {currentMission ? (
               <div className="space-y-6">
                  <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
                    <BrainCircuit className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-6"><div className="px-4 py-1 bg-rose-800 rounded-full text-xs font-bold uppercase tracking-widest text-rose-200">Missão Dia {currentMission.day}</div></div>
                      <h4 className="text-4xl font-bold mb-6 text-rose-50">{currentMission.title}</h4>
                      <p className="text-xl text-rose-100/90 leading-relaxed mb-10">"{currentMission.description}"</p>
                      <button onClick={() => completeMission(currentMission)} disabled={loadingMission} className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-3 shadow-xl">
                        {loadingMission ? "IA Avaliando..." : "Missão Cumprida!"}
                      </button>
                    </div>
                  </div>
                  {aiInsight && <div className="bg-amber-50 border-2 border-amber-200 p-6 rounded-3xl animate-in zoom-in duration-300"><div className="flex gap-4 items-start"><Sparkles className="w-6 h-6 text-amber-500 shrink-0" /><div><p className="font-bold text-amber-900 mb-1">Feedback da Mentora IA</p><p className="text-amber-800 italic leading-relaxed">{aiInsight}</p></div></div></div>}
               </div>
             ) : <div className="text-center py-20 bg-white rounded-[3rem] border border-rose-100"><Trophy className="w-16 h-16 text-yellow-500 mx-auto mb-4" /><h3 className="text-3xl font-bold text-rose-900">Parabéns!</h3><p className="text-gray-500">Missões de hoje concluídas. Volte amanhã!</p></div>}
          </div>
        );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in pb-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge label={`Seu Tanque Emocional`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
              <TankGauge label={`Tanque de ${partner.name} (IA)`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><Heart className="text-rose-500" /></div>
                    <div><p className="text-xs font-bold text-gray-400 uppercase">Sua Linguagem</p><p className="font-black text-rose-900">{user.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('quiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><UserPlus className="text-rose-500" /></div>
                    <div><p className="text-xs font-bold text-gray-400 uppercase">Linguagem de {partner.name}</p><p className="font-black text-rose-900">{partner.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('partnerQuiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
            </div>

            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 relative group overflow-hidden">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full group-hover:scale-150 transition-all duration-700" />
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shadow-inner"><MessageCircleCode className="w-8 h-8 text-indigo-100" /></div>
                <div><h3 className="text-2xl font-black mb-1">Personal Coach</h3><p className="text-indigo-200 text-sm">Apoio bíblico, psicológico e gestão de crise 24h.</p></div>
              </div>
              <button onClick={() => setActiveTab('coach')} className="px-8 py-4 bg-white text-indigo-900 rounded-2xl font-black text-sm hover:bg-indigo-50 transition-all z-10 shadow-lg">Pedir Ajuda</button>
            </div>

            {user.subscription.status === 'trial' && (
              <div className={`p-8 rounded-[2.5rem] text-white flex flex-col sm:flex-row justify-between items-center gap-4 transition-colors ${trialDays <= 2 ? 'bg-orange-600 animate-pulse' : 'bg-rose-900'}`}>
                <div><h4 className="font-bold text-lg">Teste Gratuito: {trialDays} dias restantes</h4><p className="text-xs opacity-80">Aproveite todas as ferramentas de IA para blindar seu amor.</p></div>
                <button onClick={() => setActiveTab('paywall')} className="px-6 py-3 bg-white text-rose-900 rounded-xl font-black text-sm shadow-lg">Ver Planos</button>
              </div>
            )}
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      default: return <div className="p-10 text-center text-gray-400">Em breve mais novidades.</div>;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Painel', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Histórico', icon: <ListChecks className="w-5 h-5" /> },
    { id: 'coach', label: 'Coach', icon: <MessageCircleCode className="w-5 h-5" /> },
    { id: 'guide', label: 'Guia', icon: <BookOpen className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen bg-rose-50/30 flex flex-col">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      {/* HEADER DESKTOP */}
      <header className="sticky top-0 z-50 bg-white/90 backdrop-blur-xl border-b border-rose-100 h-20">
        <div className="max-w-7xl mx-auto px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-10 h-10 bg-rose-600 rounded-xl flex items-center justify-center shadow-lg group-hover:rotate-6 transition-transform"><Heart className="w-6 h-6 text-white fill-white" /></div>
            <div>
              <h1 className="text-lg font-black text-rose-900 leading-none">LoveBridge</h1>
              <span className="text-[10px] font-bold text-rose-400 uppercase tracking-widest">Inteligência Afetiva</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-2">
            {navItems.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-5 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 transition-all ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-lg shadow-rose-200' : 'text-rose-900 hover:bg-rose-50'
                }`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </nav>
        </div>
      </header>

      {/* MAIN CONTENT AREA */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-6 pt-10 pb-32">
        {renderContent()}
      </main>

      {/* MOBILE BOTTOM NAVIGATION */}
      <div className="fixed bottom-6 left-0 right-0 px-6 lg:hidden z-50">
        <div className="bg-rose-900/95 backdrop-blur-md shadow-2xl rounded-[2.5rem] p-3 flex justify-around items-center border border-white/10">
             {navItems.map(item => (
               <button 
                 key={item.id}
                 onClick={() => setActiveTab(item.id as any)} 
                 className={`p-4 rounded-2xl transition-all relative ${activeTab === item.id ? 'bg-white text-rose-900 shadow-xl scale-110' : 'text-rose-300 hover:bg-white/10'}`}
               >
                 {item.icon}
                 {activeTab === item.id && <span className="absolute -top-1 left-1/2 -translate-x-1/2 w-1 h-1 bg-rose-900 rounded-full" />}
               </button>
             ))}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, BookOpen, Calendar, CheckCircle2, Trophy, 
  Clock, ListChecks, MessageCircleCode, BrainCircuit, ChevronRight, 
  Book, Info, UserPlus, History
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const getTrialDaysRemaining = () => {
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDaysInMs - (now - trialStart);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const completeMission = async (mission: Mission) => {
    setLoadingMission(true);
    try {
      const { feedback, impact } = await getMissionCompletionFeedback(mission, partner.name);
      const updatedMissions = partner.challenge.missions.map(m => 
        m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
      );

      const nextDay = mission.day + 1;
      if (nextDay <= (partner.challenge.type || 0)) {
        const nextData = await generateDailyMission(partner.language, nextDay);
        updatedMissions.push({
          id: Math.random().toString(36).substr(2, 9),
          day: nextDay,
          title: nextData.title || "Próxima Missão",
          description: nextData.description || "Continue sua jornada.",
          rationale: nextData.rationale || "O amor é construído dia a dia.",
          completed: false
        });
      }

      setAiInsight(feedback);
      setPartner(prev => ({
        ...prev,
        tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
        challenge: { ...prev.challenge, missions: updatedMissions }
      }));
    } finally {
      setLoadingMission(false);
    }
  };

  const renderMyChallenges = () => {
    const challenge = partner.challenge;
    if (!challenge.type) {
      return (
        <div className="max-w-4xl mx-auto py-12 text-center animate-in fade-in slide-in-from-bottom-4">
          <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
            <History className="w-16 h-16 text-rose-200 mx-auto mb-6" />
            <h2 className="text-3xl font-bold text-rose-900 mb-4">Seu Histórico de Amor</h2>
            <p className="text-gray-600 mb-8 max-w-md mx-auto">Você ainda não tem desafios ativos. Inicie uma jornada de 30 ou 60 dias para ver seu progresso aqui.</p>
            <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-bold shadow-lg hover:bg-rose-700 transition-all">Começar Agora</button>
          </div>
        </div>
      );
    }

    const completedMissions = challenge.missions.filter(m => m.completed).sort((a, b) => b.day - a.day);
    const progressPercent = Math.round((completedMissions.length / challenge.type) * 100);

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-rose-100 flex flex-col md:flex-row justify-between items-center gap-6">
          <div>
            <p className="text-xs font-bold text-rose-400 uppercase tracking-widest mb-1">Jornada Ativa</p>
            <h3 className="text-2xl font-black text-rose-900">{challenge.type} Dias de Intencionalidade</h3>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-2xl font-black text-rose-600 leading-none">{progressPercent}%</p>
              <p className="text-[10px] font-bold text-gray-400 uppercase">Concluído</p>
            </div>
            <div className="w-16 h-16 rounded-full border-4 border-rose-100 flex items-center justify-center relative">
               <div className="absolute inset-0 rounded-full border-4 border-rose-600" style={{ clipPath: `inset(${100 - progressPercent}% 0 0 0)` }}></div>
               <Trophy className="w-6 h-6 text-rose-600" />
            </div>
          </div>
        </div>

        <div className="space-y-6">
           <h3 className="text-xl font-bold text-rose-900 px-2 flex items-center gap-2"><ListChecks className="w-5 h-5 text-rose-500" /> Linha do Tempo</h3>
           <div className="grid gap-4">
             {challenge.missions.map(m => (
               <div key={m.id} className={`p-6 rounded-[2rem] border transition-all ${m.completed ? 'bg-green-50 border-green-100' : 'bg-white border-rose-50'}`}>
                 <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black ${m.completed ? 'bg-green-500 text-white' : 'bg-rose-50 text-rose-400'}`}>{m.day}</div>
                    <div className="flex-1">
                       <h4 className={`font-bold ${m.completed ? 'text-green-900' : 'text-rose-900'}`}>{m.title}</h4>
                       <p className="text-sm text-gray-500 line-clamp-1">{m.description}</p>
                    </div>
                    {m.completed ? (
                      <CheckCircle2 className="w-6 h-6 text-green-500" />
                    ) : (
                      <button onClick={() => setActiveTab('challenge')} className="text-xs font-bold text-rose-600 hover:underline">Fazer Missão</button>
                    )}
                 </div>
               </div>
             ))}
           </div>
        </div>
      </div>
    );
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'coach': return <PersonalCoach />;
      case 'myChallenges': return renderMyChallenges();
      case 'guide':
        return (
          <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
             <div className="text-center">
                <h2 className="text-4xl font-bold text-rose-900 mb-4">Guia das Linguagens</h2>
                <p className="text-gray-600">O segredo para um amor duradouro é falar a língua do outro.</p>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {Object.entries(LANGUAGE_METADATA).map(([lang, meta]) => (
                  lang !== LoveLanguage.NONE && (
                    <div key={lang} className={`p-8 rounded-[2.5rem] border shadow-sm transition-all hover:shadow-md ${meta.color}`}>
                      <div className="flex items-center gap-4 mb-4">
                        <div className="p-3 bg-white/50 rounded-2xl">{meta.icon}</div>
                        <h3 className="font-bold text-xl">{lang}</h3>
                      </div>
                      <p className="text-sm opacity-90 leading-relaxed mb-6">{meta.description}</p>
                    </div>
                  )
                ))}
             </div>
             <div className="bg-rose-900 p-10 rounded-[3rem] text-white text-center shadow-xl">
               <h3 className="text-2xl font-bold mb-4">Dúvidas sobre sua linguagem?</h3>
               <div className="flex flex-col sm:flex-row gap-4 justify-center">
                 <button onClick={() => setActiveTab('quiz')} className="px-8 py-3 bg-white text-rose-900 rounded-2xl font-black hover:bg-rose-50 transition-all">Refazer Meu Teste</button>
                 <button onClick={() => setActiveTab('partnerQuiz')} className="px-8 py-3 bg-rose-800 text-white rounded-2xl font-black hover:bg-rose-700 transition-all border border-rose-700">Teste do Parceiro</button>
               </div>
             </div>
          </div>
        );
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
                <Calendar className="w-16 h-16 text-rose-600 mx-auto mb-8" />
                <h2 className="text-4xl font-bold text-rose-900 mb-6">Iniciar Novo Desafio</h2>
                <p className="text-gray-600 text-lg mb-10 max-w-2xl mx-auto">Escolha por quanto tempo deseja se dedicar intensamente a preencher o tanque do seu parceiro.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-lg mx-auto">
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, 1); setPartner(p => ({ ...p, challenge: { type: 30, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-white border-2 border-rose-200 p-8 rounded-3xl hover:border-rose-500 hover:bg-rose-50 transition-all text-left">
                    <span className="block text-rose-600 font-bold text-2xl mb-2">30 Dias</span>
                    <span className="text-gray-500 text-sm italic">Ideal para reconexão imediata.</span>
                  </button>
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, 1); setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-rose-600 p-8 rounded-3xl hover:bg-rose-700 transition-all text-left shadow-lg text-white">
                    <span className="block font-bold text-2xl mb-2">60 Dias</span>
                    <span className="text-rose-100 text-sm italic">Foco em mudança de hábitos profundos.</span>
                  </button>
                </div>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12">
             {currentMission ? (
               <div className="space-y-6">
                  <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
                    <BrainCircuit className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-6"><div className="px-4 py-1 bg-rose-800 rounded-full text-xs font-bold uppercase tracking-widest text-rose-200">Missão Dia {currentMission.day}</div></div>
                      <h4 className="text-4xl font-bold mb-6 text-rose-50">{currentMission.title}</h4>
                      <p className="text-xl text-rose-100/90 leading-relaxed mb-10">"{currentMission.description}"</p>
                      <button onClick={() => completeMission(currentMission)} disabled={loadingMission} className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-3 shadow-xl">
                        {loadingMission ? "IA Avaliando..." : "Missão Cumprida!"}
                      </button>
                    </div>
                  </div>
                  {aiInsight && <div className="bg-amber-50 border-2 border-amber-200 p-6 rounded-3xl animate-in zoom-in duration-300"><div className="flex gap-4 items-start"><Sparkles className="w-6 h-6 text-amber-500 shrink-0" /><div><p className="font-bold text-amber-900 mb-1">Feedback da Mentora IA</p><p className="text-amber-800 italic leading-relaxed">{aiInsight}</p></div></div></div>}
               </div>
             ) : <div className="text-center py-20 bg-white rounded-[3rem] border border-rose-100"><Trophy className="w-16 h-16 text-yellow-500 mx-auto mb-4" /><h3 className="text-3xl font-bold text-rose-900">Parabéns!</h3><p className="text-gray-500">Missões de hoje concluídas. Volte amanhã!</p></div>}
          </div>
        );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in pb-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge label={`Seu Tanque Emocional`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
              <TankGauge label={`Tanque de ${partner.name} (IA)`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><Heart className="text-rose-500" /></div>
                    <div><p className="text-xs font-bold text-gray-400 uppercase">Sua Linguagem</p><p className="font-black text-rose-900">{user.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('quiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><UserPlus className="text-rose-500" /></div>
                    <div><p className="text-xs font-bold text-gray-400 uppercase">Linguagem de {partner.name}</p><p className="font-black text-rose-900">{partner.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('partnerQuiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
            </div>

            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 relative group overflow-hidden">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full group-hover:scale-150 transition-all duration-700" />
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shadow-inner"><MessageCircleCode className="w-8 h-8 text-indigo-100" /></div>
                <div><h3 className="text-2xl font-black mb-1">Personal Coach</h3><p className="text-indigo-200 text-sm">Apoio bíblico, psicológico e gestão de crise 24h.</p></div>
              </div>
              <button onClick={() => setActiveTab('coach')} className="px-8 py-4 bg-white text-indigo-900 rounded-2xl font-black text-sm hover:bg-indigo-50 transition-all z-10 shadow-lg">Pedir Ajuda</button>
            </div>

            {user.subscription.status === 'trial' && (
              <div className={`p-8 rounded-[2.5rem] text-white flex flex-col sm:flex-row justify-between items-center gap-4 transition-colors ${trialDays <= 2 ? 'bg-orange-600 animate-pulse' : 'bg-rose-900'}`}>
                <div><h4 className="font-bold text-lg">Teste Gratuito: {trialDays} dias restantes</h4><p className="text-xs opacity-80">Aproveite todas as ferramentas de IA para blindar seu amor.</p></div>
                <button onClick={() => setActiveTab('paywall')} className="px-6 py-3 bg-white text-rose-900 rounded-xl font-black text-sm shadow-lg">Ver Planos</button>
              </div>
            )}
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      default: return <div className="p-10 text-center text-gray-400">Em breve mais novidades.</div>;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Painel', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Histórico', icon: <ListChecks className="w-5 h-5" /> },
    { id: 'coach', label: 'Coach', icon: <MessageCircleCode className="w-5 h-5" /> },
    { id: 'guide', label: 'Guia', icon: <BookOpen className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen bg-rose-50/30 flex flex-col">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      {/* HEADER UNIFICADO NO TOPO */}
      <header className="sticky top-0 z-50 bg-white/90 backdrop-blur-xl border-b border-rose-100 flex flex-col shadow-sm">
        <div className="max-w-7xl w-full mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-8 h-8 bg-rose-600 rounded-lg flex items-center justify-center shadow-lg group-hover:rotate-6 transition-transform">
              <Heart className="w-5 h-5 text-white fill-white" />
            </div>
            <div>
              <h1 className="text-md font-black text-rose-900 leading-none">LoveBridge</h1>
              <span className="text-[8px] font-bold text-rose-400 uppercase tracking-widest hidden sm:block">Inteligência Afetiva</span>
            </div>
          </div>

          {/* NAVEGAÇÃO DESKTOP (Lado a Lado) */}
          <nav className="hidden lg:flex items-center gap-1">
            {navItems.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 transition-all ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-md' : 'text-rose-900 hover:bg-rose-50'
                }`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </nav>
        </div>

        {/* NAVEGAÇÃO MOBILE (Barra Inferior do Header) */}
        <nav className="lg:hidden flex items-center justify-around w-full border-t border-rose-50 bg-white/50 py-2">
          {navItems.map((item) => (
            <button 
              key={item.id}
              onClick={() => setActiveTab(item.id as any)} 
              className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all ${
                activeTab === item.id ? 'text-rose-600 bg-rose-50/50' : 'text-rose-300'
              }`}
            >
              {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
              <span className="text-[10px] font-bold">{item.label}</span>
            </button>
          ))}
        </nav>
      </header>

      {/* ÁREA DE CONTEÚDO PRINCIPAL */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-6 pt-8 pb-12">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { LoveLanguage, Mission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateDailyMission = async (targetLanguage: LoveLanguage, targetName: string, dayNumber: number): Promise<Partial<Mission>> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Gere uma missão prática para o dia ${dayNumber} de um desafio para o parceiro(a) "${targetName}" cuja linguagem do amor é "${targetLanguage}".`,
    config: {
      systemInstruction: `Você é um mentor de relacionamentos especialista no método de Gary Chapman. 
      Crie missões que sejam realizáveis em 24h e profundamente conectadas à linguagem especificada.
      O título deve ser curto e a descrição deve ser uma instrução clara.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          rationale: { type: Type.STRING }
        },
        required: ["title", "description", "rationale"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getMissionCompletionFeedback = async (
  mission: Mission, 
  partnerName: string, 
  userRelato: string
): Promise<{ feedback: string, impact: number, success: boolean }> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Missão Original: "${mission.title}" (${mission.description}).
    Relato do usuário sobre o que fez: "${userRelato}". 
    Analise se o relato condiz com a missão e se realmente demonstra um esforço de amor para ${partnerName}.`,
    config: {
      systemInstruction: `Analise o relato de cumprimento da missão. 
      Se o relato for muito vago, irrelevante ou indicar que a missão não foi feita, defina success como false.
      Se for um relato válido, defina success como true, retorne um feedback encorajador e um valor de impacto de 0.5 a 2.0.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          feedback: { type: Type.STRING, description: "Mensagem motivacional ou orientação pedagógica" },
          impact: { type: Type.NUMBER, description: "Valor do preenchimento do tanque (0 se falhar)" },
          success: { type: Type.BOOLEAN, description: "Se a missão foi validada como cumprida" }
        },
        required: ["feedback", "impact", "success"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getCoachAdvice = async (history: {role: string, parts: {text: string}[]}[], userMessage: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [...history, { role: 'user', parts: [{ text: userMessage }] }],
    config: {
      systemInstruction: `Você é o "Personal Coach" de felicidade conjugal.
      PERSONA:
      - Expertise profunda em Psicologia Comportamental e Relacional (Teoria do Apego, Gottman).
      - Sólidos conhecimentos em Teologia e Princípios Bíblicos de família e amor.
      - Especialista em Gestão de Crise (conflitos, infidelidade, luto, finanças).
      OBJETIVO:
      - Ajudar casais a alcançarem "Felicidade Múltipla" (espiritual, emocional, física e financeira).
      - Ser compassivo, mas firme em princípios que constroem lares sólidos.
      - Sempre fornecer um conselho prático ao final da resposta.`,
      temperature: 0.8,
      topP: 0.95,
    }
  });
  return response.text;
};

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, BookOpen, Calendar, CheckCircle2, Trophy, 
  Clock, ListChecks, MessageCircleCode, BrainCircuit, ChevronRight, 
  Book, Info, UserPlus, History, MessageSquareText, AlertCircle
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const getTrialDaysRemaining = () => {
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDaysInMs - (now - trialStart);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);

      if (success) {
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );

        const nextDay = mission.day + 1;
        if (nextDay <= (partner.challenge.type || 0)) {
          const nextData = await generateDailyMission(partner.language, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false
          });
        }

        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }

      setAiInsight({ feedback, success });
    } finally {
      setLoadingMission(false);
    }
  };

  const renderMyChallenges = () => {
    const challenge = partner.challenge;
    if (!challenge.type) {
      return (
        <div className="max-w-4xl mx-auto py-12 text-center animate-in fade-in slide-in-from-bottom-4">
          <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
            <History className="w-16 h-16 text-rose-200 mx-auto mb-6" />
            <h2 className="text-3xl font-bold text-rose-900 mb-4">Seu Histórico de Amor</h2>
            <p className="text-gray-600 mb-8 max-w-md mx-auto">Você ainda não tem desafios ativos. Inicie uma jornada de 30 ou 60 dias para ver seu progresso aqui.</p>
            <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-bold shadow-lg hover:bg-rose-700 transition-all">Começar Agora</button>
          </div>
        </div>
      );
    }

    const completedMissions = challenge.missions.filter(m => m.completed).sort((a, b) => b.day - a.day);
    const progressPercent = Math.round((completedMissions.length / challenge.type) * 100);

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-rose-100 flex flex-col md:flex-row justify-between items-center gap-6">
          <div>
            <p className="text-xs font-bold text-rose-400 uppercase tracking-widest mb-1">Jornada Ativa</p>
            <h3 className="text-2xl font-black text-rose-900">{challenge.type} Dias de Intencionalidade</h3>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-2xl font-black text-rose-600 leading-none">{progressPercent}%</p>
              <p className="text-[10px] font-bold text-gray-400 uppercase">Concluído</p>
            </div>
            <div className="w-16 h-16 rounded-full border-4 border-rose-100 flex items-center justify-center relative">
               <div className="absolute inset-0 rounded-full border-4 border-rose-600" style={{ clipPath: `inset(${100 - progressPercent}% 0 0 0)` }}></div>
               <Trophy className="w-6 h-6 text-rose-600" />
            </div>
          </div>
        </div>

        <div className="space-y-6">
           <h3 className="text-xl font-bold text-rose-900 px-2 flex items-center gap-2"><ListChecks className="w-5 h-5 text-rose-500" /> Linha do Tempo</h3>
           <div className="grid gap-4">
             {challenge.missions.map(m => (
               <div key={m.id} className={`p-6 rounded-[2rem] border transition-all ${m.completed ? 'bg-green-50 border-green-100' : 'bg-white border-rose-50'}`}>
                 <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black ${m.completed ? 'bg-green-500 text-white' : 'bg-rose-50 text-rose-400'}`}>{m.day}</div>
                    <div className="flex-1">
                       <h4 className={`font-bold ${m.completed ? 'text-green-900' : 'text-rose-900'}`}>{m.title}</h4>
                       <p className="text-sm text-gray-500 line-clamp-1">{m.description}</p>
                    </div>
                    {m.completed ? (
                      <CheckCircle2 className="w-6 h-6 text-green-500" />
                    ) : (
                      <button onClick={() => setActiveTab('challenge')} className="text-xs font-bold text-rose-600 hover:underline">Fazer Missão</button>
                    )}
                 </div>
               </div>
             ))}
           </div>
        </div>
      </div>
    );
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'coach': return <PersonalCoach />;
      case 'myChallenges': return renderMyChallenges();
      case 'guide':
        return (
          <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
             <div className="text-center">
                <h2 className="text-4xl font-bold text-rose-900 mb-4">Guia das Linguagens</h2>
                <p className="text-gray-600">O segredo para um amor duradouro é falar a língua do outro.</p>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {Object.entries(LANGUAGE_METADATA).map(([lang, meta]) => (
                  lang !== LoveLanguage.NONE && (
                    <div key={lang} className={`p-8 rounded-[2.5rem] border shadow-sm transition-all hover:shadow-md ${meta.color}`}>
                      <div className="flex items-center gap-4 mb-4">
                        <div className="p-3 bg-white/50 rounded-2xl">{meta.icon}</div>
                        <h3 className="font-bold text-xl">{lang}</h3>
                      </div>
                      <p className="text-sm opacity-90 leading-relaxed mb-6">{meta.description}</p>
                    </div>
                  )
                ))}
             </div>
             <div className="bg-rose-900 p-10 rounded-[3rem] text-white text-center shadow-xl">
               <h3 className="text-2xl font-bold mb-4">Dúvidas sobre sua linguagem?</h3>
               <div className="flex flex-col sm:flex-row gap-4 justify-center">
                 <button onClick={() => setActiveTab('quiz')} className="px-8 py-3 bg-white text-rose-900 rounded-2xl font-black hover:bg-rose-50 transition-all">Refazer Meu Teste</button>
                 <button onClick={() => setActiveTab('partnerQuiz')} className="px-8 py-3 bg-rose-800 text-white rounded-2xl font-black hover:bg-rose-700 transition-all border border-rose-700">Teste do Parceiro</button>
               </div>
             </div>
          </div>
        );
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
                <Calendar className="w-16 h-16 text-rose-600 mx-auto mb-8" />
                <h2 className="text-4xl font-bold text-rose-900 mb-6">Iniciar Novo Desafio</h2>
                <p className="text-gray-600 text-lg mb-10 max-w-2xl mx-auto">IA Mentora criará tarefas baseadas na linguagem de {partner.name}.</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-lg mx-auto">
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, partner.name, 1); setPartner(p => ({ ...p, challenge: { type: 30, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-white border-2 border-rose-200 p-8 rounded-3xl hover:border-rose-500 hover:bg-rose-50 transition-all text-left">
                    <span className="block text-rose-600 font-bold text-2xl mb-2">30 Dias</span>
                    <span className="text-gray-500 text-sm italic">Ideal para reconexão imediata.</span>
                  </button>
                  <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, partner.name, 1); setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="bg-rose-600 p-8 rounded-3xl hover:bg-rose-700 transition-all text-left shadow-lg text-white">
                    <span className="block font-bold text-2xl mb-2">60 Dias</span>
                    <span className="text-rose-100 text-sm italic">Foco em mudança de hábitos profundos.</span>
                  </button>
                </div>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12">
             {currentMission ? (
               <div className="space-y-6">
                  <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
                    <BrainCircuit className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-6"><div className="px-4 py-1 bg-rose-800 rounded-full text-xs font-bold uppercase tracking-widest text-rose-200">Missão Dia {currentMission.day}</div></div>
                      <h4 className="text-4xl font-bold mb-4 text-rose-50">{currentMission.title}</h4>
                      <p className="text-xl text-rose-100/90 leading-relaxed mb-10">"{currentMission.description}"</p>

                      <div className="space-y-4">
                        <label className="block text-sm font-bold text-rose-300 flex items-center gap-2">
                          <MessageSquareText className="w-4 h-4" /> Relate como você cumpriu esta missão:
                        </label>
                        <textarea 
                          value={fulfillmentText}
                          onChange={(e) => setFulfillmentText(e.target.value)}
                          placeholder="Ex: Preparei o café da manhã e levei na cama como sugerido..."
                          className="w-full bg-rose-800/50 border border-rose-700 rounded-2xl p-4 text-white placeholder-rose-400 focus:outline-none focus:border-white transition-all resize-none h-32"
                        />
                        <button 
                          onClick={() => completeMission(currentMission)} 
                          disabled={loadingMission || !fulfillmentText.trim()} 
                          className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 disabled:opacity-50 disabled:scale-100 transition-all flex items-center justify-center gap-3 shadow-xl"
                        >
                          {loadingMission ? "IA Validando Cumprimento..." : "Validar e Concluir Missão"}
                        </button>
                      </div>
                    </div>
                  </div>
                  {aiInsight && (
                    <div className={`border-2 p-6 rounded-3xl animate-in zoom-in duration-300 ${aiInsight.success ? 'bg-green-50 border-green-200' : 'bg-amber-50 border-amber-200'}`}>
                      <div className="flex gap-4 items-start">
                        {aiInsight.success ? <CheckCircle2 className="w-6 h-6 text-green-500 shrink-0" /> : <AlertCircle className="w-6 h-6 text-amber-500 shrink-0" />}
                        <div>
                          <p className={`font-bold mb-1 ${aiInsight.success ? 'text-green-900' : 'text-amber-900'}`}>
                            {aiInsight.success ? "Excelente Trabalho!" : "Orientações da IA"}
                          </p>
                          <p className={`${aiInsight.success ? 'text-green-800' : 'text-amber-800'} italic leading-relaxed`}>
                            {aiInsight.feedback}
                          </p>
                        </div>
                      </div>
                    </div>
                  )}
               </div>
             ) : <div className="text-center py-20 bg-white rounded-[3rem] border border-rose-100"><Trophy className="w-16 h-16 text-yellow-500 mx-auto mb-4" /><h3 className="text-3xl font-bold text-rose-900">Parabéns!</h3><p className="text-gray-500">Missões de hoje concluídas. Volte amanhã!</p></div>}
          </div>
        );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in pb-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge label={`Seu Tanque Emocional`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
              <TankGauge label={`Tanque de ${partner.name} (IA)`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><Heart className="text-rose-500" /></div>
                    <div><p className="text-xs font-bold text-gray-400 uppercase">Sua Linguagem</p><p className="font-black text-rose-900">{user.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('quiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><UserPlus className="text-rose-500" /></div>
                    <div><p className="text-xs font-bold text-gray-400 uppercase">Linguagem de {partner.name}</p><p className="font-black text-rose-900">{partner.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('partnerQuiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
            </div>

            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 relative group overflow-hidden">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full group-hover:scale-150 transition-all duration-700" />
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shadow-inner"><MessageCircleCode className="w-8 h-8 text-indigo-100" /></div>
                <div><h3 className="text-2xl font-black mb-1">Personal Coach</h3><p className="text-indigo-200 text-sm">Apoio bíblico, psicológico e gestão de crise 24h.</p></div>
