import { GoogleGenAI, Type } from "@google/genai";
import { LoveLanguage, Mission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateDailyMission = async (targetLanguage: LoveLanguage, targetName: string, dayNumber: number): Promise<Partial<Mission>> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Gere uma missão prática de "Amor Sacrificial" para o dia ${dayNumber} do desafio. O alvo é "${targetName}" e sua linguagem do amor predominante é "${targetLanguage}".`,
    config: {
      systemInstruction: `Você é um mentor de relacionamentos especialista no método de Gary Chapman e na filosofia do "Amor Sacrificial".
      SEU OBJETIVO: Criar tarefas que desafiem o usuário a colocar a felicidade de ${targetName} acima de seus próprios interesses momentâneos.

      REGRAS PARA A MISSÃO:
      1. ALINHAMENTO TOTAL: A tarefa deve ser um exemplo clássico e potente da linguagem "${targetLanguage}". Não misture linguagens.
      2. INTENCIONALIDADE: A missão deve exigir que o usuário pare o que está fazendo para servir, elogiar, presentear, tocar ou dedicar tempo de forma focada.
      3. PRATICIDADE: Deve ser realizável em 24h, mas ter um peso emocional significativo.

      ESTRUTURA:
      - title: Um nome inspirador e curto.
      - description: Instrução direta do que fazer.
      - rationale: Explicação de como esse ato específico de sacrifício preenche o tanque de quem tem a linguagem "${targetLanguage}".`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          rationale: { type: Type.STRING }
        },
        required: ["title", "description", "rationale"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getMissionCompletionFeedback = async (
  mission: Mission, 
  partnerName: string, 
  userRelato: string
): Promise<{ feedback: string, impact: number, success: boolean }> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Missão: "${mission.title}". 
    O que foi pedido: "${mission.description}".
    Relato do usuário: "${userRelato}". 
    Avalie se o usuário realmente se sacrificou para fazer ${partnerName} feliz.`,
    config: {
      systemInstruction: `Analise o relato de cumprimento sob a ótica do Amor Sacrificial.
      - Se o usuário fez apenas o "mínimo" ou foi vago, dê um feedback orientando como ser mais profundo e defina success como false.
      - Se o usuário demonstrou esforço real e foco na felicidade de ${partnerName}, defina success como true.
      - Retorne um feedback que valide a importância espiritual e emocional do ato praticado.
      - Impact: Atribua de 0.5 a 2.0 dependendo da profundidade do relato.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          feedback: { type: Type.STRING },
          impact: { type: Type.NUMBER },
          success: { type: Type.BOOLEAN }
        },
        required: ["feedback", "impact", "success"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getCoachAdvice = async (history: {role: string, parts: {text: string}[]}[], userMessage: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [...history, { role: 'user', parts: [{ text: userMessage }] }],
    config: {
      systemInstruction: `Você é o "Personal Coach" de felicidade conjugal.
      PERSONA:
      - Expertise em Psicologia Relacional e Sabedoria Bíblica sobre família.
      - Defensor do Amor Sacrificial (doação mútua e serviço).
      OBJETIVO:
      - Ajudar casais a restaurarem a conexão através da doação intencional.
      - Sempre fornecer um conselho prático focado em fazer o outro feliz.`,
      temperature: 0.8,
      topP: 0.95,
    }
  });
  return response.text;
};

