import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, BookOpen, Calendar, CheckCircle2, Trophy, 
  Clock, ListChecks, MessageCircleCode, BrainCircuit, ChevronRight, 
  Book, Info, UserPlus, History, MessageSquareText, AlertCircle, RotateCcw, Eye
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const getTrialDaysRemaining = () => {
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDaysInMs - (now - trialStart);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const redoMission = (missionId: string) => {
    const updatedMissions = partner.challenge.missions.map(m => 
      m.id === missionId ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
    );
    setPartner(prev => ({
      ...prev,
      challenge: { ...prev.challenge, missions: updatedMissions }
    }));
    setAiInsight(null);
    setFulfillmentText('');
    setActiveTab('challenge');
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);

      if (success) {
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );

        const isLastMissionInList = partner.challenge.missions[partner.challenge.missions.length - 1].id === mission.id;
        const nextDay = mission.day + 1;

        if (isLastMissionInList && nextDay <= (partner.challenge.type || 0)) {
          const nextData = await generateDailyMission(partner.language, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false
          });
        }

        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }

      setAiInsight({ feedback, success });
    } finally {
      setLoadingMission(false);
    }
  };

  const renderMyChallenges = () => {
    const challenge = partner.challenge;
    if (!challenge.type) {
      return (
        <div className="max-w-4xl mx-auto py-12 text-center animate-in fade-in slide-in-from-bottom-4">
          <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
            <History className="w-16 h-16 text-rose-200 mx-auto mb-6" />
            <h2 className="text-3xl font-bold text-rose-900 mb-4">Seu Histórico de Amor</h2>
            <p className="text-gray-600 mb-8 max-w-md mx-auto">Você ainda não tem desafios ativos. Inicie sua jornada de 60 dias para ver seu progresso aqui.</p>
            <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-bold shadow-lg hover:bg-rose-700 transition-all">Começar Agora</button>
          </div>
        </div>
      );
    }

    const completedMissions = challenge.missions.filter(m => m.completed).sort((a, b) => b.day - a.day);
    const progressPercent = Math.round((completedMissions.length / challenge.type) * 100);

    return (
      <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-rose-100 flex flex-col md:flex-row justify-between items-center gap-6">
          <div>
            <p className="text-xs font-bold text-rose-400 uppercase tracking-widest mb-1">Jornada Ativa</p>
            <h3 className="text-2xl font-black text-rose-900">{challenge.type} Dias de Intencionalidade</h3>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-2xl font-black text-rose-600 leading-none">{progressPercent}%</p>
              <p className="text-[10px] font-bold text-gray-400 uppercase">Concluído</p>
            </div>
            <div className="w-16 h-16 rounded-full border-4 border-rose-100 flex items-center justify-center relative">
               <div className="absolute inset-0 rounded-full border-4 border-rose-600" style={{ clipPath: `inset(${100 - progressPercent}% 0 0 0)` }}></div>
               <Trophy className="w-6 h-6 text-rose-600" />
            </div>
          </div>
        </div>

        <div className="space-y-6">
           <h3 className="text-xl font-bold text-rose-900 px-2 flex items-center gap-2"><ListChecks className="w-5 h-5 text-rose-500" /> Linha do Tempo</h3>
           <div className="grid gap-4">
             {challenge.missions.map(m => (
               <div key={m.id} className={`p-6 rounded-[2rem] border transition-all ${m.completed ? 'bg-green-50 border-green-100 shadow-sm' : 'bg-white border-rose-50'}`}>
                 <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black shrink-0 ${m.completed ? 'bg-green-500 text-white' : 'bg-rose-50 text-rose-400'}`}>{m.day}</div>
                    <div className="flex-1 min-w-0">
                       <h4 className={`font-bold truncate ${m.completed ? 'text-green-900' : 'text-rose-900'}`}>{m.title}</h4>
                       <p className="text-xs text-gray-500 line-clamp-1">{m.description}</p>
                    </div>
                    {m.completed ? (
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => redoMission(m.id)}
                          className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-green-200 text-green-600 rounded-xl text-[10px] font-black hover:bg-green-50 transition-all uppercase tracking-wider"
                          title="Fazer novamente esta tarefa"
                        >
                          <RotateCcw className="w-3 h-3" /> Refazer
                        </button>
                        <CheckCircle2 className="w-5 h-5 text-green-500" />
                      </div>
                    ) : (
                      <button onClick={() => setActiveTab('challenge')} className="text-xs font-bold text-rose-600 hover:underline px-2">Ver Missão</button>
                    )}
                 </div>
               </div>
             ))}
           </div>
        </div>
      </div>
    );
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'coach': return <PersonalCoach />;
      case 'myChallenges': return renderMyChallenges();
      case 'guide':
        return (
          <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
             <div className="text-center">
                <h2 className="text-4xl font-bold text-rose-900 mb-4 tracking-tight">Guia das Linguagens</h2>
                <p className="text-gray-600">O segredo para um amor duradouro é falar a língua do outro.</p>
             </div>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {Object.entries(LANGUAGE_METADATA).map(([lang, meta]) => (
                  lang !== LoveLanguage.NONE && (
                    <div key={lang} className={`p-8 rounded-[2.5rem] border shadow-sm transition-all hover:shadow-md ${meta.color}`}>
                      <div className="flex items-center gap-4 mb-4">
                        <div className="p-3 bg-white/50 rounded-2xl">{meta.icon}</div>
                        <h3 className="font-bold text-xl">{lang}</h3>
                      </div>
                      <p className="text-sm opacity-90 leading-relaxed mb-6">{meta.description}</p>
                    </div>
                  )
                ))}
             </div>
             <div className="bg-rose-900 p-10 rounded-[3rem] text-white text-center shadow-xl">
               <h3 className="text-2xl font-bold mb-4">Dúvidas sobre sua linguagem?</h3>
               <div className="flex flex-col sm:flex-row gap-4 justify-center">
                 <button onClick={() => setActiveTab('quiz')} className="px-8 py-3 bg-white text-rose-900 rounded-2xl font-black hover:bg-rose-50 transition-all">Refazer Meu Teste</button>
                 <button onClick={() => setActiveTab('partnerQuiz')} className="px-8 py-3 bg-rose-800 text-white rounded-2xl font-black hover:bg-rose-700 transition-all border border-rose-700">Teste do Parceiro</button>
               </div>
             </div>
          </div>
        );
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
                <Calendar className="w-16 h-16 text-rose-600 mx-auto mb-8" />
                <h2 className="text-4xl font-bold text-rose-900 mb-6 tracking-tight">Iniciar Desafios do 60 Dias</h2>
                <p className="text-gray-600 text-lg mb-10 max-w-2xl mx-auto">Nossa IA criará uma jornada de 60 dias de Amor Sacrificial baseada na linguagem de {partner.name}.</p>
                <div className="max-w-sm mx-auto">
                  <button 
                    onClick={async () => { 
                      setLoadingMission(true); 
                      const d = await generateDailyMission(partner.language, partner.name, 1); 
                      setPartner(p => ({ 
                        ...p, 
                        challenge: { 
                          type: 60, 
                          startDate: new Date().toISOString(), 
                          missions: [{ id: '1', day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] 
                        } 
                      })); 
                      setLoadingMission(false); 
                    }} 
                    className="w-full bg-rose-600 p-10 rounded-[2.5rem] hover:bg-rose-700 transition-all text-center shadow-xl shadow-rose-200 text-white group"
                  >
                    <span className="block font-black text-3xl mb-2 group-hover:scale-105 transition-transform uppercase tracking-tighter">Começar 60 Dias</span>
                    <span className="text-rose-100 text-sm italic">Foco total em mudança de hábitos profundos.</span>
                  </button>
                </div>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12">
             {currentMission ? (
               <div className="space-y-6">
                  <div className="bg-rose-900 text-white rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
                    <BrainCircuit className="absolute top-8 right-8 w-12 h-12 text-rose-700 opacity-30" />
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-6">
                        <div className="px-4 py-1 bg-rose-800 rounded-full text-[10px] font-black uppercase tracking-[0.2em] text-rose-200">
                          Missão Dia {currentMission.day}
                        </div>
                      </div>
                      <h4 className="text-4xl font-black mb-4 text-rose-50 leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-xl text-rose-100/90 leading-relaxed mb-10">"{currentMission.description}"</p>

                      <div className="space-y-4">
                        <label className="block text-sm font-bold text-rose-300 flex items-center gap-2">
                          <MessageSquareText className="w-4 h-4" /> Relate como você cumpriu esta missão:
                        </label>
                        <div className="relative group">
                          <textarea 
                            value={fulfillmentText}
                            onChange={(e) => setFulfillmentText(e.target.value)}
                            placeholder="Descreva aqui sua ação de amor..."
                            className="w-full bg-rose-950/40 border border-rose-700 rounded-2xl p-5 text-white text-lg placeholder-rose-500 focus:outline-none focus:border-white focus:ring-2 focus:ring-rose-500/20 transition-all resize-none h-40 font-medium"
                          />
                          {fulfillmentText && (
                            <div className="absolute top-2 right-4 px-3 py-1 bg-white/10 rounded-full flex items-center gap-1.5 animate-in fade-in zoom-in duration-200">
                               <Eye className="w-3 h-3 text-rose-300" />
                               <span className="text-[10px] font-bold text-rose-200 uppercase tracking-widest">Visualização Ativa</span>
                            </div>
                          )}
                        </div>

                        {/* ÁREA DE PRÉ-VISUALIZAÇÃO EM TEMPO REAL */}
                        {fulfillmentText && (
                          <div className="bg-white/5 border border-white/10 p-5 rounded-2xl animate-in slide-in-from-top-2 duration-300">
                            <p className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                              <Sparkles className="w-3 h-3" /> Espelhamento de Digitação
                            </p>
                            <p className="text-white text-sm italic opacity-90 leading-relaxed">
                              {fulfillmentText}
                            </p>
                          </div>
                        )}

                        <button 
                          onClick={() => completeMission(currentMission)} 
                          disabled={loadingMission || !fulfillmentText.trim()} 
                          className="w-full py-5 bg-white text-rose-900 rounded-2xl font-black text-lg hover:scale-[1.02] active:scale-95 disabled:opacity-50 disabled:scale-100 transition-all flex items-center justify-center gap-3 shadow-xl mt-4"
                        >
                          {loadingMission ? "IA Validando Cumprimento..." : "Validar e Concluir Missão"}
                        </button>
                      </div>
                    </div>
                  </div>
                  {aiInsight && (
                    <div className={`border-2 p-6 rounded-3xl animate-in zoom-in duration-300 ${aiInsight.success ? 'bg-green-50 border-green-200' : 'bg-amber-50 border-amber-200'}`}>
                      <div className="flex gap-4 items-start">
                        {aiInsight.success ? <CheckCircle2 className="w-6 h-6 text-green-500 shrink-0" /> : <AlertCircle className="w-6 h-6 text-amber-500 shrink-0" />}
                        <div>
                          <p className={`font-bold mb-1 ${aiInsight.success ? 'text-green-900' : 'text-amber-900'}`}>
                            {aiInsight.success ? "Excelente Trabalho!" : "Orientações da IA"}
                          </p>
                          <p className={`${aiInsight.success ? 'text-green-800' : 'text-amber-800'} italic leading-relaxed text-sm`}>
                            {aiInsight.feedback}
                          </p>
                        </div>
                      </div>
                    </div>
                  )}
               </div>
             ) : (
              <div className="text-center py-20 bg-white rounded-[3rem] border border-rose-100 px-6">
                <Trophy className="w-20 h-20 text-yellow-500 mx-auto mb-6 drop-shadow-lg" />
                <h3 className="text-3xl font-black text-rose-900 mb-2">Jornada Completa!</h3>
                <p className="text-gray-500 mb-8">Você concluiu todos os 60 dias da jornada de Amor Sacrificial.</p>
                <button onClick={() => setActiveTab('myChallenges')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-black hover:bg-rose-700 transition-all flex items-center gap-2 mx-auto">
                  <History className="w-5 h-5" /> Ver Histórico
                </button>
              </div>
             )}
          </div>
        );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in pb-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge label={`Seu Tanque Emocional`} level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} />
              <TankGauge label={`Tanque de ${partner.name} (IA)`} level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><Heart className="text-rose-500" /></div>
                    <div><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Sua Linguagem</p><p className="font-black text-rose-900">{user.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('quiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center"><UserPlus className="text-rose-500" /></div>
                    <div><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Linguagem de {partner.name}</p><p className="font-black text-rose-900">{partner.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('partnerQuiz')} className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100"><ChevronRight /></button>
               </div>
            </div>

            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 relative group overflow-hidden">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full group-hover:scale-150 transition-all duration-700" />
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shadow-inner"><MessageCircleCode className="w-8 h-8 text-indigo-100" /></div>
                <div><h3 className="text-2xl font-black mb-1 leading-tight">Personal Coach</h3><p className="text-indigo-200 text-sm">Apoio bíblico, psicológico e gestão de crise 24h.</p></div>
              </div>
              <button onClick={() => setActiveTab('coach')} className="px-8 py-4 bg-white text-indigo-900 rounded-2xl font-black text-sm hover:bg-indigo-50 transition-all z-10 shadow-lg">Pedir Ajuda</button>
            </div>

            {user.subscription.status === 'trial' && (
              <div className={`p-8 rounded-[3rem] text-white flex flex-col sm:flex-row justify-between items-center gap-4 transition-colors ${trialDays <= 2 ? 'bg-orange-600 animate-pulse' : 'bg-rose-900'}`}>
                <div><h4 className="font-bold text-lg">Teste Gratuito: {trialDays} dias restantes</h4><p className="text-xs opacity-80">Aproveite todas as ferramentas de IA para blindar seu amor.</p></div>
                <button onClick={() => setActiveTab('paywall')} className="px-6 py-3 bg-white text-rose-900 rounded-xl font-black text-sm shadow-lg">Ver Planos</button>
              </div>
            )}
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      default: return <div className="p-10 text-center text-gray-400">Em breve mais novidades.</div>;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Painel', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Histórico', icon: <ListChecks className="w-5 h-5" /> },
    { id: 'coach', label: 'Coach', icon: <MessageCircleCode className="w-5 h-5" /> },
    { id: 'guide', label: 'Guia', icon: <BookOpen className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen bg-rose-50/30 flex flex-col">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      <header className="sticky top-0 z-50 bg-white/95 backdrop-blur-xl border-b border-rose-100 flex flex-col shadow-sm">
        <div className="max-w-7xl w-full mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-9 h-9 bg-rose-600 rounded-xl flex items-center justify-center shadow-lg group-hover:rotate-6 transition-transform">
              <Heart className="w-5 h-5 text-white fill-white" />
            </div>
            <div>
              <h1 className="text-md font-black text-rose-900 leading-none">LoveBridge</h1>
              <span className="text-[8px] font-bold text-rose-400 uppercase tracking-widest hidden sm:block">Inteligência Afetiva</span>
            </div>
          </div>

          <nav className="hidden lg:flex items-center gap-1">
            {navItems.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-4 py-2 rounded-xl text-xs font-black flex items-center gap-2 transition-all ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-md' : 'text-rose-900 hover:bg-rose-50'
                }`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </nav>
        </div>

        <nav className="lg:hidden flex items-center justify-around w-full border-t border-rose-50 bg-white/50 py-2 px-2">
          {navItems.map((item) => (
            <button 
              key={item.id}
              onClick={() => setActiveTab(item.id as any)} 
              className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all flex-1 ${
                activeTab === item.id ? 'text-rose-600 bg-rose-50/50' : 'text-rose-300'
              }`}
            >
              {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
              <span className="text-[9px] font-black uppercase tracking-tighter">{item.label}</span>
            </button>
          ))}
        </nav>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-6 pt-8 pb-12">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

