import React, { useState, useEffect } from 'react';
import { LoveLanguage } from '../types';
import { QUIZ_QUESTIONS } from '../constants';
import { Check } from 'lucide-react';

interface QuizProps {
  onComplete: (result: LoveLanguage) => void;
}

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [scores, setScores] = useState<Record<LoveLanguage, number>>({
    [LoveLanguage.WORDS]: 0,
    [LoveLanguage.TIME]: 0,
    [LoveLanguage.GIFTS]: 0,
    [LoveLanguage.SERVICE]: 0,
    [LoveLanguage.TOUCH]: 0,
    [LoveLanguage.NONE]: 0,
  });

  const handleAnswer = (language: LoveLanguage, idx: number) => {
    if (selectedIdx !== null || isTransitioning) return;

    setSelectedIdx(idx);

    // Feedback visual imediato da escolha (snappy)
    setTimeout(() => {
      setIsTransitioning(true);

      const newScores = { ...scores, [language]: scores[language] + 1 };
      setScores(newScores);

      // Transição para o próximo estado
      setTimeout(() => {
        if (currentStep < QUIZ_QUESTIONS.length - 1) {
          setCurrentStep(currentStep + 1);
          setSelectedIdx(null);
          setIsTransitioning(false);
        } else {
          // Finaliza o quiz
          let maxLang = LoveLanguage.WORDS;
          let maxScore = -1;

          Object.entries(newScores).forEach(([lang, score]) => {
            const numericScore = score as number;
            if (numericScore > maxScore && lang !== LoveLanguage.NONE) {
              maxScore = numericScore;
              maxLang = lang as LoveLanguage;
            }
          });

          onComplete(maxLang);
        }
      }, 200); // Reduzido de 300ms para 200ms
    }, 250); // Reduzido de 400ms para 250ms para maior agilidade
  };

  const question = QUIZ_QUESTIONS[currentStep];
  const progress = ((currentStep + 1) / QUIZ_QUESTIONS.length) * 100;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-[2.5rem] shadow-2xl shadow-rose-100 overflow-hidden border border-rose-50">
      {/* Barra de Progresso */}
      <div className="h-2.5 bg-rose-50">
        <div 
          className="h-full bg-gradient-to-r from-rose-400 to-rose-600 transition-all duration-500 ease-out rounded-r-full" 
          style={{ width: `${progress}%` }} 
        />
      </div>

      <div className={`p-10 md:p-14 ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'} transition-all duration-200`}>
        <div className="flex justify-between items-center mb-10">
          <span className="px-4 py-1.5 bg-rose-50 text-rose-600 font-bold text-xs uppercase tracking-[0.2em] rounded-full">
            Questão {currentStep + 1} de {QUIZ_QUESTIONS.length}
          </span>
          <div className="flex gap-1.5">
            {QUIZ_QUESTIONS.map((_, i) => (
              <div 
                key={i} 
                className={`w-2.5 h-2.5 rounded-full transition-all duration-300 ${i <= currentStep ? 'bg-rose-400 scale-110' : 'bg-rose-100 scale-100'}`}
              />
            ))}
          </div>
        </div>

        <div key={currentStep} className="question-animate">
          <h2 className="text-3xl md:text-4xl font-black mb-10 text-rose-900 leading-[1.1] tracking-tight">
            {question.text}
          </h2>

          <div className="space-y-4">
            {question.options.map((opt, idx) => {
              const isSelected = selectedIdx === idx;
              const isOtherSelected = selectedIdx !== null && selectedIdx !== idx;

              return (
                <button
                  key={idx}
                  disabled={selectedIdx !== null}
                  onClick={() => handleAnswer(opt.language, idx)}
                  className={`
                    w-full p-6 text-left rounded-3xl border-2 transition-all duration-200 group relative
                    flex items-center justify-between overflow-hidden
                    ${isSelected 
                      ? 'border-rose-500 bg-rose-500 text-white scale-[1.02] shadow-xl shadow-rose-200 option-selected' 
                      : isOtherSelected
                        ? 'border-gray-50 bg-gray-50 opacity-40 grayscale'
                        : 'border-rose-100 bg-white hover:border-rose-300 hover:shadow-lg hover:-translate-y-0.5'
                    }
                  `}
                >
                  <span className={`text-xl font-semibold leading-snug pr-8 transition-colors duration-200 ${
                    isSelected ? 'text-white' : 'text-gray-700'
                  }`}>
                    {opt.text}
                  </span>

                  <div className={`
                    w-8 h-8 rounded-full border-2 shrink-0 flex items-center justify-center transition-all duration-200
                    ${isSelected 
                      ? 'bg-white border-white' 
                      : 'border-rose-200 bg-rose-50 group-hover:border-rose-400'
                    }
                  `}>
                    {isSelected && <Check className="w-5 h-5 text-rose-600 stroke-[4]" />}
                  </div>

                  {/* Efeito de brilho ao selecionar */}
                  {isSelected && (
                    <div className="absolute inset-0 bg-white/10 pointer-events-none animate-pulse" />
                  )}
                </button>
              );
            })}
          </div>
        </div>
      </div>

      <div className="px-10 pb-10 flex justify-center">
        <p className="text-gray-400 text-sm font-medium italic">
          Não há respostas certas, apenas o que faz sentido para o seu coração.
        </p>
      </div>
    </div>
  );
};

