import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, BookOpen, Calendar, CheckCircle2, Trophy, 
  Clock, ListChecks, MessageCircleCode, BrainCircuit, ChevronRight, 
  Book, Info, UserPlus, History, MessageSquareText, AlertCircle, RotateCcw, Eye, Link2, Unlink
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    const mockCode = Math.random().toString(36).substring(2, 8).toUpperCase();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false,
      coupleCode: mockCode, isLinked: false
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleLinkPartner = (code: string) => {
    if (code.length >= 4) {
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: partner.name }));
      setPartner(prev => ({ ...prev, isLinked: true }));
      setActiveTab('dashboard');
      alert("Sucesso! Contas vinculadas. Agora vocês compartilham o tanque emocional em tempo real.");
    }
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const getTrialDaysRemaining = () => {
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    const remaining = sevenDaysInMs - (now - trialStart);
    return Math.max(0, Math.ceil(remaining / (24 * 60 * 60 * 1000)));
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const redoMission = (missionId: string) => {
    const updatedMissions = partner.challenge.missions.map(m => 
      m.id === missionId ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
    );
    setPartner(prev => ({
      ...prev,
      challenge: { ...prev.challenge, missions: updatedMissions }
    }));
    setAiInsight(null);
    setFulfillmentText('');
    setActiveTab('challenge');
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);

      if (success) {
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );

        const isLastMissionInList = partner.challenge.missions[partner.challenge.missions.length - 1].id === mission.id;
        const nextDay = mission.day + 1;

        if (isLastMissionInList && nextDay <= (partner.challenge.type || 0)) {
          const nextData = await generateDailyMission(partner.language, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false
          });
        }

        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }

      setAiInsight({ feedback, success });
    } finally {
      setLoadingMission(false);
    }
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'connection': 
        return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      case 'coach': return <PersonalCoach />;
      case 'myChallenges': 
        const challengeList = partner.challenge;
        if (!challengeList.type) {
          return (
            <div className="max-w-4xl mx-auto py-12 text-center animate-in fade-in slide-in-from-bottom-4">
              <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-rose-100">
                <History className="w-16 h-16 text-rose-200 mx-auto mb-6" />
                <h2 className="text-3xl font-bold text-rose-900 mb-4">Seu Histórico de Amor</h2>
                <p className="text-gray-600 mb-8 max-w-md mx-auto">Você ainda não tem desafios ativos. Inicie sua jornada para ver seu progresso aqui.</p>
                <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-600 text-white rounded-2xl font-bold shadow-lg hover:bg-rose-700 transition-all">Começar Agora</button>
              </div>
            </div>
          );
        }
        const completedMissions = challengeList.missions.filter(m => m.completed).sort((a, b) => b.day - a.day);
        const progressPercent = Math.round((completedMissions.length / challengeList.type) * 100);
        return (
          <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in pb-12">
            <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-rose-100 flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <p className="text-xs font-bold text-rose-400 uppercase tracking-widest mb-1">Jornada de Blindagem</p>
                <h3 className="text-2xl font-black text-rose-900">{challengeList.type} Dias de Intencionalidade</h3>
              </div>
              <div className="flex items-center gap-4">
                <div className="text-right">
                  <p className="text-2xl font-black text-rose-600 leading-none">{progressPercent}%</p>
                  <p className="text-[10px] font-bold text-gray-400 uppercase">Progresso</p>
                </div>
                <div className="w-16 h-16 rounded-full border-4 border-rose-100 flex items-center justify-center relative">
                   <div className="absolute inset-0 rounded-full border-4 border-rose-600" style={{ clipPath: `inset(${100 - progressPercent}% 0 0 0)` }}></div>
                   <Trophy className="w-6 h-6 text-rose-600" />
                </div>
              </div>
            </div>
            <div className="space-y-6">
               <h3 className="text-xl font-bold text-rose-900 px-2 flex items-center gap-2"><ListChecks className="w-5 h-5 text-rose-500" /> Histórico de Missões</h3>
               <div className="grid gap-4">
                 {challengeList.missions.map(m => (
                   <div key={m.id} className={`p-6 rounded-[2rem] border transition-all ${m.completed ? 'bg-green-50 border-green-100 shadow-sm' : 'bg-white border-rose-50'}`}>
                     <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black shrink-0 ${m.completed ? 'bg-green-500 text-white' : 'bg-rose-50 text-rose-400'}`}>{m.day}</div>
                        <div className="flex-1 min-w-0">
                           <h4 className={`font-bold truncate ${m.completed ? 'text-green-900' : 'text-rose-900'}`}>{m.title}</h4>
                           <p className="text-xs text-gray-500 line-clamp-1">{m.description}</p>
                        </div>
                        {m.completed ? (
                          <div className="flex items-center gap-2">
                            <button onClick={() => redoMission(m.id)} className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-green-200 text-green-600 rounded-xl text-[10px] font-black hover:bg-green-50 transition-all uppercase tracking-wider"><RotateCcw className="w-3 h-3" /> Refazer</button>
                            <CheckCircle2 className="w-5 h-5 text-green-500" />
                          </div>
                        ) : (
                          <button onClick={() => setActiveTab('challenge')} className="text-xs font-bold text-rose-600 hover:underline px-2">Cumprir Agora</button>
                        )}
                     </div>
                   </div>
                 ))}
               </div>
            </div>
          </div>
        );
      case 'dashboard':
        const trialDays = getTrialDaysRemaining();
        return (
          <div className="space-y-10 animate-in fade-in pb-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm hover:shadow-md transition-all">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center shadow-inner"><Heart className="text-rose-500" /></div>
                    <div><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Sua Linguagem</p><p className="font-black text-rose-900">{user.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('quiz')} className="px-4 py-2 bg-rose-50 text-rose-600 rounded-xl text-xs font-bold hover:bg-rose-100 transition-all">Refazer</button>
               </div>
               <div className="bg-white p-6 rounded-[2.5rem] border border-rose-100 flex items-center justify-between shadow-sm hover:shadow-md transition-all">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-50 rounded-2xl flex items-center justify-center shadow-inner"><UserPlus className="text-rose-500" /></div>
                    <div><p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Linguagem dele(a)</p><p className="font-black text-rose-900">{partner.language}</p></div>
                  </div>
                  <button onClick={() => setActiveTab('partnerQuiz')} className="px-4 py-2 bg-rose-50 text-rose-600 rounded-xl text-xs font-bold hover:bg-rose-100 transition-all">Definir</button>
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <TankGauge 
                label="Meu Tanque Emocional" 
                type="self" 
                level={user.tankLevel} 
                onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} 
              />
              <div className="relative group">
                <TankGauge 
                  label={`Tanque de ${partner.name}`} 
                  type="partner" 
                  level={partner.tankLevel} 
                  onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} 
                />
                {!user.isLinked && (
                  <button onClick={() => setActiveTab('connection')} className="absolute top-4 right-4 flex items-center gap-1.5 px-3 py-1 bg-amber-50 text-amber-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100 hover:bg-amber-100 transition-all shadow-sm">
                    <Link2 className="w-3 h-3" /> Sincronizar
                  </button>
                )}
              </div>
            </div>

            {/* Resto do Dashboard... */}
            <div className="bg-white p-8 rounded-[3rem] border border-rose-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 bg-rose-600 rounded-2xl flex items-center justify-center shadow-lg shadow-rose-200"><Calendar className="w-7 h-7 text-white" /></div>
                <div><h3 className="text-2xl font-black text-rose-900 leading-tight">Jornada de Amor Sacrificial</h3>{partner.challenge.type ? (<p className="text-rose-500 font-bold text-sm">Missão {partner.challenge.missions.length} de {partner.challenge.type}</p>) : (<p className="text-gray-400 font-medium text-sm">Transforme sua relação hoje.</p>)}</div>
              </div>
              <button onClick={() => setActiveTab('challenge')} className="px-8 py-4 bg-rose-50 text-rose-600 rounded-2xl font-black text-sm hover:bg-rose-100 transition-all flex items-center gap-2">{partner.challenge.type ? 'Ver Missão do Dia' : 'Iniciar 60 Dias'}<ChevronRight className="w-4 h-4" /></button>
            </div>

            <div className="bg-indigo-900 text-white p-8 rounded-[3rem] shadow-xl flex flex-col md:flex-row items-center justify-between gap-6 relative group overflow-hidden">
              <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/5 rounded-full group-hover:scale-150 transition-all duration-700" />
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-indigo-700 rounded-2xl flex items-center justify-center shadow-inner"><MessageCircleCode className="w-8 h-8 text-indigo-100" /></div>
                <div><h3 className="text-2xl font-black mb-1 leading-tight">Mentor de Casal (IA)</h3><p className="text-indigo-200 text-sm">Respostas baseadas em psicologia e sabedoria bíblica.</p></div>
              </div>
              <button onClick={() => setActiveTab('coach')} className="px-8 py-4 bg-white text-indigo-900 rounded-2xl font-black text-sm hover:bg-indigo-50 transition-all z-10 shadow-lg">Pedir Ajuda Agora</button>
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'guide': return <div className="p-10 text-center text-gray-400 font-bold">Guia das linguagens em breve.</div>;
      default: return <div className="p-10 text-center text-gray-400">Página em desenvolvimento.</div>;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'connection', label: 'Vínculo', icon: <Link2 className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Mentor', icon: <MessageCircleCode className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Histórico', icon: <History className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen bg-rose-50/30 flex flex-col">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      <header className="sticky top-0 z-50 bg-white/95 backdrop-blur-xl border-b border-rose-100 flex flex-col shadow-sm">
        <div className="max-w-7xl w-full mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-9 h-9 bg-rose-600 rounded-xl flex items-center justify-center shadow-lg group-hover:rotate-6 transition-transform">
              <Heart className="w-5 h-5 text-white fill-white" />
            </div>
            <div>
              <h1 className="text-md font-black text-rose-900 leading-none uppercase tracking-tighter">DIALETO</h1>
              <span className="text-[8px] font-bold text-rose-400 uppercase tracking-widest hidden sm:block">Inteligência Conjugal</span>
            </div>
          </div>

          <nav className="hidden lg:flex items-center gap-1">
            {navItems.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-4 py-2 rounded-xl text-xs font-black flex items-center gap-2 transition-all ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-md' : 'text-rose-900 hover:bg-rose-50'
                }`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </nav>

          <div className="flex items-center gap-2">
            {user.isLinked && (
              <div className="flex items-center gap-2 px-3 py-1 bg-green-50 text-green-600 rounded-full border border-green-100">
                <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-widest">Sincronizado</span>
              </div>
            )}
          </div>
        </div>

        <nav className="lg:hidden flex items-center justify-around w-full border-t border-rose-50 bg-white/50 py-2 px-2">
          {navItems.map((item) => (
            <button 
              key={item.id}
              onClick={() => setActiveTab(item.id as any)} 
              className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all flex-1 ${
                activeTab === item.id ? 'text-rose-600 bg-rose-50/50' : 'text-rose-300'
              }`}
            >
              {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
              <span className="text-[9px] font-black uppercase tracking-tighter">{item.label}</span>
            </button>
          ))}
        </nav>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-6 pt-8 pb-12">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

