                <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, partner.name, 1); setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 text-white group"><span className="block font-black text-3xl mb-1 group-hover:scale-105 transition-transform uppercase tracking-tighter">Ativar Desafio</span><span className="text-rose-100 text-xs font-bold uppercase tracking-widest">IA Gerando Missões Personalizadas</span></button>
