        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl shadow-rose-200 group-hover:rotate-6 transition-transform">
              <Heart className="w-7 h-7 text-white fill-white" />
            </div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>

          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'
                }`}
              >
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>

          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">
        {renderContent()}
      </main>

      {/* Navegação Mobile Premium */}
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button 
            key={item.id}
            onClick={() => setActiveTab(item.id as any)} 
            className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${
              activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'
            }`}
          >
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message, TankTheme, GratitudeEntry } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import MyChallenges from './components/MyChallenges';
import GratitudeJournal from './components/GratitudeJournal';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, Calendar, CheckCircle2, Trophy, 
  BrainCircuit, ChevronRight, UserPlus, History, MessageSquareText, 
  Eye, Link2, Star, TrendingUp, Zap, Sun, Compass, RotateCcw, Clock3
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    const mockCode = Math.random().toString(36).substring(2, 8).toUpperCase();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false,
      coupleCode: mockCode, isLinked: false, tankTheme: TankTheme.MODERN, gratitudeJournal: []
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false, gratitudeJournal: []
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection' | 'gratitude'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean; impact?: number } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');
  const [showCelebration, setShowCelebration] = useState(false);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleLinkPartner = (code: string) => {
    if (code.length >= 4) {
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: partner.name }));
      setPartner(prev => ({ ...prev, isLinked: true }));
      setActiveTab('dashboard');
      alert("Sucesso! Contas vinculadas. Agora vocês compartilham o tanque emocional em tempo real.");
    }
  };

  const handleAddGratitude = (entry: Omit<GratitudeEntry, 'id' | 'date'>) => {
    const newEntry: GratitudeEntry = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString()
    };

    setUser(prev => ({
      ...prev,
      tankLevel: Math.min(10, parseFloat((prev.tankLevel + 0.2).toFixed(1))),
      gratitudeJournal: [...(prev.gratitudeJournal || []), newEntry]
    }));
  };

  const handleDeleteGratitude = (id: string) => {
    setUser(prev => ({
      ...prev,
      gratitudeJournal: (prev.gratitudeJournal || []).filter(e => e.id !== id)
    }));
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const redoMission = (missionId: string) => {
    const updatedMissions = partner.challenge.missions.map(m => 
      m.id === missionId ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
    );
    setPartner(prev => ({
      ...prev,
      challenge: { ...prev.challenge, missions: updatedMissions }
    }));
    setAiInsight(null);
    setFulfillmentText('');
    setShowCelebration(false);
    setActiveTab('challenge');
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);

      if (success) {
        setShowCelebration(true);
        // Remove a celebração após alguns segundos
        setTimeout(() => setShowCelebration(false), 4000);

        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );

        const isLastMissionInList = partner.challenge.missions[partner.challenge.missions.length - 1].id === mission.id;
        const nextDay = mission.day + 1;

        if (isLastMissionInList && nextDay <= (partner.challenge.type || 0)) {
          const nextData = await generateDailyMission(partner.language, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false
          });
        }

        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }

      setAiInsight({ feedback, success, impact });
    } finally {
      setLoadingMission(false);
    }
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection', 'gratitude'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'connection': 
        return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      case 'coach': return <PersonalCoach />;
      case 'gratitude':
        return <GratitudeJournal entries={user.gratitudeJournal || []} onAddEntry={handleAddGratitude} onDeleteEntry={handleDeleteGratitude} />;
      case 'myChallenges': 
        return (
          <MyChallenges 
            challenge={partner.challenge} 
            partnerName={partner.name}
            onRedoMission={redoMission}
            onGoToChallenge={() => setActiveTab('challenge')}
          />
        );
      case 'dashboard':
        return (
          <div className="space-y-12 animate-in fade-in pb-20">
            {/* Seção Hero: Missão em Destaque */}
            <section className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-rose-500 to-indigo-600 rounded-[3.5rem] blur opacity-10 group-hover:opacity-25 transition duration-1000 group-hover:duration-200"></div>
               <div className="relative glass-card p-10 md:p-14 rounded-[3.5rem] flex flex-col md:flex-row justify-between items-center gap-10">
                  <div className="flex-1 space-y-6">
                    <div className="inline-flex items-center gap-2 px-5 py-2 bg-rose-50 text-rose-600 rounded-full text-xs font-black uppercase tracking-[0.2em] border border-rose-100">
                      <Clock3 className="w-4 h-4" /> Micro-Ação do Dia
                    </div>
                    <h2 className="text-4xl md:text-5xl font-black text-rose-950 leading-tight">
                      Pronto para blindar seu amor <span className="text-rose-600 italic">hoje?</span>
                    </h2>
                    <p className="text-slate-500 text-lg max-w-lg font-medium">
                      Pequenos gestos de Amor Sacrificial feitos com intenção transformam o ambiente da sua casa.
                    </p>
                    <div className="flex flex-wrap gap-4 pt-4">
                      <button onClick={() => setActiveTab('challenge')} className="px-10 py-5 bg-rose-600 text-white rounded-[2rem] font-black text-lg hover:bg-rose-700 hover:scale-105 transition-all shadow-2xl shadow-rose-200 flex items-center gap-3">
                         {partner.challenge.type ? 'Abrir Missão' : 'Iniciar 60 Dias'} <ChevronRight className="w-5 h-5" />
                      </button>
                      <button onClick={() => setActiveTab('coach')} className="px-8 py-5 bg-white border border-rose-100 text-rose-900 rounded-[2rem] font-bold text-lg hover:bg-rose-50 transition-all flex items-center gap-3 shadow-sm">
                         Aconselhamento Pastoral <Compass className="w-5 h-5 text-rose-400" />
                      </button>
                    </div>
                  </div>
                  <div className="w-full md:w-1/3 flex justify-center">
                    <div className="w-48 h-48 bg-rose-50 rounded-[3rem] flex items-center justify-center relative animate-float">
                      <div className="absolute inset-0 bg-rose-500/5 rounded-full blur-2xl"></div>
                      <Calendar className="w-20 h-20 text-rose-500" />
                      {partner.challenge.missions.length > 0 && (
                        <div className="absolute -top-4 -right-4 bg-indigo-600 text-white l-14 h-14 rounded-full flex flex-col items-center justify-center font-black shadow-xl">
                          <span className="text-[10px] uppercase leading-none">Dia</span>
                          <span className="text-xl">{partner.challenge.missions.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
            </section>

            {/* Linguagens do Amor Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="glass-card p-8 rounded-[3rem] hover-lift flex items-center justify-between border-blue-50">
                  <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center shadow-inner"><Heart className="text-blue-500 w-8 h-8" /></div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Sua Linguagem</p>
                      <h4 className="text-xl font-black text-slate-900">{user.language}</h4>
                    </div>
                  </div>
                  <button onClick={() => setActiveTab('quiz')} className="p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-all shadow-sm"><RotateCcw size={20} /></button>
               </div>
               <div className="glass-card p-8 rounded-[3rem] hover-lift flex items-center justify-between border-rose-50">
                  <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-rose-50 rounded-2xl flex items-center justify-center shadow-inner"><UserPlus className="text-rose-500 w-8 h-8" /></div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Linguagem dele(a)</p>
                      <h4 className="text-xl font-black text-slate-900">{partner.language}</h4>
                    </div>
                  </div>
                  <button onClick={() => setActiveTab('partnerQuiz')} className="p-4 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100 transition-all shadow-sm"><Zap size={20} /></button>
               </div>
            </div>

            {/* Tanques Emocionais (Termômetros) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <TankGauge 
                label="Termômetro Diário" 
                type="self" 
                level={user.tankLevel} 
                onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} 
                theme={user.tankTheme || TankTheme.MODERN}
                onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))}
              />
              <div className="relative group">
                <TankGauge 
                  label={`Termômetro do Parceiro`} 
                  type="partner" 
                  level={partner.tankLevel} 
                  onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} 
                  theme={user.tankTheme || TankTheme.MODERN}
                  onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))}
                />
                {!user.isLinked && (
                  <button onClick={() => setActiveTab('connection')} className="absolute top-6 right-6 flex items-center gap-1.5 px-4 py-2 bg-amber-100 text-amber-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-200 hover:bg-amber-600 hover:text-white transition-all shadow-lg shadow-amber-200/20">
                    <Link2 className="w-3.5 h-3.5" /> Vincular agora
                  </button>
                )}
              </div>
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="glass-card p-12 md:p-20 rounded-[4rem] shadow-xl border border-rose-100">
                <div className="w-24 h-24 bg-rose-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10"><Calendar className="w-12 h-12 text-rose-600" /></div>
                <h2 className="text-5xl font-black text-rose-950 mb-8 tracking-tight">Comece a Semear</h2>
                <p className="text-slate-500 text-xl mb-12 max-w-2xl mx-auto font-medium">60 dias de Amor Sacrificial transformarão seu casamento em algo duradouro e prazeroso.</p>
                <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, partner.name, 1); setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 text-white group"><span className="block font-black text-3xl mb-1 group-hover:scale-105 transition-transform uppercase tracking-tighter">Ativar Desafio</span><span className="text-rose-100 text-xs font-bold uppercase tracking-widest">Conselho Pastoral do Dia</span></button>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12 relative">
             {/* Efeito de Celebração Sutil */}
             {showCelebration && [...Array(15)].map((_, i) => (
                <div 
                  key={i} 
                  className="floating-heart text-rose-500 opacity-0" 
                  style={{ 
                    left: `${Math.random() * 80 + 10}%`, 
                    top: '80%',
                    animationDelay: `${Math.random() * 0.8}s`,
                    fontSize: `${Math.random() * 20 + 10}px`
                  }}
                >
                  <Heart className="fill-current" />
                </div>
             ))}

             {currentMission ? (
               <div className="space-y-6">
                  {aiInsight?.success && (
                    <div className="bg-emerald-600 text-white p-10 rounded-[3.5rem] shadow-2xl animate-success-pop flex flex-col md:flex-row items-center gap-8 border-4 border-white">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shrink-0 shadow-lg rotate-6"><Trophy className="w-12 h-12 text-emerald-600" /></div>
                      <div className="flex-1 text-center md:text-left">
                        <div className="flex items-center justify-center md:justify-start gap-3 mb-2">
                          <span className="px-4 py-1.5 bg-emerald-700 rounded-full text-[10px] font-black uppercase tracking-widest">Missão Lendária</span>
                          <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-100"><TrendingUp className="w-4 h-4" /> Impacto: +{aiInsight.impact}</div>
                        </div>
                        <h4 className="text-3xl font-black mb-3">Vitória no Relacionamento!</h4>
                        <p className="text-emerald-50 text-lg leading-relaxed font-medium">"{aiInsight.feedback}"</p>
                      </div>
                    </div>
                  )}

                  <div className="bg-slate-950 text-white rounded-[3.5rem] p-10 md:p-16 shadow-2xl relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-rose-600/10 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
                    <BrainCircuit className="absolute bottom-10 right-10 w-24 h-24 text-white/5 group-hover:rotate-12 transition-transform duration-700" />

                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-10">
                        <div className="px-5 py-2 bg-white/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-rose-400 backdrop-blur-sm">Dia {currentMission.day} • {partner.language}</div>
                        <div className="px-5 py-2 bg-emerald-500/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-emerald-400 backdrop-blur-sm flex items-center gap-2">
                          <Clock3 className="w-3 h-3" /> Simples & Eficaz
                        </div>
                      </div>
                      <h4 className="text-5xl font-black mb-8 text-white leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-2xl text-slate-300 leading-relaxed mb-12 font-medium">"{currentMission.description}"</p>

                      <div className="bg-white/5 border border-white/10 p-6 rounded-2xl mb-12">
                         <h5 className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                           <Sparkles className="w-3 h-3" /> Por que isso importa?
                         </h5>
                         <p className="text-slate-400 text-sm italic font-medium">"{currentMission.rationale}"</p>
                      </div>

                      {!aiInsight?.success && (
                        <div className="space-y-6">
                          <div className="flex items-center justify-between">
                             <label className="text-xs font-black text-rose-400 uppercase tracking-widest flex items-center gap-2"><MessageSquareText className="w-4 h-4" /> Como foi sua experiência?</label>
                             {fulfillmentText && (<div className="flex items-center gap-2 animate-in fade-in"><div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" /><span className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">Análise de IA Pronta</span></div>)}
                          </div>
                          <textarea 
                            value={fulfillmentText} 
                            onChange={(e) => setFulfillmentText(e.target.value)} 
                            placeholder="Descreva brevemente como foi realizar essa micro-missão..." 
                            className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-8 text-white text-xl placeholder-white/20 focus:outline-none focus:border-rose-500 focus:ring-4 focus:ring-rose-500/10 transition-all resize-none h-48 font-medium" 
                          />
                          <button 
                            onClick={() => completeMission(currentMission)} 
                            disabled={loadingMission || !fulfillmentText.trim()} 
                            className="w-full py-6 bg-rose-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-rose-700 active:scale-95 disabled:opacity-30 transition-all flex items-center justify-center gap-4 shadow-2xl shadow-rose-950"
                          >
                            {loadingMission ? (
                              <><div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" /> Analisando impacto...</>
                            ) : (
                              <>Validar Missão <Star className="w-6 h-6 fill-current" /></>
                            )}
                          </button>
                        </div>
                      )}

                      {aiInsight?.success && (
                        <div className="mt-12 flex justify-center">
                          <button onClick={() => { setAiInsight(null); setShowCelebration(false); }} className="px-10 py-5 bg-white text-slate-900 rounded-[2rem] font-black text-lg hover:bg-slate-100 transition-all shadow-xl">Continuar Jornada</button>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
             ) : (
               <div className="glass-card p-16 rounded-[4rem] text-center border border-rose-100 shadow-sm animate-in zoom-in-95">
                 <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10 shadow-inner"><CheckCircle2 className="w-12 h-12 text-emerald-500" /></div>
                 <h3 className="text-4xl font-black text-slate-900 mb-4">Meta Diária Atingida!</h3>
                 <p className="text-slate-500 text-xl mb-12 max-w-md mx-auto font-medium">Você acaba de depositar amor no banco emocional do seu parceiro(a). O amanhã reserva uma nova oportunidade.</p>
                 <div className="flex flex-col sm:flex-row gap-5 justify-center">
                    <button onClick={() => setActiveTab('myChallenges')} className="px-10 py-5 bg-indigo-600 text-white rounded-[2rem] font-black hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200">Ver Histórico</button>
                    <button onClick={() => setActiveTab('dashboard')} className="px-10 py-5 bg-white border border-rose-100 text-rose-600 rounded-[2rem] font-black hover:bg-rose-50 transition-all">Página Inicial</button>
                 </div>
               </div>
             )}
          </div>
        );
      default: return <div className="p-20 text-center font-bold text-rose-300 text-3xl">Página sendo polida pela nossa equipe...</div>;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sun className="w-5 h-5" /> },
    { id: 'gratitude', label: 'Diário', icon: <Heart className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Mentor', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Evolução', icon: <TrendingUp className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      <header className="sticky top-0 z-[60] bg-white/70 backdrop-blur-2xl border-b border-rose-100/50 h-20 flex items-center">
        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl shadow-rose-200 group-hover:rotate-6 transition-transform">
              <Heart className="w-7 h-7 text-white fill-white" />
            </div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>

          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'
                }`}
              >
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>

          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">
        {renderContent()}
      </main>

      {/* Navegação Mobile Premium */}
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button 
            key={item.id}
            onClick={() => setActiveTab(item.id as any)} 
            className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${
              activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'
            }`}
          >
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message, TankTheme, GratitudeEntry } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import MyChallenges from './components/MyChallenges';
import GratitudeJournal from './components/GratitudeJournal';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, Calendar, CheckCircle2, Trophy, 
  BrainCircuit, ChevronRight, UserPlus, History, MessageSquareText, 
  Eye, Link2, Star, TrendingUp, Zap, Sun, Compass, RotateCcw, Clock3
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [] };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return {
      status: 'trial',
      plan: 'none',
      trialStartedAt: new Date().toISOString(),
      expiresAt: null
    };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    const initialSub = getInitialSubscription();
    const mockCode = Math.random().toString(36).substring(2, 8).toUpperCase();
    return saved ? JSON.parse(saved) : { 
      name: '', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: initialSub, notificationsEnabled: false,
      coupleCode: mockCode, isLinked: false, tankTheme: TankTheme.MODERN, gratitudeJournal: []
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', language: LoveLanguage.NONE, tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false, gratitudeJournal: []
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection' | 'gratitude'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean; impact?: number } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');
  const [showCelebration, setShowCelebration] = useState(false);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleLinkPartner = (code: string) => {
    if (code.length >= 4) {
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: partner.name }));
      setPartner(prev => ({ ...prev, isLinked: true }));
      setActiveTab('dashboard');
      alert("Sucesso! Contas vinculadas. Agora vocês compartilham o tanque emocional em tempo real.");
    }
  };

  const handleAddGratitude = (entry: Omit<GratitudeEntry, 'id' | 'date'>) => {
    const newEntry: GratitudeEntry = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString()
    };

    setUser(prev => ({
      ...prev,
      tankLevel: Math.min(10, parseFloat((prev.tankLevel + 0.2).toFixed(1))),
      gratitudeJournal: [...(prev.gratitudeJournal || []), newEntry]
    }));
  };

  const handleDeleteGratitude = (id: string) => {
    setUser(prev => ({
      ...prev,
      gratitudeJournal: (prev.gratitudeJournal || []).filter(e => e.id !== id)
    }));
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    const trialStart = new Date(user.subscription.trialStartedAt).getTime();
    const now = new Date().getTime();
    const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
    return (now - trialStart) <= sevenDaysInMs;
  };

  const handleSubscribe = (planId: string) => {
    setUser(prev => ({
      ...prev,
      subscription: { ...prev.subscription, status: 'active', plan: planId as any }
    }));
    setActiveTab('dashboard');
  };

  const redoMission = (missionId: string) => {
    const updatedMissions = partner.challenge.missions.map(m => 
      m.id === missionId ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
    );
    setPartner(prev => ({
      ...prev,
      challenge: { ...prev.challenge, missions: updatedMissions }
    }));
    setAiInsight(null);
    setFulfillmentText('');
    setShowCelebration(false);
    setActiveTab('challenge');
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);

      if (success) {
        setShowCelebration(true);
        // Remove a celebração após alguns segundos
        setTimeout(() => setShowCelebration(false), 4000);

        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );

        const isLastMissionInList = partner.challenge.missions[partner.challenge.missions.length - 1].id === mission.id;
        const nextDay = mission.day + 1;

        if (isLastMissionInList && nextDay <= (partner.challenge.type || 0)) {
          const nextData = await generateDailyMission(partner.language, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false
          });
        }

        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }

      setAiInsight({ feedback, success, impact });
    } finally {
      setLoadingMission(false);
    }
  };

  const renderContent = () => {
    const hasAccess = checkAccess();

    if (!hasAccess && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection', 'gratitude'].includes(activeTab)) {
      return <Paywall onSubscribe={handleSubscribe} isExpired={true} />;
    }

    if (activeTab === 'paywall') return <Paywall onSubscribe={handleSubscribe} isExpired={!hasAccess} />;

    switch (activeTab) {
      case 'connection': 
        return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      case 'coach': return <PersonalCoach />;
      case 'gratitude':
        return <GratitudeJournal entries={user.gratitudeJournal || []} onAddEntry={handleAddGratitude} onDeleteEntry={handleDeleteGratitude} />;
      case 'myChallenges': 
        return (
          <MyChallenges 
            challenge={partner.challenge} 
            partnerName={partner.name}
            onRedoMission={redoMission}
            onGoToChallenge={() => setActiveTab('challenge')}
          />
        );
      case 'dashboard':
        return (
          <div className="space-y-12 animate-in fade-in pb-20">
            {/* Seção Hero: Missão em Destaque */}
            <section className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-rose-500 to-indigo-600 rounded-[3.5rem] blur opacity-10 group-hover:opacity-25 transition duration-1000 group-hover:duration-200"></div>
               <div className="relative glass-card p-10 md:p-14 rounded-[3.5rem] flex flex-col md:flex-row justify-between items-center gap-10">
                  <div className="flex-1 space-y-6">
                    <div className="inline-flex items-center gap-2 px-5 py-2 bg-rose-50 text-rose-600 rounded-full text-xs font-black uppercase tracking-[0.2em] border border-rose-100">
                      <Clock3 className="w-4 h-4" /> Micro-Ação do Dia
                    </div>
                    <h2 className="text-4xl md:text-5xl font-black text-rose-950 leading-tight">
                      Pronto para blindar seu amor <span className="text-rose-600 italic">hoje?</span>
                    </h2>
                    <p className="text-slate-500 text-lg max-w-lg font-medium">
                      Pequenos gestos de Amor Sacrificial feitos com intenção transformam o ambiente da sua casa.
                    </p>
                    <div className="flex flex-wrap gap-4 pt-4">
                      <button onClick={() => setActiveTab('challenge')} className="px-10 py-5 bg-rose-600 text-white rounded-[2rem] font-black text-lg hover:bg-rose-700 hover:scale-105 transition-all shadow-2xl shadow-rose-200 flex items-center gap-3">
                         {partner.challenge.type ? 'Abrir Missão' : 'Iniciar 60 Dias'} <ChevronRight className="w-5 h-5" />
                      </button>
                      <button onClick={() => setActiveTab('coach')} className="px-8 py-5 bg-white border border-rose-100 text-rose-900 rounded-[2rem] font-bold text-lg hover:bg-rose-50 transition-all flex items-center gap-3 shadow-sm">
                         Aconselhamento Pastoral <Compass className="w-5 h-5 text-rose-400" />
                      </button>
                    </div>
                  </div>
                  <div className="w-full md:w-1/3 flex justify-center">
                    <div className="w-48 h-48 bg-rose-50 rounded-[3rem] flex items-center justify-center relative animate-float">
                      <div className="absolute inset-0 bg-rose-500/5 rounded-full blur-2xl"></div>
                      <Calendar className="w-20 h-20 text-rose-500" />
                      {partner.challenge.missions.length > 0 && (
                        <div className="absolute -top-4 -right-4 bg-indigo-600 text-white w-14 h-14 rounded-full flex flex-col items-center justify-center font-black shadow-xl">
                          <span className="text-[10px] uppercase leading-none">Dia</span>
                          <span className="text-xl">{partner.challenge.missions.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
            </section>

            {/* Linguagens do Amor Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="glass-card p-8 rounded-[3rem] hover-lift flex items-center justify-between border-blue-50">
                  <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center shadow-inner"><Heart className="text-blue-500 w-8 h-8" /></div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Sua Linguagem</p>
                      <h4 className="text-xl font-black text-slate-900">{user.language}</h4>
                    </div>
                  </div>
                  <button onClick={() => setActiveTab('quiz')} className="p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 transition-all shadow-sm"><RotateCcw size={20} /></button>
               </div>
               <div className="glass-card p-8 rounded-[3rem] hover-lift flex items-center justify-between border-rose-50">
                  <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-rose-50 rounded-2xl flex items-center justify-center shadow-inner"><UserPlus className="text-rose-500 w-8 h-8" /></div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Linguagem dele(a)</p>
                      <h4 className="text-xl font-black text-slate-900">{partner.language}</h4>
                    </div>
                  </div>
                  <button onClick={() => setActiveTab('partnerQuiz')} className="p-4 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-100 transition-all shadow-sm"><Zap size={20} /></button>
               </div>
            </div>

            {/* Tanques Emocionais (Termômetros) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <TankGauge 
                label="Termômetro Diário" 
                type="self" 
                level={user.tankLevel} 
                onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} 
                theme={user.tankTheme || TankTheme.MODERN}
                onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))}
              />
              <div className="relative group">
                <TankGauge 
                  label={`Termômetro do Parceiro`} 
                  type="partner" 
                  level={partner.tankLevel} 
                  onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} 
                  theme={user.tankTheme || TankTheme.MODERN}
                  onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))}
                />
                {!user.isLinked && (
                  <button onClick={() => setActiveTab('connection')} className="absolute top-6 right-6 flex items-center gap-1.5 px-4 py-2 bg-amber-100 text-amber-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-200 hover:bg-amber-600 hover:text-white transition-all shadow-lg shadow-amber-200/20">
                    <Link2 className="w-3.5 h-3.5" /> Vincular agora
                  </button>
                )}
              </div>
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, language: res })); setActiveTab('dashboard'); }} />;
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="glass-card p-12 md:p-20 rounded-[4rem] shadow-xl border border-rose-100">
                <div className="w-24 h-24 bg-rose-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10"><Calendar className="w-12 h-12 text-rose-600" /></div>
                <h2 className="text-5xl font-black text-rose-950 mb-8 tracking-tight">Comece a Semear</h2>
                <p className="text-slate-500 text-xl mb-12 max-w-2xl mx-auto font-medium">60 dias de Amor Sacrificial transformarão seu casamento em algo duradouro e prazeroso.</p>
                <button onClick={async () => { setLoadingMission(true); const d = await generateDailyMission(partner.language, partner.name, 1); setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false }] } })); setLoadingMission(false); }} className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 text-white group"><span className="block font-black text-3xl mb-1 group-hover:scale-105 transition-transform uppercase tracking-tighter">Ativar Desafio</span><span className="text-rose-100 text-xs font-bold uppercase tracking-widest">Conselho Pastoral do Dia</span></button>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12 relative">
             {/* Efeito de Celebração Sutil */}
             {showCelebration && [...Array(15)].map((_, i) => (
                <div 
                  key={i} 
                  className="floating-heart text-rose-500 opacity-0" 
                  style={{ 
                    left: `${Math.random() * 80 + 10}%`, 
                    top: '80%',
                    animationDelay: `${Math.random() * 0.8}s`,
                    fontSize: `${Math.random() * 20 + 10}px`
                  }}
                >
                  <Heart className="fill-current" />
                </div>
             ))}

             {currentMission ? (
               <div className="space-y-6">
                  {aiInsight?.success && (
                    <div className="bg-emerald-600 text-white p-10 rounded-[3.5rem] shadow-2xl animate-success-pop flex flex-col md:flex-row items-center gap-8 border-4 border-white">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shrink-0 shadow-lg rotate-6"><Trophy className="w-12 h-12 text-emerald-600" /></div>
                      <div className="flex-1 text-center md:text-left">
                        <div className="flex items-center justify-center md:justify-start gap-3 mb-2">
                          <span className="px-4 py-1.5 bg-emerald-700 rounded-full text-[10px] font-black uppercase tracking-widest">Missão Lendária</span>
                          <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-100"><TrendingUp className="w-4 h-4" /> Impacto: +{aiInsight.impact}</div>
                        </div>
                        <h4 className="text-3xl font-black mb-3">Vitória no Relacionamento!</h4>
                        <p className="text-emerald-50 text-lg leading-relaxed font-medium">"{aiInsight.feedback}"</p>
                      </div>
                    </div>
                  )}

                  <div className="bg-slate-950 text-white rounded-[3.5rem] p-10 md:p-16 shadow-2xl relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-rose-600/10 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
                    <BrainCircuit className="absolute bottom-10 right-10 w-24 h-24 text-white/5 group-hover:rotate-12 transition-transform duration-700" />

                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-10">
                        <div className="px-5 py-2 bg-white/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-rose-400 backdrop-blur-sm">Dia {currentMission.day} • {partner.language}</div>
                        <div className="px-5 py-2 bg-emerald-500/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-emerald-400 backdrop-blur-sm flex items-center gap-2">
                          <Clock3 className="w-3 h-3" /> Simples & Eficaz
                        </div>
                      </div>
                      <h4 className="text-5xl font-black mb-8 text-white leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-2xl text-slate-300 leading-relaxed mb-12 font-medium">"{currentMission.description}"</p>

                      <div className="bg-white/5 border border-white/10 p-6 rounded-2xl mb-12">
                         <h5 className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                           <Sparkles className="w-3 h-3" /> Por que isso importa?
                         </h5>
                         <p className="text-slate-400 text-sm italic font-medium">"{currentMission.rationale}"</p>
                      </div>

                      {!aiInsight?.success && (
                        <div className="space-y-6">
                          <div className="flex items-center justify-between">
                             <label className="text-xs font-black text-rose-400 uppercase tracking-widest flex items-center gap-2"><MessageSquareText className="w-4 h-4" /> Como foi sua experiência?</label>
                             {fulfillmentText && (<div className="flex items-center gap-2 animate-in fade-in"><div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" /><span className="text-[10px] font-bold text-emerald-400 uppercase tracking-widest">Análise de IA Pronta</span></div>)}
                          </div>
                          <textarea 
                            value={fulfillmentText} 
                            onChange={(e) => setFulfillmentText(e.target.value)} 
                            placeholder="Descreva brevemente como foi realizar essa micro-missão..." 
                            className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-8 text-white text-xl placeholder-white/20 focus:outline-none focus:border-rose-500 focus:ring-4 focus:ring-rose-500/10 transition-all resize-none h-48 font-medium" 
                          />
                          <button 
                            onClick={() => completeMission(currentMission)} 
                            disabled={loadingMission || !fulfillmentText.trim()} 
                            className="w-full py-6 bg-rose-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-rose-700 active:scale-95 disabled:opacity-30 transition-all flex items-center justify-center gap-4 shadow-2xl shadow-rose-950"
                          >
                            {loadingMission ? (
                              <><div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" /> Analisando impacto...</>
                            ) : (
                              <>Validar Missão <Star className="w-6 h-6 fill-current" /></>
                            )}
                          </button>
                        </div>
                      )}

                      {aiInsight?.success && (
                        <div className="mt-12 flex justify-center">
                          <button onClick={() => { setAiInsight(null); setShowCelebration(false); }} className="px-10 py-5 bg-white text-slate-900 rounded-[2rem] font-black text-lg hover:bg-slate-100 transition-all shadow-xl">Continuar Jornada</button>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
             ) : (
               <div className="glass-card p-16 rounded-[4rem] text-center border border-rose-100 shadow-sm animate-in zoom-in-95">
                 <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10 shadow-inner"><CheckCircle2 className="w-12 h-12 text-emerald-500" /></div>
                 <h3 className="text-4xl font-black text-slate-900 mb-4">Meta Diária Atingida!</h3>
                 <p className="text-slate-500 text-xl mb-12 max-w-md mx-auto font-medium">Você acaba de depositar amor no banco emocional do seu parceiro(a). O amanhã reserva uma nova oportunidade.</p>
                 <div className="flex flex-col sm:flex-row gap-5 justify-center">
                    <button onClick={() => setActiveTab('myChallenges')} className="px-10 py-5 bg-indigo-600 text-white rounded-[2rem] font-black hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200">Ver Histórico</button>
                    <button onClick={() => setActiveTab('dashboard')} className="px-10 py-5 bg-white border border-rose-100 text-rose-600 rounded-[2rem] font-black hover:bg-rose-50 transition-all">Página Inicial</button>
                 </div>
               </div>
             )}
          </div>
        );
      default: return <div className="p-20 text-center font-bold text-rose-300 text-3xl">Página sendo polida pela nossa equipe...</div>;
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sun className="w-5 h-5" /> },
    { id: 'gratitude', label: 'Diário', icon: <Heart className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Aconselhamento', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Evolução', icon: <TrendingUp className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}

      <header className="sticky top-0 z-[60] bg-white/70 backdrop-blur-2xl border-b border-rose-100/50 h-20 flex items-center">
        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer group" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl shadow-rose-200 group-hover:rotate-6 transition-transform">
              <Heart className="w-7 h-7 text-white fill-white" />
            </div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>

          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id as any)} 
                className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${
                  activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'
                }`}
              >
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>

          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">
        {renderContent()}
      </main>

      {/* Navegação Mobile Premium */}
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button 
            key={item.id}
            onClick={() => setActiveTab(item.id as any)} 
            className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${
              activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'
            }`}
          >
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

