          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>
      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">{renderContent()}</main>
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'}`}>
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message, TankTheme, GratitudeEntry } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import MyChallenges from './components/MyChallenges';
import GratitudeJournal from './components/GratitudeJournal';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, Calendar, CheckCircle2, Trophy, 
  BrainCircuit, ChevronRight, UserPlus, History, MessageSquareText, 
  Eye, Link2, Star, TrendingUp, Zap, Sun, Compass, RotateCcw, Clock3
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [], cycleCount: 1 };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return { status: 'trial', plan: 'none', trialStartedAt: new Date().toISOString(), expiresAt: null };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    return saved ? JSON.parse(saved) : { 
      name: '', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: getInitialSubscription(), notificationsEnabled: false,
      coupleCode: Math.random().toString(36).substring(2, 8).toUpperCase(), isLinked: false, 
      tankTheme: TankTheme.MODERN, gratitudeJournal: []
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false, gratitudeJournal: []
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection' | 'gratitude'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean; impact?: number } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');
  const [showCelebration, setShowCelebration] = useState(false);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleRestartChallenge = async () => {
    if (confirm("Deseja iniciar um novo ciclo de 60 dias de semeadura?")) {
      setLoadingMission(true);
      const cycle = (partner.challenge.cycleCount || 1) + 1;
      // Alterna entre lang1 e lang2 baseado no dia 1
      const targetLang = partner.languages[0];
      const d = await generateDailyMission(targetLang, partner.name, 1);
      setPartner(p => ({
        ...p,
        challenge: {
          ...emptyChallenge,
          type: 60,
          cycleCount: cycle,
          startDate: new Date().toISOString(),
          missions: [{
            id: Math.random().toString(36).substr(2, 9),
            day: 1,
            title: d.title!,
            description: d.description!,
            rationale: d.rationale!,
            completed: false,
            languageApplied: targetLang
          }]
        }
      }));
      setLoadingMission(false);
      setActiveTab('challenge');
    }
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);
      if (success) {
        setShowCelebration(true);
        setTimeout(() => setShowCelebration(false), 4000);
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );
        const nextDay = mission.day + 1;
        if (nextDay <= (partner.challenge.type || 0)) {
          // LÓGICA DE ALTERNÂNCIA: Ímpar = Lang 1, Par = Lang 2
          const targetLang = nextDay % 2 !== 0 ? partner.languages[0] : partner.languages[1];
          const nextData = await generateDailyMission(targetLang, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false,
            languageApplied: targetLang
          });
        }
        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }
      setAiInsight({ feedback, success, impact });
    } finally {
      setLoadingMission(false);
    }
  };

  // Fix: Added missing handler to record a new gratitude entry in the journal
  const handleAddGratitude = (entry: Omit<GratitudeEntry, 'id' | 'date'>) => {
    const newEntry: GratitudeEntry = {
      ...entry,
      id: Math.random().toString(36).substring(2, 9),
      date: new Date().toISOString()
    };
    setUser(prev => ({
      ...prev,
      gratitudeJournal: [...(prev.gratitudeJournal || []), newEntry]
    }));
  };

  // Fix: Added missing handler to delete a specific gratitude entry by ID
  const handleDeleteGratitude = (id: string) => {
    setUser(prev => ({
      ...prev,
      gratitudeJournal: (prev.gratitudeJournal || []).filter(e => e.id !== id)
    }));
  };

  // Fix: Added missing handler to reset a mission's completion state
  const redoMission = (id: string) => {
    setPartner(prev => ({
      ...prev,
      challenge: {
        ...prev.challenge,
        missions: prev.challenge.missions.map(m => 
          m.id === id ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
        )
      }
    }));
  };

  // Fix: Added missing handler to simulate linking with a partner via code
  const handleLinkPartner = (partnerCode: string) => {
    if (partnerCode.trim().length >= 4) {
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: 'Parceiro(a)' }));
      setPartner(prev => ({ ...prev, isLinked: true }));
      alert("Conexão estabelecida com sucesso!");
    } else {
      alert("Por favor, insira um código válido.");
    }
  };

  const renderContent = () => {
    if (!checkAccess() && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection', 'gratitude'].includes(activeTab)) {
      return <Paywall onSubscribe={(id) => { setUser(p => ({ ...p, subscription: { ...p.subscription, status: 'active', plan: id as any } })); setActiveTab('dashboard'); }} isExpired={true} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-12 animate-in fade-in pb-20">
            <section className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-rose-500 to-indigo-600 rounded-[3.5rem] blur opacity-10 group-hover:opacity-25 transition duration-1000"></div>
               <div className="relative glass-card p-10 md:p-14 rounded-[3.5rem] flex flex-col md:flex-row justify-between items-center gap-10">
                  <div className="flex-1 space-y-6">
                    <div className="inline-flex items-center gap-2 px-5 py-2 bg-rose-50 text-rose-600 rounded-full text-xs font-black uppercase tracking-widest border border-rose-100">
                      <Clock3 className="w-4 h-4" /> Micro-Ação do Dia
                    </div>
                    <h2 className="text-4xl md:text-5xl font-black text-rose-950 leading-tight">Pronto para blindar seu amor <span className="text-rose-600 italic">hoje?</span></h2>
                    <p className="text-slate-500 text-lg max-w-lg font-medium">Pequenos gestos de Amor Sacrificial feitos com intenção transformam o ambiente da sua casa.</p>
                    <div className="flex flex-wrap gap-4 pt-4">
                      <button onClick={() => setActiveTab('challenge')} className="px-10 py-5 bg-rose-600 text-white rounded-[2rem] font-black text-lg hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 flex items-center gap-3">
                         {partner.challenge.type ? 'Abrir Missão' : 'Iniciar 60 Dias'} <ChevronRight className="w-5 h-5" />
                      </button>
                      <button onClick={() => setActiveTab('coach')} className="px-8 py-5 bg-white border border-rose-100 text-rose-900 rounded-[2rem] font-bold text-lg hover:bg-rose-50 transition-all flex items-center gap-3 shadow-sm">
                         Aconselhamento Pastoral <Compass className="w-5 h-5 text-rose-400" />
                      </button>
                    </div>
                  </div>
                  <div className="w-full md:w-1/3 flex justify-center">
                    <div className="w-48 h-48 bg-rose-50 rounded-[3rem] flex items-center justify-center relative animate-float">
                      <Calendar className="w-20 h-20 text-rose-500" />
                      {partner.challenge.missions.length > 0 && (
                        <div className="absolute -top-4 -right-4 bg-indigo-600 text-white w-14 h-14 rounded-full flex flex-col items-center justify-center font-black shadow-xl">
                          <span className="text-[10px] uppercase leading-none">Dia</span>
                          <span className="text-xl">{partner.challenge.missions.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
            </section>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="glass-card p-8 rounded-[3rem] border border-blue-50">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Suas Linguagens Principais</p>
                  <div className="flex flex-wrap gap-3">
                    {user.languages.length > 0 ? user.languages.map(l => (
                      <div key={l} className="px-4 py-2 bg-blue-50 text-blue-600 rounded-xl text-xs font-black border border-blue-100">{l}</div>
                    )) : <button onClick={() => setActiveTab('quiz')} className="text-blue-500 font-bold hover:underline">Fazer Teste Pastoral</button>}
                  </div>
               </div>
               <div className="glass-card p-8 rounded-[3rem] border border-rose-50">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Linguagens de {partner.name}</p>
                  <div className="flex flex-wrap gap-3">
                    {partner.languages.length > 0 ? partner.languages.map(l => (
                      <div key={l} className="px-4 py-2 bg-rose-50 text-rose-600 rounded-xl text-xs font-black border border-rose-100">{l}</div>
                    )) : <button onClick={() => setActiveTab('partnerQuiz')} className="text-rose-500 font-bold hover:underline">Descobrir linguagens dele(a)</button>}
                  </div>
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <TankGauge label="Termômetro Diário" type="self" level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
              <TankGauge label="Termômetro do Parceiro" type="partner" level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="glass-card p-12 md:p-20 rounded-[4rem] shadow-xl border border-rose-100">
                <div className="w-24 h-24 bg-rose-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10"><Calendar className="w-12 h-12 text-rose-600" /></div>
                <h2 className="text-5xl font-black text-rose-950 mb-8 tracking-tight">Comece a Semear</h2>
                <p className="text-slate-500 text-xl mb-12 max-w-2xl mx-auto font-medium">60 dias de Amor Sacrificial transformarão seu casamento em algo duradouro e prazeroso.</p>
                <button 
                  disabled={partner.languages.length < 2}
                  onClick={async () => { 
                    setLoadingMission(true); 
                    const targetLang = partner.languages[0];
                    const d = await generateDailyMission(targetLang, partner.name, 1); 
                    setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), cycleCount: 1, missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false, languageApplied: targetLang }] } })); 
                    setLoadingMission(false); 
                  }} 
                  className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all text-white group disabled:opacity-50"
                >
                  <span className="block font-black text-3xl mb-1 uppercase tracking-tighter">Ativar Desafio</span>
                  <span className="text-rose-100 text-xs font-bold uppercase tracking-widest">
                    {partner.languages.length < 2 ? "Descubra as linguagens do parceiro primeiro" : "Conselho Pastoral do Dia"}
                  </span>
                </button>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        const allCompleted = challenge.missions.length === challenge.type && challenge.missions.every(m => m.completed);

        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12 relative">
             {showCelebration && [...Array(15)].map((_, i) => (
                <div key={i} className="floating-heart text-rose-500 opacity-0" style={{ left: `${Math.random() * 80 + 10}%`, top: '80%', animationDelay: `${Math.random() * 0.8}s`, fontSize: `${Math.random() * 20 + 10}px` }}><Heart className="fill-current" /></div>
             ))}
             {allCompleted ? (
               <div className="glass-card p-16 rounded-[4rem] text-center border border-emerald-100 shadow-xl bg-emerald-50/20">
                 <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10"><Trophy className="w-12 h-12 text-emerald-500" /></div>
                 <h3 className="text-4xl font-black text-emerald-950 mb-4">Ciclo de 60 Dias Concluído!</h3>
                 <p className="text-slate-600 text-xl mb-12 max-w-md mx-auto font-medium">Sua semeadura foi constante. O seu casamento está mais forte hoje.</p>
                 <div className="flex flex-col sm:flex-row gap-5 justify-center">
                    <button onClick={handleRestartChallenge} className="px-10 py-5 bg-emerald-600 text-white rounded-[2rem] font-black hover:bg-emerald-700 transition-all shadow-xl">Semear por mais 60 dias</button>
                    <button onClick={() => setActiveTab('dashboard')} className="px-10 py-5 bg-white border border-rose-100 text-rose-600 rounded-[2rem] font-black">Voltar ao Início</button>
                 </div>
               </div>
             ) : currentMission ? (
               <div className="space-y-6">
                  {aiInsight?.success && (
                    <div className="bg-emerald-600 text-white p-10 rounded-[3.5rem] shadow-2xl flex flex-col md:flex-row items-center gap-8 border-4 border-white">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shrink-0 shadow-lg rotate-6"><Trophy className="w-12 h-12 text-emerald-600" /></div>
                      <div className="flex-1">
                        <h4 className="text-3xl font-black mb-3">Semente bem plantada!</h4>
                        <p className="text-emerald-50 text-lg leading-relaxed font-medium">"{aiInsight.feedback}"</p>
                      </div>
                    </div>
                  )}
                  <div className="bg-slate-950 text-white rounded-[3.5rem] p-10 md:p-16 shadow-2xl relative overflow-hidden group">
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-10">
                        <div className="px-5 py-2 bg-white/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-rose-400 backdrop-blur-sm">Dia {currentMission.day} • {currentMission.languageApplied}</div>
                      </div>
                      <h4 className="text-5xl font-black mb-8 text-white leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-2xl text-slate-300 leading-relaxed mb-12 font-medium">"{currentMission.description}"</p>
                      <div className="bg-white/5 border border-white/10 p-6 rounded-2xl mb-12">
                         <h5 className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2"><Sparkles className="w-3 h-3" /> Sabedoria de Semeadura</h5>
                         <p className="text-slate-400 text-sm italic font-medium">"{currentMission.rationale}"</p>
                      </div>
                      {!aiInsight?.success && (
                        <div className="space-y-6">
                          <textarea value={fulfillmentText} onChange={(e) => setFulfillmentText(e.target.value)} placeholder="Como foi semear amor desta forma hoje?" className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-8 text-white text-xl focus:outline-none focus:border-rose-500 transition-all h-48 font-medium" />
                          <button onClick={() => completeMission(currentMission)} disabled={loadingMission || !fulfillmentText.trim()} className="w-full py-6 bg-rose-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-rose-700 transition-all flex items-center justify-center gap-4 shadow-2xl">
                            {loadingMission ? <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" /> : "Validar Missão"}
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
             ) : null}
          </div>
        );
      case 'coach': return <PersonalCoach />;
      case 'gratitude': return <GratitudeJournal entries={user.gratitudeJournal || []} onAddEntry={handleAddGratitude} onDeleteEntry={handleDeleteGratitude} />;
      case 'myChallenges': return <MyChallenges challenge={partner.challenge} partnerName={partner.name} onRedoMission={redoMission} onGoToChallenge={() => setActiveTab('challenge')} />;
      case 'connection': return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      default: return null;
    }
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    return (new Date().getTime() - new Date(user.subscription.trialStartedAt).getTime()) <= 7 * 24 * 60 * 60 * 1000;
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sun className="w-5 h-5" /> },
    { id: 'gratitude', label: 'Diário', icon: <Heart className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Aconselhamento', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Evolução', icon: <TrendingUp className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}
      <header className="sticky top-0 z-[60] bg-white/70 backdrop-blur-2xl border-b border-rose-100/50 h-20 flex items-center">
        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl"><Heart className="w-7 h-7 text-white fill-white" /></div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'}`}>
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>
          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>
      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">{renderContent()}</main>
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'}`}>
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { LoveLanguage, Mission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateDailyMission = async (targetLanguage: LoveLanguage, targetName: string, dayNumber: number): Promise<Partial<Mission>> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Gere uma missão prática de "Amor Sacrificial" para o dia ${dayNumber} do desafio. O alvo é "${targetName}" e sua linguagem do amor predominante é "${targetLanguage}".`,
    config: {
      systemInstruction: `Você é um mentor de relacionamentos especialista no método de Gary Chapman.
      SEU OBJETIVO: Criar uma tarefa simples, curta e potente que fortaleça o vínculo com ${targetName} através da linguagem "${targetLanguage}".

      REGRAS PARA A MISSÃO:
      1. SIMPLICIDADE ABSOLUTA: A tarefa deve ser realizável em menos de 15 minutos e não deve exigir gastos financeiros significativos ou logística complexa.
      2. REPLICABILIDADE: Foque em ações que possam se tornar hábitos. O usuário deve sentir que "pode fazer isso sempre".
      3. CONEXÃO DIRETA: A missão deve atingir o coração da linguagem "${targetLanguage}". 
         - Se Palavras: Um elogio específico.
         - Se Tempo: 10 min de conversa olho no olho sem celular.
         - Se Presentes: Uma flor colhida ou um doce favorito.
         - Se Atos de Serviço: Uma tarefa doméstica que o outro detesta fazer.
         - Se Toque: Um abraço de 30 segundos ou massagem rápida nos ombros.
      4. TOM: Inspirador, prático e focado no cuidado.

      ESTRUTURA:
      - title: Nome curto e acionável (ex: "O Elogio Sincero", "O Café do Cuidado").
      - description: Instrução passo a passo de como executar.
      - rationale: Explicação breve de por que esse pequeno gesto é um "depósito" gigante no tanque emocional de quem fala "${targetLanguage}".`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          rationale: { type: Type.STRING }
        },
        required: ["title", "description", "rationale"]
      }
    }
  });
  // Fix: Use trim() to clean the response text before parsing JSON
  return JSON.parse(response.text?.trim() || '{}');
};

export const getMissionCompletionFeedback = async (
  mission: Mission, 
  partnerName: string, 
  userRelato: string
): Promise<{ feedback: string, impact: number, success: boolean }> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Missão: "${mission.title}". 
    O que foi pedido: "${mission.description}".
    Relato do usuário: "${userRelato}". 
    Avalie o cumprimento desta pequena meta diária para ${partnerName}.`,
    config: {
      systemInstruction: `Analise o relato de cumprimento.
      - Valorize a consistência e a intenção, não a grandiosidade.
      - Se o usuário descreveu o que fez com sinceridade, success é true.
      - Ofereça um feedback encorajador que mostre como esse pequeno passo constrói uma relação inabalável.
      - Impact: Atribua de 0.3 a 1.5 baseado no nível de conexão demonstrado no relato.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          feedback: { type: Type.STRING },
          impact: { type: Type.NUMBER },
          success: { type: Type.BOOLEAN }
        },
        required: ["feedback", "impact", "success"]
      }
    }
  });
  // Fix: Use trim() to clean the response text before parsing JSON
  return JSON.parse(response.text?.trim() || '{"feedback": "Erro no feedback", "impact": 0, "success": false}');
};

export const getCoachAdvice = async (history: {role: string, parts: {text: string}[]}[], userMessage: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [...history, { role: 'user', parts: [{ text: userMessage }] }],
    config: {
      systemInstruction: `Você é o "Personal Coach" de felicidade conjugal.
      PERSONA:
      - Prático, acolhedor e focado em soluções.
      - Defensor de que "pequenas coisas feitas com muito amor mudam o mundo".
      OBJETIVO:
      - Transformar conflitos em oportunidades de serviço.
      - Sugerir micro-ações imediatas para melhorar o clima da casa.`,
      temperature: 0.8,
      topP: 0.95,
    }
  });
  // Fix: Ensure we return an empty string if text is undefined
  return response.text || '';
};

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message, TankTheme, GratitudeEntry } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import MyChallenges from './components/MyChallenges';
import GratitudeJournal from './components/GratitudeJournal';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, Calendar, CheckCircle2, Trophy, 
  BrainCircuit, ChevronRight, UserPlus, History, MessageSquareText, 
  Eye, Link2, Star, TrendingUp, Zap, Sun, Compass, RotateCcw, Clock3
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [], cycleCount: 1 };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return { status: 'trial', plan: 'none', trialStartedAt: new Date().toISOString(), expiresAt: null };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    return saved ? JSON.parse(saved) : { 
      name: '', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: getInitialSubscription(), notificationsEnabled: false,
      coupleCode: Math.random().toString(36).substring(2, 8).toUpperCase(), isLinked: false, 
      tankTheme: TankTheme.MODERN, gratitudeJournal: []
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false, gratitudeJournal: []
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection' | 'gratitude'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean; impact?: number } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');
  const [showCelebration, setShowCelebration] = useState(false);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleRestartChallenge = async () => {
    if (confirm("Deseja iniciar um novo ciclo de 60 dias de semeadura?")) {
      setLoadingMission(true);
      const cycle = (partner.challenge.cycleCount || 1) + 1;
      const targetLang = partner.languages[0];
      const d = await generateDailyMission(targetLang, partner.name, 1);
      setPartner(p => ({
        ...p,
        challenge: {
          ...emptyChallenge,
          type: 60,
          cycleCount: cycle,
          startDate: new Date().toISOString(),
          missions: [{
            id: Math.random().toString(36).substr(2, 9),
            day: 1,
            title: d.title!,
            description: d.description!,
            rationale: d.rationale!,
            completed: false,
            languageApplied: targetLang
          }]
        }
      }));
      setLoadingMission(false);
      setActiveTab('challenge');
    }
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);
      if (success) {
        setShowCelebration(true);
        setTimeout(() => setShowCelebration(false), 4000);
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );
        const nextDay = mission.day + 1;
        if (nextDay <= (partner.challenge.type || 0)) {
          const targetLang = nextDay % 2 !== 0 ? partner.languages[0] : partner.languages[1];
          const nextData = await generateDailyMission(targetLang, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false,
            languageApplied: targetLang
          });
        }
        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }
      setAiInsight({ feedback, success, impact });
    } finally {
      setLoadingMission(false);
    }
  };

  const handleAddGratitude = (entry: Omit<GratitudeEntry, 'id' | 'date'>) => {
    const newEntry: GratitudeEntry = {
      ...entry,
      id: Math.random().toString(36).substring(2, 9),
      date: new Date().toISOString()
    };
    setUser(prev => ({
      ...prev,
      gratitudeJournal: [...(prev.gratitudeJournal || []), newEntry]
    }));
  };

  const handleDeleteGratitude = (id: string) => {
    setUser(prev => ({
      ...prev,
      gratitudeJournal: (prev.gratitudeJournal || []).filter(e => e.id !== id)
    }));
  };

  const redoMission = (id: string) => {
    setPartner(prev => ({
      ...prev,
      challenge: {
        ...prev.challenge,
        missions: prev.challenge.missions.map(m => 
          m.id === id ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
        )
      }
    }));
  };

  const handleLinkPartner = (partnerCode: string) => {
    if (partnerCode.trim().length >= 4) {
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: 'Parceiro(a)' }));
      setPartner(prev => ({ ...prev, isLinked: true }));
      alert("Conexão estabelecida com sucesso!");
    } else {
      alert("Por favor, insira um código válido.");
    }
  };

  const renderContent = () => {
    if (!checkAccess() && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection', 'gratitude'].includes(activeTab)) {
      return <Paywall onSubscribe={(id) => { setUser(p => ({ ...p, subscription: { ...p.subscription, status: 'active', plan: id as any } })); setActiveTab('dashboard'); }} isExpired={true} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-12 animate-in fade-in pb-20">
            <section className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-rose-500 to-indigo-600 rounded-[3.5rem] blur opacity-10 group-hover:opacity-25 transition duration-1000"></div>
               <div className="relative glass-card p-10 md:p-14 rounded-[3.5rem] flex flex-col md:flex-row justify-between items-center gap-10">
                  <div className="flex-1 space-y-6">
                    <div className="inline-flex items-center gap-2 px-5 py-2 bg-rose-50 text-rose-600 rounded-full text-xs font-black uppercase tracking-widest border border-rose-100">
                      <Clock3 className="w-4 h-4" /> Micro-Ação do Dia
                    </div>
                    <h2 className="text-4xl md:text-5xl font-black text-rose-950 leading-tight">Pronto para blindar seu amor <span className="text-rose-600 italic">hoje?</span></h2>
                    <p className="text-slate-500 text-lg max-w-lg font-medium">Pequenos gestos de Amor Sacrificial feitos com intenção transformam o ambiente da sua casa.</p>
                    <div className="flex flex-wrap gap-4 pt-4">
                      <button onClick={() => setActiveTab('challenge')} className="px-10 py-5 bg-rose-600 text-white rounded-[2rem] font-black text-lg hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 flex items-center gap-3">
                         {partner.challenge.type ? 'Abrir Missão' : 'Iniciar 60 Dias'} <ChevronRight className="w-5 h-5" />
                      </button>
                      <button onClick={() => setActiveTab('coach')} className="px-8 py-5 bg-white border border-rose-100 text-rose-900 rounded-[2rem] font-bold text-lg hover:bg-rose-50 transition-all flex items-center gap-3 shadow-sm">
                         Aconselhamento Pastoral <Compass className="w-5 h-5 text-rose-400" />
                      </button>
                    </div>
                  </div>
                  <div className="w-full md:w-1/3 flex justify-center">
                    <div className="w-48 h-48 bg-rose-50 rounded-[3rem] flex items-center justify-center relative animate-float">
                      <Calendar className="w-20 h-20 text-rose-500" />
                      {partner.challenge.missions.length > 0 && (
                        <div className="absolute -top-4 -right-4 bg-indigo-600 text-white w-14 h-14 rounded-full flex flex-col items-center justify-center font-black shadow-xl">
                          <span className="text-[10px] uppercase leading-none">Dia</span>
                          <span className="text-xl">{partner.challenge.missions.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
            </section>

            {/* Restaurado o visual dos cartões conforme imagem enviada */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="bg-white p-10 rounded-[3.5rem] border border-blue-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Suas Linguagens Principais</p>
                  {user.languages.length > 0 ? (
                    <div className="flex flex-wrap gap-3">
                      {user.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-blue-50 text-blue-600 rounded-2xl text-xs font-black border border-blue-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-blue-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('quiz')} 
                      className="text-left text-2xl font-black text-blue-600 hover:text-blue-700 transition-colors flex items-center gap-2 group"
                    >
                      Fazer Teste Pastoral
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>

               <div className="bg-white p-10 rounded-[3.5rem] border border-rose-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Linguagens de {partner.name}</p>
                  {partner.languages.length > 0 ? (
                    <div className="flex flex-wrap gap-3">
                      {partner.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-rose-50 text-rose-600 rounded-2xl text-xs font-black border border-rose-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-rose-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('partnerQuiz')} 
                      className="text-left text-2xl font-black text-rose-600 hover:text-rose-700 transition-colors flex items-center gap-2 group"
                    >
                      Descobrir linguagens dele(a)
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <TankGauge label="Termômetro Diário" type="self" level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
              <TankGauge label="Termômetro do Parceiro" type="partner" level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="glass-card p-12 md:p-20 rounded-[4rem] shadow-xl border border-rose-100">
                <div className="w-24 h-24 bg-rose-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10"><Calendar className="w-12 h-12 text-rose-600" /></div>
                <h2 className="text-5xl font-black text-rose-950 mb-8 tracking-tight">Comece a Semear</h2>
                <p className="text-slate-500 text-xl mb-12 max-w-2xl mx-auto font-medium">60 dias de Amor Sacrificial transformarão seu casamento em algo duradouro e prazeroso.</p>
                <button 
                  disabled={partner.languages.length < 2}
                  onClick={async () => { 
                    setLoadingMission(true); 
                    const targetLang = partner.languages[0];
                    const d = await generateDailyMission(targetLang, partner.name, 1); 
                    setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), cycleCount: 1, missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false, languageApplied: targetLang }] } })); 
                    setLoadingMission(false); 
                  }} 
                  className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all text-white group disabled:opacity-50"
                >
                  <span className="block font-black text-3xl mb-1 uppercase tracking-tighter">Ativar Desafio</span>
                  <span className="text-rose-100 text-xs font-bold uppercase tracking-widest">
                    {partner.languages.length < 2 ? "Descubra as linguagens do parceiro primeiro" : "Conselho Pastoral do Dia"}
                  </span>
                </button>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        const allCompleted = challenge.missions.length === challenge.type && challenge.missions.every(m => m.completed);

        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12 relative">
             {showCelebration && [...Array(15)].map((_, i) => (
                <div key={i} className="floating-heart text-rose-500 opacity-0" style={{ left: `${Math.random() * 80 + 10}%`, top: '80%', animationDelay: `${Math.random() * 0.8}s`, fontSize: `${Math.random() * 20 + 10}px` }}><Heart className="fill-current" /></div>
             ))}
             {allCompleted ? (
               <div className="glass-card p-16 rounded-[4rem] text-center border border-emerald-100 shadow-xl bg-emerald-50/20">
                 <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10"><Trophy className="w-12 h-12 text-emerald-500" /></div>
                 <h3 className="text-4xl font-black text-emerald-950 mb-4">Ciclo de 60 Dias Concluído!</h3>
                 <p className="text-slate-600 text-xl mb-12 max-w-md mx-auto font-medium">Sua semeadura foi constante. O seu casamento está mais forte hoje.</p>
                 <div className="flex flex-col sm:flex-row gap-5 justify-center">
                    <button onClick={handleRestartChallenge} className="px-10 py-5 bg-emerald-600 text-white rounded-[2rem] font-black hover:bg-emerald-700 transition-all shadow-xl">Semear por mais 60 dias</button>
                    <button onClick={() => setActiveTab('dashboard')} className="px-10 py-5 bg-white border border-rose-100 text-rose-600 rounded-[2rem] font-black">Voltar ao Início</button>
                 </div>
               </div>
             ) : currentMission ? (
               <div className="space-y-6">
                  {aiInsight?.success && (
                    <div className="bg-emerald-600 text-white p-10 rounded-[3.5rem] shadow-2xl flex flex-col md:flex-row items-center gap-8 border-4 border-white">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shrink-0 shadow-lg rotate-6"><Trophy className="w-12 h-12 text-emerald-600" /></div>
                      <div className="flex-1">
                        <h4 className="text-3xl font-black mb-3">Semente bem plantada!</h4>
                        <p className="text-emerald-50 text-lg leading-relaxed font-medium">"{aiInsight.feedback}"</p>
                      </div>
                    </div>
                  )}
                  <div className="bg-slate-950 text-white rounded-[3.5rem] p-10 md:p-16 shadow-2xl relative overflow-hidden group">
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-10">
                        <div className="px-5 py-2 bg-white/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-rose-400 backdrop-blur-sm">Dia {currentMission.day} • {currentMission.languageApplied}</div>
                      </div>
                      <h4 className="text-5xl font-black mb-8 text-white leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-2xl text-slate-300 leading-relaxed mb-12 font-medium">"{currentMission.description}"</p>
                      <div className="bg-white/5 border border-white/10 p-6 rounded-2xl mb-12">
                         <h5 className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2"><Sparkles className="w-3 h-3" /> Sabedoria de Semeadura</h5>
                         <p className="text-slate-400 text-sm italic font-medium">"{currentMission.rationale}"</p>
                      </div>
                      {!aiInsight?.success && (
                        <div className="space-y-6">
                          <textarea value={fulfillmentText} onChange={(e) => setFulfillmentText(e.target.value)} placeholder="Como foi semear amor desta forma hoje?" className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-8 text-white text-xl focus:outline-none focus:border-rose-500 transition-all h-48 font-medium" />
                          <button onClick={() => completeMission(currentMission)} disabled={loadingMission || !fulfillmentText.trim()} className="w-full py-6 bg-rose-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-rose-700 transition-all flex items-center justify-center gap-4 shadow-2xl">
                            {loadingMission ? <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" /> : "Validar Missão"}
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
             ) : null}
          </div>
        );
      case 'coach': return <PersonalCoach />;
      case 'gratitude': return <GratitudeJournal entries={user.gratitudeJournal || []} onAddEntry={handleAddGratitude} onDeleteEntry={handleDeleteGratitude} />;
      case 'myChallenges': return <MyChallenges challenge={partner.challenge} partnerName={partner.name} onRedoMission={redoMission} onGoToChallenge={() => setActiveTab('challenge')} />;
      case 'connection': return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      default: return null;
    }
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    return (new Date().getTime() - new Date(user.subscription.trialStartedAt).getTime()) <= 7 * 24 * 60 * 60 * 1000;
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sun className="w-5 h-5" /> },
    { id: 'gratitude', label: 'Diário', icon: <Heart className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Aconselhamento', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Evolução', icon: <TrendingUp className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}
      <header className="sticky top-0 z-[60] bg-white/70 backdrop-blur-2xl border-b border-rose-100/50 h-20 flex items-center">
        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl"><Heart className="w-7 h-7 text-white fill-white" /></div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'}`}>
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>
          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>
      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">{renderContent()}</main>
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'}`}>
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message, TankTheme, GratitudeEntry } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import MyChallenges from './components/MyChallenges';
import GratitudeJournal from './components/GratitudeJournal';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, Calendar, CheckCircle2, Trophy, 
  BrainCircuit, ChevronRight, UserPlus, History, MessageSquareText, 
  Eye, Link2, Star, TrendingUp, Zap, Sun, Compass, RotateCcw, Clock3
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [], cycleCount: 1 };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return { status: 'trial', plan: 'none', trialStartedAt: new Date().toISOString(), expiresAt: null };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    return saved ? JSON.parse(saved) : { 
      name: '', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: getInitialSubscription(), notificationsEnabled: false,
      coupleCode: Math.random().toString(36).substring(2, 8).toUpperCase(), isLinked: false, 
      tankTheme: TankTheme.MODERN, gratitudeJournal: []
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false, gratitudeJournal: []
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'partnerQuiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection' | 'gratitude'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean; impact?: number } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');
  const [showCelebration, setShowCelebration] = useState(false);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleRestartChallenge = async () => {
    if (confirm("Deseja iniciar um novo ciclo de 60 dias de semeadura?")) {
      setLoadingMission(true);
      const cycle = (partner.challenge.cycleCount || 1) + 1;
      const targetLang = partner.languages[0];
      const d = await generateDailyMission(targetLang, partner.name, 1);
      setPartner(p => ({
        ...p,
        challenge: {
          ...emptyChallenge,
          type: 60,
          cycleCount: cycle,
          startDate: new Date().toISOString(),
          missions: [{
            id: Math.random().toString(36).substr(2, 9),
            day: 1,
            title: d.title!,
            description: d.description!,
            rationale: d.rationale!,
            completed: false,
            languageApplied: targetLang
          }]
        }
      }));
      setLoadingMission(false);
      setActiveTab('challenge');
    }
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);
      if (success) {
        setShowCelebration(true);
        setTimeout(() => setShowCelebration(false), 4000);
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );
        const nextDay = mission.day + 1;
        if (nextDay <= (partner.challenge.type || 0)) {
          const targetLang = nextDay % 2 !== 0 ? partner.languages[0] : partner.languages[1];
          const nextData = await generateDailyMission(targetLang, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false,
            languageApplied: targetLang
          });
        }
        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }
      setAiInsight({ feedback, success, impact });
    } finally {
      setLoadingMission(false);
    }
  };

  const handleAddGratitude = (entry: Omit<GratitudeEntry, 'id' | 'date'>) => {
    const newEntry: GratitudeEntry = {
      ...entry,
      id: Math.random().toString(36).substring(2, 9),
      date: new Date().toISOString()
    };
    setUser(prev => ({
      ...prev,
      gratitudeJournal: [...(prev.gratitudeJournal || []), newEntry]
    }));
  };

  const handleDeleteGratitude = (id: string) => {
    setUser(prev => ({
      ...prev,
      gratitudeJournal: (prev.gratitudeJournal || []).filter(e => e.id !== id)
    }));
  };

  const redoMission = (id: string) => {
    setPartner(prev => ({
      ...prev,
      challenge: {
        ...prev.challenge,
        missions: prev.challenge.missions.map(m => 
          m.id === id ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
        )
      }
    }));
  };

  const handleLinkPartner = (partnerCode: string) => {
    if (partnerCode.trim().length >= 4) {
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: 'Parceiro(a)' }));
      setPartner(prev => ({ ...prev, isLinked: true }));
      alert("Conexão estabelecida com sucesso!");
    } else {
      alert("Por favor, insira um código válido.");
    }
  };

  const renderContent = () => {
    if (!checkAccess() && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection', 'gratitude'].includes(activeTab)) {
      return <Paywall onSubscribe={(id) => { setUser(p => ({ ...p, subscription: { ...p.subscription, status: 'active', plan: id as any } })); setActiveTab('dashboard'); }} isExpired={true} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-12 animate-in fade-in pb-20">
            <section className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-rose-500 to-indigo-600 rounded-[3.5rem] blur opacity-10 group-hover:opacity-25 transition duration-1000"></div>
               <div className="relative glass-card p-10 md:p-14 rounded-[3.5rem] flex flex-col md:flex-row justify-between items-center gap-10">
                  <div className="flex-1 space-y-6">
                    <div className="inline-flex items-center gap-2 px-5 py-2 bg-rose-50 text-rose-600 rounded-full text-xs font-black uppercase tracking-widest border border-rose-100">
                      <Clock3 className="w-4 h-4" /> Micro-Ação do Dia
                    </div>
                    <h2 className="text-4xl md:text-5xl font-black text-rose-950 leading-tight">Pronto para blindar seu amor <span className="text-rose-600 italic">hoje?</span></h2>
                    <p className="text-slate-500 text-lg max-w-lg font-medium">Pequenos gestos de Amor Sacrificial feitos com intenção transformam o ambiente da sua casa.</p>
                    <div className="flex flex-wrap gap-4 pt-4">
                      <button onClick={() => setActiveTab('challenge')} className="px-10 py-5 bg-rose-600 text-white rounded-[2rem] font-black text-lg hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 flex items-center gap-3">
                         {partner.challenge.type ? 'Abrir Missão' : 'Iniciar 60 Dias'} <ChevronRight className="w-5 h-5" />
                      </button>
                      <button onClick={() => setActiveTab('coach')} className="px-8 py-5 bg-white border border-rose-100 text-rose-900 rounded-[2rem] font-bold text-lg hover:bg-rose-50 transition-all flex items-center gap-3 shadow-sm">
                         Aconselhamento Pastoral <Compass className="w-5 h-5 text-rose-400" />
                      </button>
                    </div>
                  </div>
                  <div className="w-full md:w-1/3 flex justify-center">
                    <div className="w-48 h-48 bg-rose-50 rounded-[3rem] flex items-center justify-center relative animate-float">
                      <Calendar className="w-20 h-20 text-rose-500" />
                      {partner.challenge.missions.length > 0 && (
                        <div className="absolute -top-4 -right-4 bg-indigo-600 text-white w-14 h-14 rounded-full flex flex-col items-center justify-center font-black shadow-xl">
                          <span className="text-[10px] uppercase leading-none">Dia</span>
                          <span className="text-xl">{partner.challenge.missions.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
            </section>

            {/* Visual dos cartões restaurado e texto simplificado para "Fazer Teste" */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="bg-white p-10 rounded-[3.5rem] border border-blue-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Suas Linguagens Principais</p>
                  {user.languages.length > 0 ? (
                    <div className="flex flex-wrap gap-3">
                      {user.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-blue-50 text-blue-600 rounded-2xl text-xs font-black border border-blue-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-blue-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('quiz')} 
                      className="text-left text-2xl font-black text-blue-600 hover:text-blue-700 transition-colors flex items-center gap-2 group"
                    >
                      Fazer Teste
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>

               <div className="bg-white p-10 rounded-[3.5rem] border border-rose-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Linguagens de {partner.name}</p>
                  {partner.languages.length > 0 ? (
                    <div className="flex flex-wrap gap-3">
                      {partner.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-rose-50 text-rose-600 rounded-2xl text-xs font-black border border-rose-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-rose-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('partnerQuiz')} 
                      className="text-left text-2xl font-black text-rose-600 hover:text-rose-700 transition-colors flex items-center gap-2 group"
                    >
                      Descobrir linguagens dele(a)
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <TankGauge label="Termômetro Diário" type="self" level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
              <TankGauge label="Termômetro do Parceiro" type="partner" level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'partnerQuiz': return <Quiz onComplete={(res) => { setPartner(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="glass-card p-12 md:p-20 rounded-[4rem] shadow-xl border border-rose-100">
                <div className="w-24 h-24 bg-rose-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10"><Calendar className="w-12 h-12 text-rose-600" /></div>
                <h2 className="text-5xl font-black text-rose-950 mb-8 tracking-tight">Comece a Semear</h2>
                <p className="text-slate-500 text-xl mb-12 max-w-2xl mx-auto font-medium">60 dias de Amor Sacrificial transformarão seu casamento em algo duradouro e prazeroso.</p>
                <button 
                  disabled={partner.languages.length < 2}
                  onClick={async () => { 
                    setLoadingMission(true); 
                    const targetLang = partner.languages[0];
                    const d = await generateDailyMission(targetLang, partner.name, 1); 
                    setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), cycleCount: 1, missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false, languageApplied: targetLang }] } })); 
                    setLoadingMission(false); 
                  }} 
                  className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all text-white group disabled:opacity-50"
                >
                  <span className="block font-black text-3xl mb-1 uppercase tracking-tighter">Ativar Desafio</span>
                  <span className="text-rose-100 text-xs font-bold uppercase tracking-widest">
                    {partner.languages.length < 2 ? "Descubra as linguagens do parceiro primeiro" : "Conselho Pastoral do Dia"}
                  </span>
                </button>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        const allCompleted = challenge.missions.length === challenge.type && challenge.missions.every(m => m.completed);

        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12 relative">
             {showCelebration && [...Array(15)].map((_, i) => (
                <div key={i} className="floating-heart text-rose-500 opacity-0" style={{ left: `${Math.random() * 80 + 10}%`, top: '80%', animationDelay: `${Math.random() * 0.8}s`, fontSize: `${Math.random() * 20 + 10}px` }}><Heart className="fill-current" /></div>
             ))}
             {allCompleted ? (
               <div className="glass-card p-16 rounded-[4rem] text-center border border-emerald-100 shadow-xl bg-emerald-50/20">
                 <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10"><Trophy className="w-12 h-12 text-emerald-500" /></div>
                 <h3 className="text-4xl font-black text-emerald-950 mb-4">Ciclo de 60 Dias Concluído!</h3>
                 <p className="text-slate-600 text-xl mb-12 max-w-md mx-auto font-medium">Sua semeadura foi constante. O seu casamento está mais forte hoje.</p>
                 <div className="flex flex-col sm:flex-row gap-5 justify-center">
                    <button onClick={handleRestartChallenge} className="px-10 py-5 bg-emerald-600 text-white rounded-[2rem] font-black hover:bg-emerald-700 transition-all shadow-xl">Semear por mais 60 dias</button>
                    <button onClick={() => setActiveTab('dashboard')} className="px-10 py-5 bg-white border border-rose-100 text-rose-600 rounded-[2rem] font-black">Voltar ao Início</button>
                 </div>
               </div>
             ) : currentMission ? (
               <div className="space-y-6">
                  {aiInsight?.success && (
                    <div className="bg-emerald-600 text-white p-10 rounded-[3.5rem] shadow-2xl flex flex-col md:flex-row items-center gap-8 border-4 border-white">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shrink-0 shadow-lg rotate-6"><Trophy className="w-12 h-12 text-emerald-600" /></div>
                      <div className="flex-1">
                        <h4 className="text-3xl font-black mb-3">Semente bem plantada!</h4>
                        <p className="text-emerald-50 text-lg leading-relaxed font-medium">"{aiInsight.feedback}"</p>
                      </div>
                    </div>
                  )}
                  <div className="bg-slate-950 text-white rounded-[3.5rem] p-10 md:p-16 shadow-2xl relative overflow-hidden group">
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-10">
                        <div className="px-5 py-2 bg-white/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-rose-400 backdrop-blur-sm">Dia {currentMission.day} • {currentMission.languageApplied}</div>
                      </div>
                      <h4 className="text-5xl font-black mb-8 text-white leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-2xl text-slate-300 leading-relaxed mb-12 font-medium">"{currentMission.description}"</p>
                      <div className="bg-white/5 border border-white/10 p-6 rounded-2xl mb-12">
                         <h5 className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2"><Sparkles className="w-3 h-3" /> Sabedoria de Semeadura</h5>
                         <p className="text-slate-400 text-sm italic font-medium">"{currentMission.rationale}"</p>
                      </div>
                      {!aiInsight?.success && (
                        <div className="space-y-6">
                          <textarea value={fulfillmentText} onChange={(e) => setFulfillmentText(e.target.value)} placeholder="Como foi semear amor desta forma hoje?" className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-8 text-white text-xl focus:outline-none focus:border-rose-500 transition-all h-48 font-medium" />
                          <button onClick={() => completeMission(currentMission)} disabled={loadingMission || !fulfillmentText.trim()} className="w-full py-6 bg-rose-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-rose-700 transition-all flex items-center justify-center gap-4 shadow-2xl">
                            {loadingMission ? <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" /> : "Validar Missão"}
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
             ) : null}
          </div>
        );
      case 'coach': return <PersonalCoach />;
      case 'gratitude': return <GratitudeJournal entries={user.gratitudeJournal || []} onAddEntry={handleAddGratitude} onDeleteEntry={handleDeleteGratitude} />;
      case 'myChallenges': return <MyChallenges challenge={partner.challenge} partnerName={partner.name} onRedoMission={redoMission} onGoToChallenge={() => setActiveTab('challenge')} />;
      case 'connection': return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      default: return null;
    }
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    return (new Date().getTime() - new Date(user.subscription.trialStartedAt).getTime()) <= 7 * 24 * 60 * 60 * 1000;
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sun className="w-5 h-5" /> },
    { id: 'gratitude', label: 'Diário', icon: <Heart className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Aconselhamento', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Evolução', icon: <TrendingUp className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}
      <header className="sticky top-0 z-[60] bg-white/70 backdrop-blur-2xl border-b border-rose-100/50 h-20 flex items-center">
        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl"><Heart className="w-7 h-7 text-white fill-white" /></div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'}`}>
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>
          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>
      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">{renderContent()}</main>
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'}`}>
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message, TankTheme, GratitudeEntry } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import MyChallenges from './components/MyChallenges';
import GratitudeJournal from './components/GratitudeJournal';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, Calendar, CheckCircle2, Trophy, 
  BrainCircuit, ChevronRight, UserPlus, History, MessageSquareText, 
  Eye, Link2, Star, TrendingUp, Zap, Sun, Compass, RotateCcw, Clock3
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [], cycleCount: 1 };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return { status: 'trial', plan: 'none', trialStartedAt: new Date().toISOString(), expiresAt: null };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    return saved ? JSON.parse(saved) : { 
      name: '', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: getInitialSubscription(), notificationsEnabled: false,
      coupleCode: Math.random().toString(36).substring(2, 8).toUpperCase(), isLinked: false, 
      tankTheme: TankTheme.MODERN, gratitudeJournal: []
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false, gratitudeJournal: []
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection' | 'gratitude'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean; impact?: number } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');
  const [showCelebration, setShowCelebration] = useState(false);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleRestartChallenge = async () => {
    if (confirm("Deseja iniciar um novo ciclo de 60 dias de semeadura?")) {
      setLoadingMission(true);
      const cycle = (partner.challenge.cycleCount || 1) + 1;
      const targetLang = partner.languages[0];
      const d = await generateDailyMission(targetLang, partner.name, 1);
      setPartner(p => ({
        ...p,
        challenge: {
          ...emptyChallenge,
          type: 60,
          cycleCount: cycle,
          startDate: new Date().toISOString(),
          missions: [{
            id: Math.random().toString(36).substr(2, 9),
            day: 1,
            title: d.title!,
            description: d.description!,
            rationale: d.rationale!,
            completed: false,
            languageApplied: targetLang
          }]
        }
      }));
      setLoadingMission(false);
      setActiveTab('challenge');
    }
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);
      if (success) {
        setShowCelebration(true);
        setTimeout(() => setShowCelebration(false), 4000);
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );
        const nextDay = mission.day + 1;
        if (nextDay <= (partner.challenge.type || 0)) {
          const targetLang = nextDay % 2 !== 0 ? partner.languages[0] : partner.languages[1];
          const nextData = await generateDailyMission(targetLang, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false,
            languageApplied: targetLang
          });
        }
        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }
      setAiInsight({ feedback, success, impact });
    } finally {
      setLoadingMission(false);
    }
  };

  const handleAddGratitude = (entry: Omit<GratitudeEntry, 'id' | 'date'>) => {
    const newEntry: GratitudeEntry = {
      ...entry,
      id: Math.random().toString(36).substring(2, 9),
      date: new Date().toISOString()
    };
    setUser(prev => ({
      ...prev,
      gratitudeJournal: [...(prev.gratitudeJournal || []), newEntry]
    }));
  };

  const handleDeleteGratitude = (id: string) => {
    setUser(prev => ({
      ...prev,
      gratitudeJournal: (prev.gratitudeJournal || []).filter(e => e.id !== id)
    }));
  };

  const redoMission = (id: string) => {
    setPartner(prev => ({
      ...prev,
      challenge: {
        ...prev.challenge,
        missions: prev.challenge.missions.map(m => 
          m.id === id ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
        )
      }
    }));
  };

  const handleLinkPartner = (partnerCode: string) => {
    if (partnerCode.trim().length >= 4) {
      // Simulação de sincronização: Ao conectar, assumimos que as linguagens do parceiro são obtidas
      const simulatedPartnerLangs = [LoveLanguage.TIME, LoveLanguage.WORDS];
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: 'Parceiro(a)' }));
      setPartner(prev => ({ ...prev, isLinked: true, languages: simulatedPartnerLangs }));
      alert("Conexão estabelecida com sucesso! Linguagens sincronizadas.");
      setActiveTab('dashboard');
    } else {
      alert("Por favor, insira um código válido.");
    }
  };

  const renderContent = () => {
    if (!checkAccess() && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection', 'gratitude'].includes(activeTab)) {
      return <Paywall onSubscribe={(id) => { setUser(p => ({ ...p, subscription: { ...p.subscription, status: 'active', plan: id as any } })); setActiveTab('dashboard'); }} isExpired={true} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-12 animate-in fade-in pb-20">
            <section className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-rose-500 to-indigo-600 rounded-[3.5rem] blur opacity-10 group-hover:opacity-25 transition duration-1000"></div>
               <div className="relative glass-card p-10 md:p-14 rounded-[3.5rem] flex flex-col md:flex-row justify-between items-center gap-10">
                  <div className="flex-1 space-y-6">
                    <div className="inline-flex items-center gap-2 px-5 py-2 bg-rose-50 text-rose-600 rounded-full text-xs font-black uppercase tracking-widest border border-rose-100">
                      <Clock3 className="w-4 h-4" /> Micro-Ação do Dia
                    </div>
                    <h2 className="text-4xl md:text-5xl font-black text-rose-950 leading-tight">Pronto para blindar seu amor <span className="text-rose-600 italic">hoje?</span></h2>
                    <p className="text-slate-500 text-lg max-w-lg font-medium">Pequenos gestos de Amor Sacrificial feitos com intenção transformam o ambiente da sua casa.</p>
                    <div className="flex flex-wrap gap-4 pt-4">
                      <button onClick={() => setActiveTab('challenge')} className="px-10 py-5 bg-rose-600 text-white rounded-[2rem] font-black text-lg hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 flex items-center gap-3">
                         {partner.challenge.type ? 'Abrir Missão' : 'Iniciar 60 Dias'} <ChevronRight className="w-5 h-5" />
                      </button>
                      <button onClick={() => setActiveTab('coach')} className="px-8 py-5 bg-white border border-rose-100 text-rose-900 rounded-[2rem] font-bold text-lg hover:bg-rose-50 transition-all flex items-center gap-3 shadow-sm">
                         Aconselhamento Pastoral <Compass className="w-5 h-5 text-rose-400" />
                      </button>
                    </div>
                  </div>
                  <div className="w-full md:w-1/3 flex justify-center">
                    <div className="w-48 h-48 bg-rose-50 rounded-[3rem] flex items-center justify-center relative animate-float">
                      <Calendar className="w-20 h-20 text-rose-500" />
                      {partner.challenge.missions.length > 0 && (
                        <div className="absolute -top-4 -right-4 bg-indigo-600 text-white w-14 h-14 rounded-full flex flex-col items-center justify-center font-black shadow-xl">
                          <span className="text-[10px] uppercase leading-none">Dia</span>
                          <span className="text-xl">{partner.challenge.missions.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
            </section>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="bg-white p-10 rounded-[3.5rem] border border-blue-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Suas Linguagens Principais</p>
                  {user.languages.length > 0 ? (
                    <div className="flex flex-wrap gap-3">
                      {user.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-blue-50 text-blue-600 rounded-2xl text-xs font-black border border-blue-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-blue-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('quiz')} 
                      className="text-left text-2xl font-black text-blue-600 hover:text-blue-700 transition-colors flex items-center gap-2 group"
                    >
                      Fazer Teste
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>

               <div className="bg-white p-10 rounded-[3.5rem] border border-rose-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Linguagens de {partner.name}</p>
                  {partner.languages.length > 0 && user.isLinked ? (
                    <div className="flex flex-wrap gap-3">
                      {partner.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-rose-50 text-rose-600 rounded-2xl text-xs font-black border border-rose-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-rose-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('connection')} 
                      className="text-left text-2xl font-black text-rose-600 hover:text-rose-700 transition-colors flex items-center gap-2 group"
                    >
                      Conectar com Parceiro
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <TankGauge label="Termômetro Diário" type="self" level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
              <TankGauge label="Termômetro do Parceiro" type="partner" level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="glass-card p-12 md:p-20 rounded-[4rem] shadow-xl border border-rose-100">
                <div className="w-24 h-24 bg-rose-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10"><Calendar className="w-12 h-12 text-rose-600" /></div>
                <h2 className="text-5xl font-black text-rose-950 mb-8 tracking-tight">Comece a Semear</h2>
                <p className="text-slate-500 text-xl mb-12 max-w-2xl mx-auto font-medium">60 dias de Amor Sacrificial transformarão seu casamento em algo duradouro e prazeroso.</p>
                <button 
                  disabled={partner.languages.length < 2}
                  onClick={async () => { 
                    setLoadingMission(true); 
                    const targetLang = partner.languages[0];
                    const d = await generateDailyMission(targetLang, partner.name, 1); 
                    setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), cycleCount: 1, missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false, languageApplied: targetLang }] } })); 
                    setLoadingMission(false); 
                  }} 
                  className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all text-white group disabled:opacity-50"
                >
                  <span className="block font-black text-3xl mb-1 uppercase tracking-tighter">Ativar Desafio</span>
                  <span className="text-rose-100 text-xs font-bold uppercase tracking-widest">
                    {partner.languages.length < 2 ? "Conecte-se ao parceiro para obter as linguagens dele primeiro" : "Conselho Pastoral do Dia"}
                  </span>
                </button>
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        const allCompleted = challenge.missions.length === challenge.type && challenge.missions.every(m => m.completed);

        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12 relative">
             {showCelebration && [...Array(15)].map((_, i) => (
                <div key={i} className="floating-heart text-rose-500 opacity-0" style={{ left: `${Math.random() * 80 + 10}%`, top: '80%', animationDelay: `${Math.random() * 0.8}s`, fontSize: `${Math.random() * 20 + 10}px` }}><Heart className="fill-current" /></div>
             ))}
             {allCompleted ? (
               <div className="glass-card p-16 rounded-[4rem] text-center border border-emerald-100 shadow-xl bg-emerald-50/20">
                 <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10"><Trophy className="w-12 h-12 text-emerald-500" /></div>
                 <h3 className="text-4xl font-black text-emerald-950 mb-4">Ciclo de 60 Dias Concluído!</h3>
                 <p className="text-slate-600 text-xl mb-12 max-w-md mx-auto font-medium">Sua semeadura foi constante. O seu casamento está mais forte hoje.</p>
                 <div className="flex flex-col sm:flex-row gap-5 justify-center">
                    <button onClick={handleRestartChallenge} className="px-10 py-5 bg-emerald-600 text-white rounded-[2rem] font-black hover:bg-emerald-700 transition-all shadow-xl">Semear por mais 60 dias</button>
                    <button onClick={() => setActiveTab('dashboard')} className="px-10 py-5 bg-white border border-rose-100 text-rose-600 rounded-[2rem] font-black">Voltar ao Início</button>
                 </div>
               </div>
             ) : currentMission ? (
               <div className="space-y-6">
                  {aiInsight?.success && (
                    <div className="bg-emerald-600 text-white p-10 rounded-[3.5rem] shadow-2xl flex flex-col md:flex-row items-center gap-8 border-4 border-white">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shrink-0 shadow-lg rotate-6"><Trophy className="w-12 h-12 text-emerald-600" /></div>
                      <div className="flex-1">
                        <h4 className="text-3xl font-black mb-3">Semente bem plantada!</h4>
                        <p className="text-emerald-50 text-lg leading-relaxed font-medium">"{aiInsight.feedback}"</p>
                      </div>
                    </div>
                  )}
                  <div className="bg-slate-950 text-white rounded-[3.5rem] p-10 md:p-16 shadow-2xl relative overflow-hidden group">
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-10">
                        <div className="px-5 py-2 bg-white/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-rose-400 backdrop-blur-sm">Dia {currentMission.day} • {currentMission.languageApplied}</div>
                      </div>
                      <h4 className="text-5xl font-black mb-8 text-white leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-2xl text-slate-300 leading-relaxed mb-12 font-medium">"{currentMission.description}"</p>
                      <div className="bg-white/5 border border-white/10 p-6 rounded-2xl mb-12">
                         <h5 className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2"><Sparkles className="w-3 h-3" /> Sabedoria de Semeadura</h5>
                         <p className="text-slate-400 text-sm italic font-medium">"{currentMission.rationale}"</p>
                      </div>
                      {!aiInsight?.success && (
                        <div className="space-y-6">
                          <textarea value={fulfillmentText} onChange={(e) => setFulfillmentText(e.target.value)} placeholder="Como foi semear amor desta forma hoje?" className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-8 text-white text-xl focus:outline-none focus:border-rose-500 transition-all h-48 font-medium" />
                          <button onClick={() => completeMission(currentMission)} disabled={loadingMission || !fulfillmentText.trim()} className="w-full py-6 bg-rose-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-rose-700 transition-all flex items-center justify-center gap-4 shadow-2xl">
                            {loadingMission ? <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" /> : "Validar Missão"}
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
             ) : null}
          </div>
        );
      case 'coach': return <PersonalCoach />;
      case 'gratitude': return <GratitudeJournal entries={user.gratitudeJournal || []} onAddEntry={handleAddGratitude} onDeleteEntry={handleDeleteGratitude} />;
      case 'myChallenges': return <MyChallenges challenge={partner.challenge} partnerName={partner.name} onRedoMission={redoMission} onGoToChallenge={() => setActiveTab('challenge')} />;
      case 'connection': return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      default: return null;
    }
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    return (new Date().getTime() - new Date(user.subscription.trialStartedAt).getTime()) <= 7 * 24 * 60 * 60 * 1000;
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sun className="w-5 h-5" /> },
    { id: 'gratitude', label: 'Diário', icon: <Heart className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Aconselhamento', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Evolução', icon: <TrendingUp className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}
      <header className="sticky top-0 z-[60] bg-white/70 backdrop-blur-2xl border-b border-rose-100/50 h-20 flex items-center">
        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl"><Heart className="w-7 h-7 text-white fill-white" /></div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'}`}>
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>
          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>
      <main className="flex-1 max-w-7xl w-full mx-auto px-6 py-10 relative z-10">{renderContent()}</main>
      <nav className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 rounded-[2.5rem] flex items-center justify-around shadow-2xl z-[70]">
        {navItems.map((item) => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`flex flex-col items-center gap-1.5 p-3 rounded-[1.5rem] transition-all flex-1 ${activeTab === item.id ? 'text-white bg-white/10 scale-110' : 'text-slate-500 hover:text-white'}`}>
            {React.cloneElement(item.icon as React.ReactElement, { className: "w-5 h-5" })}
            <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LoveLanguage, UserProfile, Challenge, Mission, SubscriptionInfo, Message, TankTheme, GratitudeEntry } from './types';
import { LANGUAGE_METADATA } from './constants.tsx';
import TankGauge from './components/TankGauge';
import Quiz from './components/Quiz';
import Tutorial from './components/Tutorial';
import Paywall from './components/Paywall';
import PersonalCoach from './components/PersonalCoach';
import CoupleConnection from './components/CoupleConnection';
import MyChallenges from './components/MyChallenges';
import GratitudeJournal from './components/GratitudeJournal';
import { generateDailyMission, getMissionCompletionFeedback } from './services/geminiService';
import { 
  Heart, Sparkles, Calendar, CheckCircle2, Trophy, 
  BrainCircuit, ChevronRight, UserPlus, History, MessageSquareText, 
  Eye, Link2, Star, TrendingUp, Zap, Sun, Compass, RotateCcw, Clock3
} from 'lucide-react';

const App: React.FC = () => {
  const emptyChallenge: Challenge = { type: null, startDate: null, missions: [], cycleCount: 1 };

  const getInitialSubscription = (): SubscriptionInfo => {
    const saved = localStorage.getItem('love_user_v4');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.subscription) return parsed.subscription;
    }
    return { status: 'trial', plan: 'none', trialStartedAt: new Date().toISOString(), expiresAt: null };
  };

  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_user_v4');
    return saved ? JSON.parse(saved) : { 
      name: '', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: false, subscription: getInitialSubscription(), notificationsEnabled: false,
      coupleCode: Math.random().toString(36).substring(2, 8).toUpperCase(), isLinked: false, 
      tankTheme: TankTheme.MODERN, gratitudeJournal: []
    };
  });

  const [partner, setPartner] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('love_partner_v4');
    return saved ? JSON.parse(saved) : { 
      name: 'Parceiro(a)', languages: [], tankLevel: 5, challenge: emptyChallenge,
      hasFinishedTutorial: true, subscription: getInitialSubscription(), notificationsEnabled: false,
      isLinked: false, gratitudeJournal: []
    };
  });

  const [activeTab, setActiveTab] = useState<'dashboard' | 'quiz' | 'guide' | 'challenge' | 'myChallenges' | 'coach' | 'paywall' | 'connection' | 'gratitude'>('dashboard');
  const [loadingMission, setLoadingMission] = useState(false);
  const [aiInsight, setAiInsight] = useState<{ feedback: string; success: boolean; impact?: number } | null>(null);
  const [fulfillmentText, setFulfillmentText] = useState('');
  const [showCelebration, setShowCelebration] = useState(false);

  useEffect(() => { localStorage.setItem('love_user_v4', JSON.stringify(user)); }, [user]);
  useEffect(() => { localStorage.setItem('love_partner_v4', JSON.stringify(partner)); }, [partner]);

  const handleRestartChallenge = async () => {
    if (confirm("Deseja iniciar um novo ciclo de 60 dias de semeadura?")) {
      setLoadingMission(true);
      const cycle = (partner.challenge.cycleCount || 1) + 1;
      const targetLang = partner.languages[0];
      const d = await generateDailyMission(targetLang, partner.name, 1);
      setPartner(p => ({
        ...p,
        challenge: {
          ...emptyChallenge,
          type: 60,
          cycleCount: cycle,
          startDate: new Date().toISOString(),
          missions: [{
            id: Math.random().toString(36).substr(2, 9),
            day: 1,
            title: d.title!,
            description: d.description!,
            rationale: d.rationale!,
            completed: false,
            languageApplied: targetLang
          }]
        }
      }));
      setLoadingMission(false);
      setActiveTab('challenge');
    }
  };

  const completeMission = async (mission: Mission) => {
    if (!fulfillmentText.trim()) return;
    setLoadingMission(true);
    setAiInsight(null);
    try {
      const { feedback, impact, success } = await getMissionCompletionFeedback(mission, partner.name, fulfillmentText);
      if (success) {
        setShowCelebration(true);
        setTimeout(() => setShowCelebration(false), 4000);
        const updatedMissions = partner.challenge.missions.map(m => 
          m.id === mission.id ? { ...m, completed: true, completedAt: new Date().toISOString(), aiFeedback: feedback } : m
        );
        const nextDay = mission.day + 1;
        if (nextDay <= (partner.challenge.type || 0)) {
          const targetLang = nextDay % 2 !== 0 ? partner.languages[0] : partner.languages[1];
          const nextData = await generateDailyMission(targetLang, partner.name, nextDay);
          updatedMissions.push({
            id: Math.random().toString(36).substr(2, 9),
            day: nextDay,
            title: nextData.title || "Próxima Missão",
            description: nextData.description || "Continue sua jornada.",
            rationale: nextData.rationale || "O amor é construído dia a dia.",
            completed: false,
            languageApplied: targetLang
          });
        }
        setPartner(prev => ({
          ...prev,
          tankLevel: Math.min(10, parseFloat((prev.tankLevel + impact).toFixed(1))),
          challenge: { ...prev.challenge, missions: updatedMissions }
        }));
        setFulfillmentText('');
      }
      setAiInsight({ feedback, success, impact });
    } finally {
      setLoadingMission(false);
    }
  };

  const handleAddGratitude = (entry: Omit<GratitudeEntry, 'id' | 'date'>) => {
    const newEntry: GratitudeEntry = {
      ...entry,
      id: Math.random().toString(36).substring(2, 9),
      date: new Date().toISOString()
    };
    setUser(prev => ({
      ...prev,
      gratitudeJournal: [...(prev.gratitudeJournal || []), newEntry]
    }));
  };

  const handleDeleteGratitude = (id: string) => {
    setUser(prev => ({
      ...prev,
      gratitudeJournal: (prev.gratitudeJournal || []).filter(e => e.id !== id)
    }));
  };

  const redoMission = (id: string) => {
    setPartner(prev => ({
      ...prev,
      challenge: {
        ...prev.challenge,
        missions: prev.challenge.missions.map(m => 
          m.id === id ? { ...m, completed: false, completedAt: undefined, aiFeedback: undefined } : m
        )
      }
    }));
  };

  const handleLinkPartner = (partnerCode: string) => {
    if (partnerCode.trim().length >= 4) {
      const simulatedPartnerLangs = [LoveLanguage.TIME, LoveLanguage.WORDS];
      setUser(prev => ({ ...prev, isLinked: true, linkedPartnerName: 'Parceiro(a)' }));
      setPartner(prev => ({ ...prev, isLinked: true, languages: simulatedPartnerLangs }));
      alert("Conexão estabelecida com sucesso! Linguagens sincronizadas.");
      setActiveTab('dashboard');
    } else {
      alert("Por favor, insira um código válido.");
    }
  };

  const renderContent = () => {
    if (!checkAccess() && ['dashboard', 'challenge', 'myChallenges', 'coach', 'connection', 'gratitude'].includes(activeTab)) {
      return <Paywall onSubscribe={(id) => { setUser(p => ({ ...p, subscription: { ...p.subscription, status: 'active', plan: id as any } })); setActiveTab('dashboard'); }} isExpired={true} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-12 animate-in fade-in pb-20">
            <section className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-rose-500 to-indigo-600 rounded-[3.5rem] blur opacity-10 group-hover:opacity-25 transition duration-1000"></div>
               <div className="relative glass-card p-10 md:p-14 rounded-[3.5rem] flex flex-col md:flex-row justify-between items-center gap-10">
                  <div className="flex-1 space-y-6">
                    <div className="inline-flex items-center gap-2 px-5 py-2 bg-rose-50 text-rose-600 rounded-full text-xs font-black uppercase tracking-widest border border-rose-100">
                      <Clock3 className="w-4 h-4" /> Micro-Ação do Dia
                    </div>
                    <h2 className="text-4xl md:text-5xl font-black text-rose-950 leading-tight">Pronto para blindar seu amor <span className="text-rose-600 italic">hoje?</span></h2>
                    <p className="text-slate-500 text-lg max-w-lg font-medium">Pequenos gestos de Amor Sacrificial feitos com intenção transformam o ambiente da sua casa.</p>
                    <div className="flex flex-wrap gap-4 pt-4">
                      <button onClick={() => setActiveTab('challenge')} className="px-10 py-5 bg-rose-600 text-white rounded-[2rem] font-black text-lg hover:bg-rose-700 transition-all shadow-2xl shadow-rose-200 flex items-center gap-3">
                         {partner.challenge.type ? 'Abrir Missão' : 'Iniciar 60 Dias'} <ChevronRight className="w-5 h-5" />
                      </button>
                      <button onClick={() => setActiveTab('coach')} className="px-8 py-5 bg-white border border-rose-100 text-rose-900 rounded-[2rem] font-bold text-lg hover:bg-rose-50 transition-all flex items-center gap-3 shadow-sm">
                         Aconselhamento Pastoral <Compass className="w-5 h-5 text-rose-400" />
                      </button>
                    </div>
                  </div>
                  <div className="w-full md:w-1/3 flex justify-center">
                    <div className="w-48 h-48 bg-rose-50 rounded-[3rem] flex items-center justify-center relative animate-float">
                      <Calendar className="w-20 h-20 text-rose-500" />
                      {partner.challenge.missions.length > 0 && (
                        <div className="absolute -top-4 -right-4 bg-indigo-600 text-white w-14 h-14 rounded-full flex flex-col items-center justify-center font-black shadow-xl">
                          <span className="text-[10px] uppercase leading-none">Dia</span>
                          <span className="text-xl">{partner.challenge.missions.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
            </section>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="bg-white p-10 rounded-[3.5rem] border border-blue-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Suas Linguagens Principais</p>
                  {user.languages.length > 0 ? (
                    <div className="flex flex-wrap gap-3">
                      {user.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-blue-50 text-blue-600 rounded-2xl text-xs font-black border border-blue-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-blue-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('quiz')} 
                      className="text-left text-2xl font-black text-blue-600 hover:text-blue-700 transition-colors flex items-center gap-2 group"
                    >
                      Fazer Teste
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>

               <div className="bg-white p-10 rounded-[3.5rem] border border-rose-50/50 shadow-sm flex flex-col justify-center min-h-[160px] hover:shadow-md transition-shadow">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Linguagens de {partner.name}</p>
                  {partner.languages.length > 0 && user.isLinked ? (
                    <div className="flex flex-wrap gap-3">
                      {partner.languages.map(l => (
                        <div key={l} className="px-5 py-2.5 bg-rose-50 text-rose-600 rounded-2xl text-xs font-black border border-rose-100 flex items-center gap-2">
                           <div className="w-1.5 h-1.5 bg-rose-400 rounded-full" /> {l}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <button 
                      onClick={() => setActiveTab('connection')} 
                      className="text-left text-2xl font-black text-rose-600 hover:text-rose-700 transition-colors flex items-center gap-2 group"
                    >
                      Conectar com Parceiro
                      <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                    </button>
                  )}
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <TankGauge label="Termômetro Diário" type="self" level={user.tankLevel} onUpdate={(v) => setUser(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
              <TankGauge label="Termômetro do Parceiro" type="partner" level={partner.tankLevel} onUpdate={(v) => setPartner(p => ({ ...p, tankLevel: v }))} theme={user.tankTheme || TankTheme.MODERN} onThemeChange={(t) => setUser(p => ({ ...p, tankTheme: t }))} />
            </div>
          </div>
        );
      case 'quiz': return <Quiz onComplete={(res) => { setUser(prev => ({ ...prev, languages: res })); setActiveTab('dashboard'); }} />;
      case 'challenge':
        const challenge = partner.challenge;
        if (!challenge.type) {
           return (
            <div className="max-w-4xl mx-auto py-12 px-4 text-center">
              <div className="glass-card p-12 md:p-20 rounded-[4rem] shadow-xl border border-rose-100">
                <div className="w-24 h-24 bg-rose-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10"><Calendar className="w-12 h-12 text-rose-600" /></div>
                <h2 className="text-5xl font-black text-rose-950 mb-8 tracking-tight">Comece a Semear</h2>
                <p className="text-slate-500 text-xl mb-12 max-w-2xl mx-auto font-medium">60 dias de Amor Sacrificial transformarão seu casamento em algo duradouro e prazeroso.</p>

                {partner.languages.length >= 2 ? (
                  <button 
                    onClick={async () => { 
                      setLoadingMission(true); 
                      const targetLang = partner.languages[0];
                      const d = await generateDailyMission(targetLang, partner.name, 1); 
                      setPartner(p => ({ ...p, challenge: { type: 60, startDate: new Date().toISOString(), cycleCount: 1, missions: [{ id: Math.random().toString(36).substr(2, 9), day: 1, title: d.title!, description: d.description!, rationale: d.rationale!, completed: false, languageApplied: targetLang }] } })); 
                      setLoadingMission(false); 
                    }} 
                    className="w-full max-w-md bg-rose-600 p-8 rounded-[2.5rem] hover:bg-rose-700 transition-all text-white group shadow-2xl"
                  >
                    <span className="block font-black text-3xl mb-1 uppercase tracking-tighter">Ativar Desafio</span>
                    <span className="text-rose-100 text-xs font-bold uppercase tracking-widest flex items-center justify-center gap-2">
                      <Sparkles className="w-3 h-3" /> Receber Primeira Missão
                    </span>
                  </button>
                ) : (
                  <div className="space-y-6 flex flex-col items-center">
                    <p className="text-rose-600 font-bold bg-rose-50 px-6 py-3 rounded-2xl border border-rose-100">
                      Você precisa se conectar ao seu parceiro para sincronizar as linguagens antes de começar o desafio.
                    </p>
                    <button 
                      onClick={() => setActiveTab('connection')}
                      className="w-full max-w-md bg-slate-900 p-8 rounded-[2.5rem] hover:bg-black transition-all text-white font-black text-2xl uppercase tracking-tighter flex items-center justify-center gap-4 shadow-2xl"
                    >
                      Conectar Agora <UserPlus className="w-6 h-6" />
                    </button>
                  </div>
                )}
              </div>
            </div>
           );
        }
        const currentMission = challenge.missions.find(m => !m.completed);
        const allCompleted = challenge.missions.length === challenge.type && challenge.missions.every(m => m.completed);

        return (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in pb-12 relative">
             {showCelebration && [...Array(15)].map((_, i) => (
                <div key={i} className="floating-heart text-rose-500 opacity-0" style={{ left: `${Math.random() * 80 + 10}%`, top: '80%', animationDelay: `${Math.random() * 0.8}s`, fontSize: `${Math.random() * 20 + 10}px` }}><Heart className="fill-current" /></div>
             ))}
             {allCompleted ? (
               <div className="glass-card p-16 rounded-[4rem] text-center border border-emerald-100 shadow-xl bg-emerald-50/20">
                 <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10"><Trophy className="w-12 h-12 text-emerald-500" /></div>
                 <h3 className="text-4xl font-black text-emerald-950 mb-4">Ciclo de 60 Dias Concluído!</h3>
                 <p className="text-slate-600 text-xl mb-12 max-w-md mx-auto font-medium">Sua semeadura foi constante. O seu casamento está mais forte hoje.</p>
                 <div className="flex flex-col sm:flex-row gap-5 justify-center">
                    <button onClick={handleRestartChallenge} className="px-10 py-5 bg-emerald-600 text-white rounded-[2rem] font-black hover:bg-emerald-700 transition-all shadow-xl">Semear por mais 60 dias</button>
                    <button onClick={() => setActiveTab('dashboard')} className="px-10 py-5 bg-white border border-rose-100 text-rose-600 rounded-[2rem] font-black">Voltar ao Início</button>
                 </div>
               </div>
             ) : currentMission ? (
               <div className="space-y-6">
                  {aiInsight?.success && (
                    <div className="bg-emerald-600 text-white p-10 rounded-[3.5rem] shadow-2xl flex flex-col md:flex-row items-center gap-8 border-4 border-white">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shrink-0 shadow-lg rotate-6"><Trophy className="w-12 h-12 text-emerald-600" /></div>
                      <div className="flex-1">
                        <h4 className="text-3xl font-black mb-3">Semente bem plantada!</h4>
                        <p className="text-emerald-50 text-lg leading-relaxed font-medium">"{aiInsight.feedback}"</p>
                      </div>
                    </div>
                  )}
                  <div className="bg-slate-950 text-white rounded-[3.5rem] p-10 md:p-16 shadow-2xl relative overflow-hidden group">
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-10">
                        <div className="px-5 py-2 bg-white/10 rounded-full text-[11px] font-black uppercase tracking-[0.3em] text-rose-400 backdrop-blur-sm">Dia {currentMission.day} • {currentMission.languageApplied}</div>
                      </div>
                      <h4 className="text-5xl font-black mb-8 text-white leading-tight tracking-tight">{currentMission.title}</h4>
                      <p className="text-2xl text-slate-300 leading-relaxed mb-12 font-medium">"{currentMission.description}"</p>
                      <div className="bg-white/5 border border-white/10 p-6 rounded-2xl mb-12">
                         <h5 className="text-[10px] font-black text-rose-400 uppercase tracking-widest mb-2 flex items-center gap-2"><Sparkles className="w-3 h-3" /> Sabedoria de Semeadura</h5>
                         <p className="text-slate-400 text-sm italic font-medium">"{currentMission.rationale}"</p>
                      </div>
                      {!aiInsight?.success && (
                        <div className="space-y-6">
                          <textarea value={fulfillmentText} onChange={(e) => setFulfillmentText(e.target.value)} placeholder="Como foi semear amor desta forma hoje?" className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-8 text-white text-xl focus:outline-none focus:border-rose-500 transition-all h-48 font-medium" />
                          <button onClick={() => completeMission(currentMission)} disabled={loadingMission || !fulfillmentText.trim()} className="w-full py-6 bg-rose-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-rose-700 transition-all flex items-center justify-center gap-4 shadow-2xl">
                            {loadingMission ? <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" /> : "Validar Missão"}
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
               </div>
             ) : null}
          </div>
        );
      case 'coach': return <PersonalCoach />;
      case 'gratitude': return <GratitudeJournal entries={user.gratitudeJournal || []} onAddEntry={handleAddGratitude} onDeleteEntry={handleDeleteGratitude} />;
      case 'myChallenges': return <MyChallenges challenge={partner.challenge} partnerName={partner.name} onRedoMission={redoMission} onGoToChallenge={() => setActiveTab('challenge')} />;
      case 'connection': return <CoupleConnection userCode={user.coupleCode || 'ABCD-123'} onLink={handleLinkPartner} linkedPartner={user.isLinked ? partner.name : undefined} />;
      default: return null;
    }
  };

  const checkAccess = () => {
    if (user.subscription.status === 'active') return true;
    return (new Date().getTime() - new Date(user.subscription.trialStartedAt).getTime()) <= 7 * 24 * 60 * 60 * 1000;
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: <Sun className="w-5 h-5" /> },
    { id: 'gratitude', label: 'Diário', icon: <Heart className="w-5 h-5" /> },
    { id: 'challenge', label: 'Missão', icon: <Calendar className="w-5 h-5" /> },
    { id: 'coach', label: 'Aconselhamento', icon: <Sparkles className="w-5 h-5" /> },
    { id: 'myChallenges', label: 'Evolução', icon: <TrendingUp className="w-5 h-5" /> }
  ];

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      {!user.hasFinishedTutorial && <Tutorial onComplete={() => setUser(p => ({ ...p, hasFinishedTutorial: true }))} />}
      <header className="sticky top-0 z-[60] bg-white/70 backdrop-blur-2xl border-b border-rose-100/50 h-20 flex items-center">
        <div className="max-w-7xl w-full mx-auto px-6 flex items-center justify-between">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="w-12 h-12 bg-rose-600 rounded-[1.2rem] flex items-center justify-center shadow-xl"><Heart className="w-7 h-7 text-white fill-white" /></div>
            <div className="hidden sm:block">
              <h1 className="text-xl font-black text-rose-950 leading-none tracking-tighter italic">DIALETO</h1>
              <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Amor Inteligente</span>
            </div>
          </div>
          <nav className="hidden lg:flex items-center gap-2 bg-rose-50/50 p-1.5 rounded-3xl border border-rose-100">
            {navItems.map((tab) => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-6 py-2.5 rounded-2xl text-[11px] font-black flex items-center gap-2.5 transition-all uppercase tracking-widest ${activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl' : 'text-rose-900 hover:bg-white'}`}>
                {React.cloneElement(tab.icon as React.ReactElement, { className: "w-4 h-4" })}
                {tab.label}
              </button>
            ))}
          </nav>
          <div className="flex items-center gap-3">
             <button onClick={() => setActiveTab('connection')} className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${user.isLinked ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-amber-50 text-amber-600 border border-amber-100 animate-pulse'}`}>
                {user.isLinked ? <Link2 size={20} /> : <UserPlus size={20} />}
             </button>
          </div>
        </div>
      </header>
